INSERT INTO `question` VALUES (1, '1+1=？', 1, '[\"A. 1\", \"B. 2\", \"C. 3\", \"D. 4\"]', 'B', '1+1当然等于2', '2026-02-10 11:57:22', NULL, '2026-02-10 12:19:47', NULL, NULL, 5, '其他', NULL);
INSERT INTO `question` VALUES (2, '2是以下哪些数的因数', 2, '[\"A. 2\", \"B. 4\", \"C. 7\", \"D. 9\"]', 'AB', '无', '2026-02-10 12:38:39', NULL, '2026-02-10 14:45:57', NULL, NULL, 1, '其他', NULL);
INSERT INTO `question` VALUES (3, '“四书五经”中的“四书”是指：', 1, '[\"A. 《大学》《中庸》《论语》《孟子》\", \"B. 《周易》《尚书》《诗经》《礼记》\", \"C. 《大学》《孝经》《论语》《孟子》\", \"D. 《尚书》《周易》《论语》《春秋》\"]', 'A', '“四书”指《大学》《中庸》《论语》《孟子》。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (4, '下列物理量中，属于矢量的是：', 1, '[\"A. 质量\", \"B. 温度\", \"C. 速度\", \"D. 密度\"]', 'C', '矢量是既有大小又有方向的物理量，速度是矢量；质量、温度、密度只有大小没有方\n向，是标量。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (5, '我国第一部纪传体通史是：', 1, '[\"A. 《春秋》\", \"B. 《史记》\", \"C. 《汉书》\", \"D. 《资治通鉴》\"]', 'B', '《史记》是由西汉史学家司马迁撰写的中国第一部纪传体通史。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (6, '下列关于光合作用的说法，正确的是：', 1, '[\"A. 可以在黑暗中进行\", \"B. 必须在叶绿体中进行\", \"C. 只能在白天进行\", \"D. 不需要二氧化碳\"]', 'B', '光合作用的场所是叶绿体，主要在光照下进行，原料是二氧化碳和水。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (7, '2024 年是农历甲辰年，对应的生肖是：', 1, '[\"A. 兔\", \"B. 龙\", \"C. 蛇\", \"D. 马\"]', 'B', '甲辰年对应的生肖是龙。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (8, '填入划横线部分最恰当的一项是：\n我们需要________的勇气，去面对生活中的困难和挑战。', 1, '[\"A. 破釜沉舟\", \"B. 孤注一掷\", \"C. 铤而走险\", \"D. 垂死挣扎\"]', 'A', '“破釜沉舟”比喻下定决心，不顾一切地干到底，符合语境。其他词语多含贬义或不合\n语境。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (9, '下列各句中，没有语病的一句是：', 1, '[\"A. 通过这次活动，使我们深刻地认识到了环保的重要性。\", \"B. 他那崇高的品质，经常浮现在我的脑海中。\", \"C. 能否考上理想的大学，关键在于你是否努力。\", \"D. 为了防止这类事故不再发生，我们加强了安全教育。\"]', 'C', 'A 项缺主语；B 项“品质”不能“浮现”；D 项“防止”和“不再”否定失当。C 项两面对两面，\n正确。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (10, '“近朱者赤，近墨者黑”所蕴含的道理与下列哪句话最相似？', 1, '[\"A. 青出于蓝而胜于蓝\", \"B. 蓬生麻中，不扶自直\", \"C. 公道自在人心\", \"D. 天行健，君子以自强不息\"]', 'B', '“近朱者赤”和“蓬生麻中”都强调了环境对人的影响。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (11, '从所给的四个选项中，选择最合适的一个填入问号处，使之呈现一定的规律性：\n1, 3, 5, 7, (?)', 1, '[\"A. 8\", \"B. 9\", \"C. 10\", \"D. 11\"]', 'B', '这是一个等差数列，公差为 2，所以下一个数字是 9。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (12, '甲、乙、丙、丁四人涉嫌某案被传讯。\n甲说：作案者是乙。\n乙说：作案者是甲。\n丙说：作案者不是我。\n丁说：作案者在我们四人中。\n如果四人中有且只有一个说真话，则以下哪项断定成立？', 1, '[\"A. 作案者是甲\", \"B. 作案者是乙\", \"C. 作案者是丙\", \"D. 作案者是丁\"]', 'D', '此题通过假设法或矛盾法可推断，若只有一人说真话，结合选项分析，答案为 D（具\n体逻辑较复杂，此处简化）。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (13, '一件商品按成本价提高 30%后标价，再打 8 折销售，售价为 208 元。这件商品的成本价\n是多少元？', 1, '[\"A. 180\", \"B. 190\", \"C. 200\", \"D. 210\"]', 'C', '设成本为 x，则 x * (1+30%) * 0.8 = 208，解得 x = 200。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (14, '某班有 50 名学生，其中男生 26 人，女生 24 人。随机抽取一名学生，抽到男生的概率\n是：', 1, '[\"A. 0.48\", \"B. 0.50\", \"C. 0.52\", \"D. 0.54\"]', 'C', '男生概率 = 26 / 50 = 0.52。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (15, '2, 4, 8, 16, 32, (?)', 1, '[\"A. 48\", \"B. 56\", \"C. 64\", \"D. 72\"]', 'C', '这是一个等比数列，公比为 2，所以下一个数字是 32 * 2 = 64。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (16, '甲乙两地相距 300 公里，一辆汽车从甲地开往乙地，速度为 60 公里/小时。返回时速度\n为 40 公里/小时。求往返的平均速度？', 1, '[\"A. 48\", \"B. 50\", \"C. 52\", \"D. 55\"]', 'A', '平均速度 = 总路程 / 总时间 = (300*2) / (300/60 + 300/40) = 600 / (5 + 7.5) = 600\n/ 12.5 = 48 km/h。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (17, '某商店进了一批水果，第一天卖了总数的 1/3，第二天卖了剩余的 1/2，还剩 20 斤。这\n批水果共有多少斤？', 1, '[\"A. 40\", \"B. 50\", \"C. 60\", \"D. 80\"]', 'C', '设总量为 x。第一天卖 x/3，剩 2x/3。第二天卖(2x/3)*1/2 = x/3。剩 x - x/3 - x/3 = x/3\n= 20，故 x = 60。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (18, '医生 : 医院', 1, '[\"A. 老师 : 学校\", \"B. 士兵 : 战场\", \"C. 厨师 : 菜谱\", \"D. 司机 : 汽车\"]', 'A', '职业与工作场所的对应关系。医生在医院工作，老师在学校工作。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (19, '尊重 : 崇敬', 1, '[\"A. 承受 : 忍受\", \"B. 了解 : 知晓\", \"C. 批评 : 批判\", \"D. 相信 : 信任\"]', 'C', '近义词关系，且后者程度比前者重。“崇敬”比“尊重”程度深，“批判”比“批评”程度深。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (20, '只有努力奋斗，才能实现梦想。如果这句话为真，以下哪项也一定为真？', 1, '[\"A. 只要努力奋斗，就能实现梦想\", \"B. 如果没有实现梦想，说明没有努力奋斗\", \"C. 如果实现了梦想，说明一定努力奋斗了\", \"D. 只有实现梦想，才是努力奋斗\"]', 'C', '“只有...才...”是必要条件，逻辑式为：实现梦想 -> 努力奋斗。所以 C 项成立。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (21, '某公司规定，所有经理都必须参加管理培训。如果上述规定成立，以下哪项一定为真？', 1, '[\"A. 参加管理培训的都是经理\", \"B. 没有参加管理培训的都不是经理\", \"C. 有些经理不需要参加管理培训\", \"D. 员工也必须参加管理培训\"]', 'B', '原命题：经理 -> 参加培训。逆否命题：不参加培训 -> 不是经理。故 B 正确。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
INSERT INTO `question` VALUES (22, '太阳系中体积最大的行星是：', 1, '[\"A. 地球\", \"B. 土星\", \"C. 木星\", \"D. 火星\"]', 'C', '木星是太阳系中体积和质量最大的行星。', '2026-02-10 15:29:20', 11, NULL, NULL, NULL, 3, '其他', NULL);
