INSERT INTO `question` VALUES (47, '2024 年是农历甲辰年，对应的生肖是：', 1, '[\"A. 兔\", \"B. 龙\", \"C. 蛇\", \"D. 马\"]', 'B', '甲辰年对应的生肖是龙。', '2026-02-25 19:26:11', 11, NULL, NULL, NULL, 3, '判断推理', NULL);
