INSERT INTO `question` VALUES (114, '某班有 50 名学生，其中男生 26 人，女生 24 人。随机抽取一名学生，抽到男生的概率\n是：', 1, '[{\"key\": \"A\", \"value\": \"0.48\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"0.50\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"0.52\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"0.54\", \"imageUrl\": \"\"}]', 'C', '男生概率 = 26 / 50 = 0.52。', '2026-02-26 21:05:11', 11, '2026-03-12 15:48:28', NULL, NULL, 1, '数量关系', '');
INSERT INTO `question` VALUES (115, '2, 4, 8, 16, 32, (?)', 1, '[{\"key\": \"A\", \"value\": \"48\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"56\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"64\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"72\", \"imageUrl\": \"\"}]', 'C', '这是一个等比数列，公比为 2，所以下一个数字是 32 * 2 = 64。', '2026-02-26 21:05:11', 11, '2026-03-12 15:50:11', NULL, NULL, 1, '数量关系', '');
INSERT INTO `question` VALUES (116, '甲乙两地相距 300 公里，一辆汽车从甲地开往乙地，速度为 60 公里/小时。返回时速度\n为 40 公里/小时。求往返的平均速度？', 1, '[{\"key\": \"A\", \"value\": \"48\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"50\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"52\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"55\", \"imageUrl\": \"\"}]', 'A', '平均速度 = 总路程 / 总时间 = (300*2) / (300/60 + 300/40) = 600 / (5 + 7.5) = 600\n/ 12.5 = 48 km/h。', '2026-02-26 21:05:11', 11, '2026-03-12 15:48:43', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (117, '某商店进了一批水果，第一天卖了总数的 1/3，第二天卖了剩余的 1/2，还剩 20 斤。这\n批水果共有多少斤？', 1, '[{\"key\": \"A\", \"value\": \"40\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"50\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"60\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"80\", \"imageUrl\": \"\"}]', 'C', '设总量为 x。第一天卖 x/3，剩 2x/3。第二天卖(2x/3)*1/2 = x/3。剩 x - x/3 - x/3 = x/3\n= 20，故 x = 60。', '2026-02-26 21:05:11', 11, '2026-03-12 15:48:55', NULL, NULL, 3, '数量关系', '');
INSERT INTO `question` VALUES (118, '医生 : 医院', 1, '[{\"key\": \"A\", \"value\": \"老师 : 学校\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"士兵 : 战场\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"厨师 : 菜谱\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"司机 : 汽车\", \"imageUrl\": \"\"}]', 'A', '职业与工作场所的对应关系。医生在医院工作，老师在学校工作。', '2026-02-26 21:05:11', 11, '2026-03-12 15:49:03', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (119, '尊重 : 崇敬', 1, '[{\"key\": \"A\", \"value\": \"承受 : 忍受\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"了解 : 知晓\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"批评 : 批判\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"相信 : 信任\", \"imageUrl\": \"\"}]', 'C', '近义词关系，且后者程度比前者重。“崇敬”比“尊重”程度深，“批判”比“批评”程度深。', '2026-02-26 21:05:11', 11, '2026-03-12 15:49:07', NULL, NULL, 3, '判断推理', '');
INSERT INTO `question` VALUES (120, '只有努力奋斗，才能实现梦想。如果这句话为真，以下哪项也一定为真？', 1, '[{\"key\": \"A\", \"value\": \"只要努力奋斗，就能实现梦想\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"如果没有实现梦想，说明没有努力奋斗\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"如果实现了梦想，说明一定努力奋斗了\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"只有实现梦想，才是努力奋斗\", \"imageUrl\": \"\"}]', 'C', '“只有...才...”是必要条件，逻辑式为：实现梦想 -> 努力奋斗。所以 C 项成立。', '2026-02-26 21:05:11', 11, '2026-03-12 15:49:55', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (121, '某公司规定，所有经理都必须参加管理培训。如果上述规定成立，以下哪项一定为真？', 1, '[{\"key\": \"A\", \"value\": \"参加管理培训的都是经理\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"没有参加管理培训的都不是经理\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"有些经理不需要参加管理培训\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"员工也必须参加管理培训\", \"imageUrl\": \"\"}]', 'B', '原命题：经理 -> 参加培训。逆否命题：不参加培训 -> 不是经理。故 B 正确。', '2026-02-26 21:05:11', 11, '2026-03-12 15:50:04', NULL, NULL, 1, '判断推理', '');
INSERT INTO `question` VALUES (130, '下列哪个国家被称为\"千岛之国\"？', 1, '[{\"key\": \"A\", \"value\": \"印度尼西亚\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"菲律宾\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"日本\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"马来西亚\", \"imageUrl\": \"\"}]', 'A', '印度尼西亚由上万个岛屿组成，是世界上最大的群岛国家，因此被称为\"千岛之国\"。', '2026-03-12 16:02:23', 16, '2026-03-12 16:02:30', NULL, NULL, 2, '常识判断', '');
INSERT INTO `question` VALUES (131, '中国古代四大发明中，哪一项发明最早？', 1, '[{\"key\": \"A\", \"value\": \"造纸术\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"印刷术\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"火药\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"指南针\", \"imageUrl\": \"\"}]', 'A', '造纸术发明于西汉时期（公元前 2 世纪），是最早的四大发明，其他三项发明时间较\n晚。', '2026-03-12 16:02:23', 16, '2026-03-12 16:02:33', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (132, '地球自转一周需要多长时间？', 1, '[{\"key\": \"A\", \"value\": \"24 小时\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"12 小时\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"365 天\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"30 天\", \"imageUrl\": \"\"}]', 'A', '地球自转一周约为 24 小时，即一天的时间。', '2026-03-12 16:02:23', 16, '2026-03-12 16:02:50', NULL, NULL, 1, '常识判断', '');
INSERT INTO `question` VALUES (133, '下列哪个不属于世界三大宗教？', 1, '[{\"key\": \"A\", \"value\": \"佛教\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"基督教\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"伊斯兰教\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"道教\", \"imageUrl\": \"\"}]', 'D', '世界三大宗教是佛教、基督教和伊斯兰教，道教是中国本土宗教，不属于世界三大宗\n教。', '2026-03-12 16:02:23', 16, '2026-03-12 16:02:59', NULL, NULL, 2, '常识判断', '');
INSERT INTO `question` VALUES (134, '人体最大的器官是什么？', 1, '[{\"key\": \"A\", \"value\": \"心脏\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"肝脏\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"皮肤\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"肺\", \"imageUrl\": \"\"}]', 'C', '皮肤是人体最大的器官，成人皮肤面积约 1.5-2 平方米。', '2026-03-12 16:02:23', 16, '2026-03-12 16:03:05', NULL, NULL, 1, '常识判断', '');
INSERT INTO `question` VALUES (135, '中国的首都是哪个城市？', 1, '[{\"key\": \"A\", \"value\": \"上海\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"北京\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"广州\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"深圳\", \"imageUrl\": \"\"}]', 'B', '北京是中华人民共和国的首都，自 1949 年以来一直是中国的政治中心。', '2026-03-12 16:02:23', 16, '2026-03-12 16:03:09', NULL, NULL, 1, '常识判断', '');
INSERT INTO `question` VALUES (136, '下列哪种动物是哺乳动物？', 1, '[{\"key\": \"A\", \"value\": \"鲨鱼\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"鳄鱼\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"海豚\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"金枪鱼\", \"imageUrl\": \"\"}]', 'C', '海豚是哺乳动物，用肺呼吸，胎生哺乳；鲨鱼、鳄鱼和金枪鱼都不是哺乳动物。', '2026-03-12 16:02:23', 16, '2026-03-12 16:03:15', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (137, '光在真空中的传播速度大约是多少？', 1, '[{\"key\": \"A\", \"value\": \"每秒 30 万公里\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"每秒 3 万公里\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"每秒 300 万公里\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"每秒 3000 公里\", \"imageUrl\": \"\"}]', 'A', '光在真空中的传播速度约为每秒 30 万公里（299,792,458 米/秒）。', '2026-03-12 16:02:23', 16, '2026-03-12 16:03:24', NULL, NULL, 3, '常识判断', '');
INSERT INTO `question` VALUES (138, '下列哪个行星离太阳最近？', 1, '[{\"key\": \"A\", \"value\": \"金星\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"地球\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"火星\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"水星\", \"imageUrl\": \"\"}]', 'D', '水星是太阳系八大行星中离太阳最近的行星，平均距离约 5790 万公里。', '2026-03-12 16:02:23', 16, '2026-03-12 16:03:30', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (139, '中国的国旗是什么？', 1, '[{\"key\": \"A\", \"value\": \"五星红旗\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"红旗\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"红星旗\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"五角星旗\", \"imageUrl\": \"\"}]', 'A', '中华人民共和国国旗是五星红旗，由红色旗面和五颗黄色五角星组成。', '2026-03-12 16:02:23', 16, '2026-03-12 16:03:33', NULL, NULL, 1, '常识判断', '');
INSERT INTO `question` VALUES (142, '水的化学式是什么？', 1, '[{\"key\": \"A\", \"value\": \"H2O\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"CO2\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"O2\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"N2\", \"imageUrl\": \"\"}]', 'A', '水的化学式是 H2O，由两个氢原子和一个氧原子组成。', '2026-03-12 16:02:23', 16, '2026-03-12 16:03:46', NULL, NULL, 1, '常识判断', '');
INSERT INTO `question` VALUES (146, '太阳从哪个方向升起？', 1, '[{\"key\": \"A\", \"value\": \"东方\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"西方\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"南方\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"北方\", \"imageUrl\": \"\"}]', 'A', '由于地球自西向东自转，太阳看起来从东方升起，从西方落下。', '2026-03-12 16:02:23', 16, '2026-03-12 16:04:15', NULL, NULL, 2, '常识判断', '');
INSERT INTO `question` VALUES (149, '一年有多少个季节？', 1, '[{\"key\": \"A\", \"value\": \"2 个\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"3 个\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"4 个\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"5 个\", \"imageUrl\": \"\"}]', 'C', '一年有春、夏、秋、冬四个季节，这是基本的自然常识。', '2026-03-12 16:02:23', 16, '2026-03-12 16:04:27', NULL, NULL, 1, '常识判断', '');
INSERT INTO `question` VALUES (150, '下列关于我国宪法规定的公民基本权利的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"公民的私有财产神圣不可侵犯\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"公民有言论、出版、集会、结社、游行、示威的自由\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"公民有劳动的权利和义务\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"公民有休息的权利\", \"imageUrl\": \"\"}]', 'C', '我国宪法规定，公民有劳动的权利和义务。A 选项\"神圣不可侵犯\"表述不准确，宪法\n规定的是\"公民的合法的私有财产不受侵犯\"；B 选项表述正确，但不是最完整的表述；D 选\n项公民有休息的权利，但不是基本权利表述的核心。', '2026-03-12 16:09:29', 16, '2026-03-12 16:10:16', NULL, NULL, 2, '常识判断', '');
INSERT INTO `question` VALUES (151, '下列关于我国行政区划的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"全国分为省、自治区、直辖市\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"省、自治区分为自治州、县、自治县、市\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"县、自治县分为乡、民族乡、镇\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"直辖市和较大的市分为区、县\", \"imageUrl\": null}]', 'A', '宪法规定，全国分为省、自治区、直辖市。省、自治区分为自治州、县、自治县、市。\n县、自治县分为乡、民族乡、镇。直辖市和较大的市分为区、县。自治州分为县、自治县、\n市。A 选项表述正确且完整。', '2026-03-12 16:09:29', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (152, '下列关于我国民族区域自治制度的表述，错误的是：', 1, '[{\"key\": \"A\", \"value\": \"民族自治地方分为自治区、自治州、自治县三级\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"民族自治地方的自治机关是自治区、自治州、自治县的人民代表大会和人民政府\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"民族自治地方的人民代表大会常务委员会中应当有实行区域自治的民族的公民担任主任\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"民族自治地方的人民法院院长必须由实行区域自治的民族的公民担任\", \"imageUrl\": \"\"}]', 'D', '民族自治地方的人民法院院长和人民检察院检察长，由实行区域自治的民族的公民担\n任，但不是\"必须\"，而是\"应当由\"。D 选项表述过于绝对，错误。', '2026-03-12 16:09:29', 16, '2026-03-12 16:10:32', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (153, '下列关于我国人民代表大会制度的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"全国人民代表大会是最高国家权力机关\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"全国人民代表大会常务委员会是全国人民代表大会的常设机关\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"全国人民代表大会每届任期五年\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"全国人民代表大会代表由省、自治区、直辖市、特别行政区和军队选出的代表组成\", \"imageUrl\": \"\"}]', 'A', '全国人民代表大会是最高国家权力机关，这是宪法明确规定的。B 选项表述正确，但\nA 选项更核心；C 选项表述正确，但不是人民代表大会制度的本质特征；D 选项表述正确，\n但 A 选项更根本。', '2026-03-12 16:09:30', 16, '2026-03-12 16:09:42', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (154, '下列关于我国国家主席的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"国家主席是国家元首\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"国家主席每届任期同全国人民代表大会每届任期相同\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"国家主席连续任职不得超过两届\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"国家主席缺位的时候，由副主席继任主席的职位\", \"imageUrl\": null}]', 'B', '国家主席每届任期同全国人民代表大会每届任期相同，即五年。A 选项\"国家元首\"不\n是宪法表述；C 选项宪法没有规定国家主席连续任职不得超过两届；D 选项国家主席缺位的\n时候，由副主席继任主席的职位，但 B 选项更符合宪法原文表述。', '2026-03-12 16:09:30', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (155, '下列关于我国国务院的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"国务院即中央人民政府\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"国务院是最高国家权力机关的执行机关\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"国务院是最高国家行政机关\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"国务院实行总理负责制\", \"imageUrl\": null}]', 'D', '国务院实行总理负责制，这是宪法明确规定的。A、B、C 选项表述都正确，但 D 选项\n是国务院组织原则的核心特征。', '2026-03-12 16:09:30', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (156, '下列关于我国人民法院的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"中级人民法院是最高审判机关\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"最高人民法院监督地方各级人民法院和专门人民法院的审判工作\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"最高人民法院院长每届任期同全国人民代表大会每届任期相同\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"最高人民法院院长连续任职不得超过两届\", \"imageUrl\": \"\"}]', 'B', '最高人民法院监督地方各级人民法院和专门人民法院的审判工作，这是宪法明确规定\n的。A 选项\"最高审判机关\"表述错误， B 选项更体现监督关系；C 选项表述正确，但不是\n核心；D 选项宪法没有规定连续任职不得超过两届。', '2026-03-12 16:09:30', 16, '2026-03-12 16:18:45', NULL, NULL, 3, '常识判断', '');
INSERT INTO `question` VALUES (157, '下列关于我国人民检察院的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"最高人民检察院是最高检察机关\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"最高人民检察院领导地方各级人民检察院和专门人民检察院的工作\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"最高人民检察院检察长每届任期同全国人民代表大会每届任期相同\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"最高人民检察院检察长连续任职不得超过两届\", \"imageUrl\": null}]', 'B', '最高人民检察院领导地方各级人民检察院和专门人民检察院的工作，这是宪法明确规\n定的。A 选项\"最高检察机关\"表述正确，但 B 选项更体现领导关系；C 选项表述正确，但不\n是核心；D选项宪法没有规定连续任职不得超过两届。', '2026-03-12 16:09:30', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (158, '下列关于我国监察委员会的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"中华人民共和国设立国家监察委员会和地方各级监察委员会\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"国家监察委员会是最高监察机关\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"国家监察委员会领导地方各级监察委员会的工作\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"监察委员会由主任、副主任若干人、委员若干人组成\", \"imageUrl\": \"\"}]', 'B', '国家监察委员会是最高监察机关，这是宪法明确规定的。A、C、D 选项表述都正确，\n但 B 选项是监察委员会地位的核心表述。', '2026-03-12 16:09:30', 16, '2026-03-12 16:09:56', NULL, NULL, 3, '常识判断', '');
INSERT INTO `question` VALUES (160, '下列关于我国国徽的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"中华人民共和国国徽中间是五星照耀下的天安门\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"国徽周围是谷穗和齿轮\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"国徽以红色和金色为主色调\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"国徽图案由中央人民政府委员会确定\", \"imageUrl\": \"\"}]', 'A', '国徽中间是五星照耀下的天安门，这是宪法明确规定的。B、C、D 选项表述都正确，\n但 A 选项是国徽图案的核心特征。', '2026-03-12 16:09:30', 16, '2026-03-12 16:10:41', NULL, NULL, 2, '常识判断', '');
INSERT INTO `question` VALUES (161, '下列关于我国首都的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"中华人民共和国首都是北京\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"北京是直辖市\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"北京是国家政治、经济、文化中心\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"北京是国际交往中心\", \"imageUrl\": \"\"}]', 'A', '中华人民共和国首都是北京，这是宪法明确规定的。B、C、D 选项表述都正确，但 A\n选项是宪法规定的根本表述。', '2026-03-12 16:09:30', 16, '2026-03-12 16:10:46', NULL, NULL, 1, '常识判断', '');
INSERT INTO `question` VALUES (162, '下列关于我国国家机构的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"全国人民代表大会是最高国家权力机关\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"国务院是最高国家行政机关\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"中央军事委员会领导全国武装力量\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"国家监察委员会是最高监察机关\", \"imageUrl\": \"\"}]', 'A', '全国人民代表大会是最高国家权力机关，这是宪法明确规定的国家机构根本原则。B、\nC、D 选项表述都正确，但 A 选项是国家机构体系的核心。', '2026-03-12 16:09:30', 16, '2026-03-12 16:10:05', NULL, NULL, 2, '常识判断', '');
INSERT INTO `question` VALUES (163, '下列关于我国公民基本义务的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"公民有维护国家统一和全国各民族团结的义务\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"公民有遵守宪法和法律的义务\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"公民有维护国家安全、荣誉和利益的义务\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"公民有依法纳税的义务\", \"imageUrl\": null}]', 'A', '公民有维护国家统一和全国各民族团结的义务，这是宪法明确规定的首要义务。B、\nC、D 选项表述都正确，但 A 选项是公民基本义务的首要内容。', '2026-03-12 16:09:30', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (164, '下列关于我国选举制度的核心原则是：', 1, '[{\"key\": \"A\", \"value\": \"中华人民共和国年满十八周岁的公民，不分民族、种族、性别、职业、家庭出身、宗教信仰\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"依照法律被剥夺政治权利的人没有选举权和被选举权\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"全国人民代表大会代表由省、自治区、直辖市、特别行政区和军队选出的代表组成\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"全国人民代表大会代表的名额不超过三千人\", \"imageUrl\": \"\"}]', 'A', '年满十八周岁的公民，不分民族、种族、性别、职业、家庭出身、宗教信仰、教育程度、财产状况、居住期限，都有选举权和被选举权，这是宪法明确规定的选举制度基本原则。\nB、C、D 选项表述都正确，但 A 选项是选举制度的核心原则。', '2026-03-12 16:09:30', 16, '2026-03-12 16:11:50', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (165, '下列关于我国国家赔偿制度的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"国家机关和国家机关工作人员行使职权，有本法规定的侵犯公民、法人和其他组织合法权\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"国家赔偿以支付赔偿金为主要方式\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"能够返还财产或者恢复原状的，予以返还财产或者恢复原状\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"造成公民身体伤害的，应当支付医疗费、护理费，以及赔偿因误工减少的收入\", \"imageUrl\": \"\"}]', 'A', '国家机关和国家机关工作人员行使职权，有本法规定的侵犯公民、法人和其他组织合\n法权益的情形，造成损害的，受害人有依照本法取得国家赔偿的权利，这是国家赔偿法明确\n规定的国家赔偿制度基本原则。B、C、D 选项表述都正确，但 A 选项是国家赔偿制度的核心\n原则。', '2026-03-12 16:09:30', 16, '2026-03-12 16:10:52', NULL, NULL, 5, '常识判断', '');
INSERT INTO `question` VALUES (166, '下列关于我国行政复议制度的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"公民、法人或者其他组织认为行政机关的具体行政行为侵犯其合法权益，可以依法申请行\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"行政复议机关负责法制工作的机构具体办理行政复议事项\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"行政复议申请期限为知道该具体行政行为之日起六十日内\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"行政复议决定作出前，申请人可以撤回行政复议申请\", \"imageUrl\": null}]', 'A', '公民、法人或者其他组织认为行政机关的具体行政行为侵犯其合法权益，可以依法申\n请行政复议，这是行政复议法明确规定的行政复议制度基本原则。B、C、D 选项表述都正确，\n但 A 选项是行政复议制度的核心原则。', '2026-03-12 16:09:30', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (167, '下列关于我国行政诉讼制度的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权益，\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"人民法院受理公民、法人和其他组织提起的下列诉讼：对行政拘留、暂扣或者吊销许可证\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"人民法院审理行政案件，以法律和行政法规、地方性法规为依据\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"人民法院审理行政案件，参照规章\", \"imageUrl\": \"\"}]', 'A', '公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权\n益，有权向人民法院提起诉讼，这是行政诉讼法明确规定的行政诉讼制度基本原则。B、C、\nD选项表述都正确，但 A 选项是行政诉讼制度的核心原则。', '2026-03-12 16:09:30', 16, '2026-03-12 16:10:08', NULL, NULL, 5, '常识判断', '');
INSERT INTO `question` VALUES (168, '下列关于我国行政许可制度的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"行政许可，是指行政机关根据公民、法人或者其他组织的申请，经依法审查，准予其从事\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"设定和实施行政许可，应当遵循公开、公平、公正的原则\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"符合法定条件、标准的，申请人有依法取得行政许可的平等权利，行政机关不得歧视\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"实施行政许可，应当遵循便民的原则，提高办事效率，提供优质服务\", \"imageUrl\": null}]', 'A', '行政许可，是指行政机关根据公民、法人或者其他组织的申请，经依法审查，准予其\n从事特定活动的行为，这是行政许可法明确规定的行政许可制度定义。B、C、D 选项表述都\n正确，但 A 选项是行政许可制度的核心定义。', '2026-03-12 16:09:30', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (169, '下列关于我国行政处罚制度的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"行政处罚，是指行政机关依法对违反行政管理秩序的公民、法人或者其他组织，以减损权\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"行政处罚的种类：警告、罚款、没收违法所得、没收非法财物、责令停产停业、暂扣或者\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"行政处罚由违法行为发生地的县级以上地方人民政府具有行政处罚权的行政机关管辖\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"当事人对行政处罚决定不服申请行政复议或者提起行政诉讼的，行政处罚不停止执行，法\", \"imageUrl\": \"\"}]', 'A', '行政处罚，是指行政机关依法对违反行政管理秩序的公民、法人或者其他组织，以减\n损权益或者增加义务的方式予以惩戒的行为，这是行政处罚法明确规定的行政处罚制度定义。\nB、C、D 选项表述都正确，但 A 选项是行政处罚制度的核心定义。', '2026-03-12 16:09:30', 16, '2026-03-12 16:09:52', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (170, '关于我国宪法的发展历程，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"1982 年宪法是我国颁布的第一部宪法\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"2004 年宪法修正案首次将\\\"国家尊重和保障人权\\\"写入宪法\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"2018 年宪法修正案将\\\"习近平新时代中国特色社会主义思想\\\"写入宪法\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国现行宪法共经历了五次修正\", \"imageUrl\": \"\"}]', 'C', 'A 错误，1954 年宪法是我国第一部宪法；B 错误，2004 年修正案将\"国家尊重和保障\n人权\"写入宪法，但不是首次；C 正确，2018 年宪法修正案将\"习近平新时代中国特色社会主\n义思想\"写入宪法；D 错误，我国现行宪法共经历了四次修正（1988、1993、1999、2004、\n2018 年共五次）。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:40', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (171, '下列关于我国货币政策工具的表述，正确的是：', 1, '[{\"key\": \"A\", \"value\": \"存款准备金率属于价格型货币政策工具\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"公开市场操作属于数量型货币政策工具\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"再贴现率属于数量型货币政策工具\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"常备借贷便利属于结构性货币政策工具\", \"imageUrl\": \"\"}]', 'D', 'A 错误，存款准备金率属于数量型货币政策工具；B 错误，公开市场操作属于数量型\n货币政策工具，但主要通过买卖债券调节基础货币；C 错误，再贴现率属于价格型货币政策\n工具；D 正确，常备借贷便利（SLF）属于结构性货币政策工具。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:37', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (172, '关于我国民法典，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"民法典于 2020 年 5 月 28 日通过，2021 年 1 月 1 日起施行\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"民法典共分为七编，包括总则、物权、合同、人格权、婚姻家庭、继承、侵权责任\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"民法典首次确立了\\\"绿色原则\\\"作为民法基本原则\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"民法典废止了《婚姻法》《继承法》《民法通则》《收养法》《担保法》《合同法》《物权法》\", \"imageUrl\": \"\"}]', 'A', 'A 正确，民法典于 2020 年 5 月 28 日通过，2021 年 1 月 1 日起施行；B 错误，民法典\n共分为七编，包括总则、物权、合同、人格权、婚姻家庭、继承、侵权责任，外加附则；C\n错误，\"绿色原则\"在《民法总则》中已确立；D 错误，民法典废止了《婚姻法》《继承法》《民\n法通则》《收养法》《担保法》《合同法》《物权法》《侵权责任法》《民法总则》等九部法律，\n表述正确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:35', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (173, '关于我国航天事业的发展，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国第一颗人造地球卫星\\\"东方红一号\\\"于 1970 年 4 月 24 日发射成功\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国首次载人航天飞行任务由\\\"神舟五号\\\"完成，航天员是杨利伟\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国首次月球软着陆任务由\\\"嫦娥三号\\\"完成\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国首次火星探测任务\\\"天问一号\\\"于 2020 年 7 月 23 日发射成功\", \"imageUrl\": \"\"}]', 'D', 'A 正确，\"东方红一号\"于 1970 年 4 月 24 日发射成功；B 正确，\"神舟五号\"完成首次\n载人航天飞行，航天员是杨利伟；C 正确，\"嫦娥三号\"完成首次月球软着陆；D 正确，\"天问\n一号\"于 2020 年 7 月 23 日发射成功。本题四项均正确，但根据题目要求选择最佳答案，D\n项为最新成就。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:30', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (174, '关于我国古代科技成就，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"《九章算术》是中国古代第一部数学专著，成书于汉代\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"《天工开物》是世界上第一部关于农业和手工业生产的综合性著作\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"《本草纲目》收录药物 1892 种，方剂 11096 个\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"《梦溪笔谈》被英国科学史家李约瑟称为\\\"中国科学史上的里程碑\\\"\", \"imageUrl\": \"\"}]', 'C', 'A 错误，《九章算术》不是第一部数学专著；《天工开物》是世界上第一部关于农业和\n手工业生产的综合性著作，B 正确；《本草纲目》收录药物 1892 种，方剂 11096 个，C 正确；\n《梦溪笔谈》被李约瑟称为\"中国科学史上的里程碑\"，D 正确。本题 C 项数据最准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:26', NULL, NULL, 3, '常识判断', '');
INSERT INTO `question` VALUES (175, '关于世界经济发展史，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"第一次工业革命始于英国，以蒸汽机的广泛应用为标志\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"第二次工业革命以电力的广泛应用为标志，主要发生在德国和美国\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"第三次工业革命以计算机技术、信息技术为代表，始于 20 世纪 40 年代\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"第四次工业革命以人工智能、大数据、云计算、物联网等为代表，始于 21 世纪初\", \"imageUrl\": \"\"}]', 'A', 'A 正确，第一次工业革命始于英国，以蒸汽机的广泛应用为标志；B 错误，第二次工\n业革命以电力的广泛应用为标志，主要发生在德国、美国、英国等；C 错误，第三次工业革\n命以计算机技术、信息技术为代表，始于 20 世纪 50 年代；D错误，第四次工业革命以人工\n智能、大数据、云计算、物联网等为代表，始于 21 世纪 10 年代。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:16', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (176, '关于我国行政区划，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国共有 34 个省级行政区，包括 23 个省、5 个自治区、4 个直辖市、2 个特别行政区\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国面积最大的省级行政区是新疆维吾尔自治区\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国人口最多的省级行政区是广东省\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国海岸线最长的省级行政区是广东省\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国共有 34 个省级行政区，包括 23 个省、5 个自治区、4 个直辖市、2 个\n特别行政区；B 正确，新疆维吾尔自治区是我国面积最大的省级行政区；C 正确，广东省是\n我国人口最多的省级行政区；D 错误，我国海岸线最长的省级行政区是广东省，但本题 A 项\n表述最完整准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:12', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (177, '关于我国环境保护法律法规，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"《环境保护法》于 1989 年颁布实施，是我国第一部综合性环境保护法律\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"《大气污染防治法》于 2015 年修订，首次将\\\"大气污染防治\\\"写入法律\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"《水污染防治法》于 2017 年修订，首次将\\\"水污染防治\\\"写入法律\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"《土壤污染防治法》于 2018 年颁布实施，是我国首部土壤污染防治领域的专门法律\", \"imageUrl\": \"\"}]', 'D', 'A 错误，《环境保护法》于 1989 年颁布实施，但不是第一部综合性环境保护法律；B\n错误，《大气污染防治法》于 2015 年修订，但不是首次将\"大气污染防治\"写入法律；C 错误，\n《水污染防治法》于 2017 年修订，但不是首次将\"水污染防治\"写入法律；D 正确，《土壤污\n染防治法》于 2018 年颁布实施，是我国首部土壤污染防治领域的专门法律。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:03', NULL, NULL, 5, '常识判断', '');
INSERT INTO `question` VALUES (178, '关于我国能源发展，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国是世界上最大的能源生产国和消费国\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国煤炭消费占能源消费总量的比重已降至 50%以下\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国可再生能源装机容量已超过化石能源装机容量\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国已成为世界上最大的光伏发电和风电装机国\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国是世界上最大的能源生产国和消费国；B 错误，我国煤炭消费占能源消\n费总量的比重仍在 50%以上；C 错误，我国可再生能源装机容量尚未超过化石能源装机容量；\nD正确，我国已成为世界上最大的光伏发电和风电装机国。本题 A 项表述最全面。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:59', NULL, NULL, 3, '常识判断', '');
INSERT INTO `question` VALUES (179, '关于我国金融体系，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"中国人民银行是我国的中央银行，负责制定和执行货币政策\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"中国银保监会负责对银行业和保险业进行监督管理\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"中国证监会负责对证券业进行监督管理\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"国家外汇管理局负责管理国家外汇储备\", \"imageUrl\": \"\"}]', 'A', 'A 正确，中国人民银行是我国的中央银行，负责制定和执行货币政策；B 正确，中国\n银保监会负责对银行业和保险业进行监督管理；C 正确，中国证监会负责对证券业进行监督\n管理；D 正确，国家外汇管理局负责管理国家外汇储备。本题 A 项表述最核心。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:54', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (180, '关于我国教育法律法规，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"《教育法》于 1995 年颁布实施，是我国教育领域的根本大法\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"《义务教育法》于 2006 年修订，首次将\\\"义务教育\\\"写入法律\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"《高等教育法》于 1998 年颁布实施，是我国高等教育领域的基本法律\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"《教师法》于 1993 年颁布实施，首次将\\\"教师\\\"职业写入法律\", \"imageUrl\": \"\"}]', 'A', 'A 正确，《教育法》于 1995 年颁布实施，是我国教育领域的根本大法；B 错误，《义\n务教育法》于 2006 年修订，但不是首次将\"义务教育\"写入法律；C 正确，《高等教育法》于\n1998 年颁布实施，是我国高等教育领域的基本法律；D 错误，《教师法》于 1993 年颁布实\n施，但不是首次将\"教师\"职业写入法律。本题 A 项表述最准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:34', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (181, '关于我国交通运输发展，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国高速公路总里程已超过 17 万公里，居世界第一\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"我国高速铁路总里程已超过 4 万公里，居世界第一\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"我国港口货物吞吐量已连续多年居世界第一\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"我国机场数量已超过 500 个，居世界第一\", \"imageUrl\": null}]', 'A', 'A 正确，我国高速公路总里程已超过 17 万公里，居世界第一；B 正确，我国高速铁\n路总里程已超过 4 万公里，居世界第一；C 正确，我国港口货物吞吐量已连续多年居世界第\n一；D错误，我国机场数量已超过 500 个，但不是世界第一。本题 A 项表述最准确。', '2026-03-12 16:16:18', 16, NULL, NULL, NULL, 3, '常识判断', NULL);
INSERT INTO `question` VALUES (182, '关于我国农业发展，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国是世界上最大的农产品生产国和消费国\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国粮食产量已连续多年稳定在 6.5 亿吨以上\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国水稻、小麦、玉米三大主粮自给率均超过 95%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国已成为世界上最大的农产品进口国\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国是世界上最大的农产品生产国和消费国；B 正确，我国粮食产量已连续\n多年稳定在 6.5 亿吨以上；C 正确，我国水稻、小麦、玉米三大主粮自给率均超过 95%；D\n正确，我国已成为世界上最大的农产品进口国。本题 A 项表述最全面。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:29', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (183, '关于我国社会保障体系，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国已建成世界上最大的社会保障体系\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国基本养老保险参保人数已超过 10 亿人\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国基本医疗保险参保率已超过 95%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国失业保险参保人数已超过 2 亿人\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国已建成世界上最大的社会保障体系；B 正确，我国基本养老保险参保人\n数已超过 10 亿人；C 正确，我国基本医疗保险参保率已超过 95%；D 正确，我国失业保险\n参保人数已超过 2 亿人。本题 A 项表述最全面。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:40', NULL, NULL, 3, '常识判断', '');
INSERT INTO `question` VALUES (184, '关于我国科技创新，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国研发经费投入已超过 2.5 万亿元，居世界第二\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国专利申请量已连续多年居世界第一\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国高新技术企业数量已超过 30 万家\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国已成为世界上最大的科技人力资源国\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国研发经费投入已超过 2.5 万亿元，居世界第二；B 正确，我国专利申请\n量已连续多年居世界第一；C 正确，我国高新技术企业数量已超过 30 万家；D 正确，我国\n已成为世界上最大的科技人力资源国。本题 A 项表述最准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:27', NULL, NULL, 5, '常识判断', '');
INSERT INTO `question` VALUES (185, '关于我国文化产业发展，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国文化产业增加值已超过 5 万亿元，占 GDP 比重超过 4%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国电影票房收入已超过 600 亿元，居世界第一\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国图书出版品种已超过 50 万种，居世界第一\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国网络游戏市场规模已超过 3000 亿元，居世界第一\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国文化产业增加值已超过 5 万亿元，占 GDP 比重超过 4%；B 错误，我国\n电影票房收入已超过 600 亿元，但不是世界第一；C 正确，我国图书出版品种已超过 50 万\n种，居世界第一；D 正确，我国网络游戏市场规模已超过 3000 亿元，居世界第一。本题 A\n项表述最全面。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:23', NULL, NULL, 5, '常识判断', '');
INSERT INTO `question` VALUES (186, '关于我国生态文明建设，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国森林覆盖率已超过 23%，森林蓄积量已超过 175 亿立方米\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国湿地保护率已超过 50%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国自然保护区面积已超过国土面积的 15%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国荒漠化土地面积已连续多年实现净减少\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国森林覆盖率已超过 23%，森林蓄积量已超过 175 亿立方米；B 错误，我\n国湿地保护率已超过 50%，但表述不够准确；C 错误，我国自然保护区面积已超过国土面积\n的 15%，但表述不够准确；D正确，我国荒漠化土地面积已连续多年实现净减少。本题 A 项\n表述最准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:16:21', NULL, NULL, 5, '常识判断', '');
INSERT INTO `question` VALUES (187, '关于我国对外开放，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国已与 180 多个国家和地区建立了外交关系\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国已成为世界上最大的货物贸易国\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国已成为世界上最大的外资流入国\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国已成为世界上最大的对外投资国\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国已与 180 多个国家和地区建立了外交关系；B 正确，我国已成为世界上\n最大的货物贸易国；C 错误，我国已成为世界上最大的外资流入国，但表述不够准确；D 错\n误，我国已成为世界上最大的对外投资国，但表述不够准确。本题 A 项表述最准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:43', NULL, NULL, 4, '常识判断', '');
INSERT INTO `question` VALUES (188, '关于我国脱贫攻坚，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国已实现现行标准下农村贫困人口全部脱贫\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国贫困县已全部摘帽\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国消除了绝对贫困\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国创造了人类减贫史上的奇迹\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国已实现现行标准下农村贫困人口全部脱贫；B 正确，我国贫困县已全部\n摘帽；C 正确，我国消除了绝对贫困；D 正确，我国创造了人类减贫史上的奇迹。本题 A 项\n表述最准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:48', NULL, NULL, 3, '常识判断', '');
INSERT INTO `question` VALUES (189, '关于我国疫情防控，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"我国率先控制住疫情，率先复工复产\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"我国疫苗研发和接种工作走在世界前列\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国向国际社会提供了大量疫苗和防疫物资\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国为全球抗疫作出了重要贡献\", \"imageUrl\": \"\"}]', 'A', 'A 正确，我国率先控制住疫情，率先复工复产；B 正确，我国疫苗研发和接种工作走\n在世界前列；C 正确，我国向国际社会提供了大量疫苗和防疫物资；D正确，我国为全球抗\n疫作出了重要贡献。本题 A 项表述最准确。', '2026-03-12 16:16:18', 16, '2026-03-12 16:17:57', NULL, NULL, 2, '常识判断', '');
INSERT INTO `question` VALUES (190, '随着人工智能技术的快速发展，其在医疗、教育、交通等领域的应用日益广泛。然而，人工智能在带来便利的同时，也引发了数据隐私、算法偏见、就业冲击等一系列社会问题。如何在推动技术创新的同时，有效规避其潜在风险，成为社会各界共同关注的焦点。', 1, '[{\"key\": \"A\", \"value\": \"人工智能技术发展迅速\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"人工智能应用领域广泛\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"人工智能带来便利与挑战\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"人工智能引发社会问题\", \"imageUrl\": \"\"}]', 'C', '文段首先介绍了人工智能技术的发展和应用，然后指出其带来的社会问题，最后强调\n需要在推动技术创新的同时规避风险。文段既提到了人工智能的便利，也提到了其带来的挑\n战，C 项\"人工智能带来便利与挑战\"最能概括文段主旨。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:08', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (191, '城市化进程中，大量农村人口涌入城市，为城市发展提供了充足的劳动力，但也给城市管理带来了巨大压力。如何妥善安置进城务工人员，保障其合法权益，促进其融入城市生活，成为城市治理的重要课题。', 1, '[{\"key\": \"A\", \"value\": \"城市化进程加速\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"农村人口涌入城市\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"进城务工人员安置问题\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"城市治理面临挑战\", \"imageUrl\": \"\"}]', 'C', '文段首先描述了城市化进程中农村人口涌入城市的现象，然后指出这给城市管理带来\n压力，最后强调如何妥善安置进城务工人员成为重要课题。文段的核心话题是进城务工人员\n的安置问题，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:16', NULL, NULL, 1, '言语理解', '');
INSERT INTO `question` VALUES (192, '传统文化是民族精神的载体，是文化自信的根基。在全球化背景下，如何传承和弘扬优秀传统文化，使其在现代社会焕发新的生机，是我们面临的重要任务。只有深入挖掘传统文化的当代价值，才能让传统文化真正\"活\"起来。', 1, '[{\"key\": \"A\", \"value\": \"传统文化的重要性\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"全球化对传统文化的影响\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"传承弘扬传统文化的方法\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"传统文化当代价值的挖掘\", \"imageUrl\": \"\"}]', 'D', '文段首先强调传统文化的重要性，然后指出传承弘扬传统文化的任务，最后提出\"只\n有深入挖掘传统文化的当代价值，才能让传统文化真正\'活\'起来\"。文段的落脚点在于挖掘传\n统文化的当代价值，D 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:02:47', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (193, '共享经济作为一种新兴的经济模式，通过整合闲置资源，提高了资源利用效率，降低了消费成本。然而，共享经济在快速发展的同时，也面临着监管滞后、信用体系不完善、消费者权益保护不足等问题。完善相关法律法规，建立健全信用体系，是促进共享经济健康发展\n的关键', 1, '[{\"key\": \"A\", \"value\": \"共享经济的优势\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"共享经济面临的问题\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"共享经济的发展现状\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"共享经济健康发展的对策\", \"imageUrl\": \"\"}]', 'D', '文段首先介绍了共享经济的优势，然后指出其面临的问题，最后提出完善法律法规和\n建立健全信用体系是促进共享经济健康发展的关键。文段的落脚点在于促进共享经济健康发\n展的对策，D 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:28', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (194, '随着移动互联网的普及，短视频平台迅速崛起，成为人们获取信息、娱乐休闲的重要渠道。短视频以其碎片化、即时性的特点，满足了快节奏生活下人们的需求。但过度沉迷短视频，可能导致注意力分散、思维浅薄化等问题，影响人们的深度思考能力。', 1, '[{\"key\": \"A\", \"value\": \"短视频平台的兴起\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"短视频的特点和优势\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"短视频的负面影响\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"短视频的双面性\", \"imageUrl\": \"\"}]', 'D', '文段首先介绍了短视频平台的兴起和优势，然后指出过度沉迷短视频可能导致的问题。\n文段既提到了短视频的优势，也提到了其负面影响，D 项\"短视频的双面性\"最能概括文段主\n旨。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:35', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (195, '碳中和目标的提出，标志着我国绿色低碳发展进入新阶段。实现碳中和目标，需要能源结构、产业结构、技术体系等多方面的深刻变革。这既是一场严峻的挑战，也是推动高质量发展的重大机遇。', 1, '[{\"key\": \"A\", \"value\": \"碳中和目标的提出\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"实现碳中和的挑战\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"碳中和带来的机遇\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"碳中和的挑战与机遇\", \"imageUrl\": \"\"}]', 'D', '文段首先提出碳中和目标，然后指出实现碳中和需要多方面变革，最后强调这既是挑\n战也是机遇。文段的落脚点在于碳中和的挑战与机遇，D项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:42', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (196, '数字化转型已成为企业提升竞争力的重要途径。通过数字化技术，企业可以实现生产流程优化、管理效率提升、商业模式创新。然而，数字化转型并非一蹴而就，需要企业根据自身实际情况，制定科学的转型策略，循序渐进地推进。', 1, '[{\"key\": \"A\", \"value\": \"数字化转型的重要性\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"数字化转型的优势\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"数字化转型的挑战\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"数字化转型的策略\", \"imageUrl\": \"\"}]', 'D', '文段首先指出数字化转型的重要性，然后介绍其优势，最后强调数字化转型需要制定\n科学的转型策略，循序渐进地推进。文段的落脚点在于数字化转型的策略，D 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:51', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (197, '乡村振兴战略的实施，为农村发展带来了新的机遇。通过产业振兴、人才振兴、文化振兴、生态振兴、组织振兴，可以全面激发农村发展活力，促进城乡融合发展。乡村振兴是一项系统工程，需要统筹规划、协同推进。', 1, '[{\"key\": \"A\", \"value\": \"乡村振兴战略的意义\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"乡村振兴的内容\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"乡村振兴的系统性\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"乡村振兴的实施路径\", \"imageUrl\": \"\"}]', 'D', '文段首先指出乡村振兴战略带来的机遇，然后介绍乡村振兴的内容，最后强调乡村振\n兴是一项系统工程，需要统筹规划、协同推进。文段的落脚点在于乡村振兴的实施路径，D\n项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:21', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (198, '在信息爆炸的时代，如何从海量信息中筛选出有价值的内容，成为一项重要能力。批判性思维能够帮助我们辨别信息的真伪，评估信息的价值，从而做出理性的判断。培养批判性思维，对于提升个人素养、适应社会发展具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"信息时代的挑战\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"批判性思维的作用\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"批判性思维的培养\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"批判性思维的重要性\", \"imageUrl\": \"\"}]', 'D', '文段首先指出信息时代筛选有价值信息的重要性，然后介绍批判性思维的作用，最后\n强调培养批判性思维对于提升个人素养、适应社会发展具有重要意义。文段的落脚点在于批\n判性思维的重要性，D 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:03', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (199, '随着人口老龄化加剧，养老问题日益凸显。传统的家庭养老模式面临挑战，社会化养老服务体系亟待完善。建立多层次、多元化的养老服务体系，满足不同老年人的需求，是应对人口老龄化的重要举措。', 1, '[{\"key\": \"A\", \"value\": \"人口老龄化的现状\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"传统养老模式的局限\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"养老服务体系的完善\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"应对人口老龄化的措施\", \"imageUrl\": \"\"}]', 'D', '文段首先指出人口老龄化带来的养老问题，然后分析传统养老模式的局限，最后提出\n建立多层次、多元化的养老服务体系是应对人口老龄化的重要举措。文段的落脚点在于应对\n人口老龄化的措施，D 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:15', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (200, '创新是引领发展的第一动力。在科技革命和产业变革加速演进的背景下，谁掌握了核心技术，谁就能在竞争中占据主动。加强基础研究，突破关键核心技术，是实现科技自立自强的必由之路。', 1, '[{\"key\": \"A\", \"value\": \"创新的重要性\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"科技革命的背景\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"核心技术的竞争\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"科技自立自强的路径\", \"imageUrl\": \"\"}]', 'D', '文段首先强调创新的重要性，然后指出在科技革命背景下掌握核心技术的意义，最后\n提出加强基础研究、突破关键核心技术是实现科技自立自强的必由之路。文段的落脚点在于\n科技自立自强的路径，D项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:09', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (201, '绿色发展是实现可持续发展的必然选择。通过发展绿色产业、推广绿色技术、倡导绿色生活方式，可以实现经济发展与环境保护的协调统一。绿色发展不仅是生态要求，也是经济转型升级的重要抓手。', 1, '[{\"key\": \"A\", \"value\": \"绿色发展的意义\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"绿色发展的内容\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"绿色发展的措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"绿色发展的重要性\", \"imageUrl\": \"\"}]', 'A', '文段首先指出绿色发展是实现可持续发展的必然选择，然后介绍绿色发展的具体内容，\n最后强调绿色发展不仅是生态要求，也是经济转型升级的重要抓手。文段主要阐述绿色发展\n的意义，A 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:19', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (202, '教育公平是社会公平的重要基础。推进教育公平，需要缩小城乡、区域、校际差距，保障每个孩子都能享有公平而有质量的教育。教育公平的实现，需要政府、学校、家庭、社会共同努力。', 1, '[{\"key\": \"A\", \"value\": \"教育公平的重要性\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"教育公平的现状\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"教育公平的实现途径\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"教育公平的挑战\", \"imageUrl\": \"\"}]', 'C', '文段首先指出教育公平的重要性，然后提出推进教育公平需要缩小差距，最后强调教\n育公平的实现需要多方共同努力。文段的落脚点在于教育公平的实现途径，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:23', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (203, '在全球化深入发展的今天，各国相互依存、休戚与共。构建人类命运共同体，是应对全球性挑战、促进世界和平发展的中国方案。这一理念得到了国际社会的广泛认同。', 1, '[{\"key\": \"A\", \"value\": \"全球化的发展\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"人类命运共同体的内涵\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"人类命运共同体的意义\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"人类命运共同体的国际认同\", \"imageUrl\": \"\"}]', 'C', '文段首先指出全球化背景下各国相互依存，然后提出构建人类命运共同体是应对全球\n性挑战、促进世界和平发展的中国方案，最后指出这一理念得到了国际社会的广泛认同。文\n段主要阐述人类命运共同体的意义，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:28', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (204, '随着生活水平的提高，人们对健康的重视程度不断提升。健康中国战略的实施，旨在提高全民健康水平，促进健康与经济社会协调发展。实现健康中国目标，需要完善医疗卫生服务体系，倡导健康生活方式。', 1, '[{\"key\": \"A\", \"value\": \"健康意识的提升\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"健康中国战略的意义\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"健康中国的实施路径\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"健康中国的目标\", \"imageUrl\": \"\"}]', 'C', '文段首先指出人们对健康的重视程度提升，然后介绍健康中国战略的意义，最后提出\n实现健康中国目标需要完善医疗卫生服务体系、倡导健康生活方式。文段的落脚点在于健康\n中国的实施路径，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:33', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (205, '数字经济是推动经济高质量发展的重要引擎。通过数字技术与实体经济深度融合，可以催生新业态、新模式，提升经济运行效率。发展数字经济，需要加强数字基础设施建设，培育数字人才，完善数字治理体系。', 1, '[{\"key\": \"A\", \"value\": \"数字经济的地位\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"数字经济的作用\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"数字经济的发展措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"数字经济的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出数字经济是推动经济高质量发展的重要引擎，然后介绍数字经济的作用，\n最后提出发展数字经济需要加强基础设施建设、培育人才、完善治理体系。文段的落脚点在\n于数字经济的发展措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:38', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (206, '文化自信是一个国家、一个民族发展中更基本、更深沉、更持久的力量。坚定文化自信，需要传承中华优秀传统文化，弘扬革命文化，发展社会主义先进文化。文化自信的建立，对于提升国家文化软实力具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"文化自信的重要性\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"文化自信的内涵\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"文化自信的建立途径\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"文化自信的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出文化自信的重要性，然后提出坚定文化自信需要传承传统文化、弘扬革\n命文化、发展先进文化，最后强调文化自信的建立对于提升国家文化软实力具有重要意义。\n文段的落脚点在于文化自信的建立途径，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:43', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (207, '随着城市化进程的加快，城市交通拥堵问题日益突出。解决交通拥堵问题，需要综合施策，包括优化城市布局、完善公共交通体系、推广智能交通技术等。交通拥堵问题的解决，对于提升城市居民生活质量具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"城市交通拥堵的现状\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"交通拥堵的成因\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"交通拥堵的解决措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"交通拥堵的影响\", \"imageUrl\": \"\"}]', 'C', '文段首先指出城市交通拥堵问题日益突出，然后提出解决交通拥堵问题需要综合施策，\n包括优化布局、完善公共交通、推广智能交通技术等。文段的落脚点在于交通拥堵的解决措\n施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:52', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (208, '生态文明建设是关系中华民族永续发展的根本大计。加强生态文明建设，需要树立绿水青山就是金山银山的理念，推进绿色发展，建设美丽中国。生态明建设的推进，对于实现人与自然和谐共生具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"生态文明建设的意义\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"生态文明建设的理念\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"生态文明建设的措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"生态文明建设的目标\", \"imageUrl\": \"\"}]', 'C', '文段首先指出生态文明建设的重要性，然后提出加强生态文明建设需要树立理念、推\n进绿色发展、建设美丽中国。文段的落脚点在于生态文明建设的措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:04:58', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (209, '在知识经济时代，终身学习已成为个人发展的必然要求。通过持续学习，可以不断提升自身能力，适应社会发展变化。建立学习型社会，需要完善终身教育体系，营造全民学习的良好氛围。', 1, '[{\"key\": \"A\", \"value\": \"知识经济的特点\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"终身学习的重要性\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"学习型社会的建设\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"终身教育的完善\", \"imageUrl\": \"\"}]', 'C', '文段首先指出知识经济时代终身学习的重要性，然后介绍持续学习的作用，最后提出\n建立学习型社会需要完善终身教育体系、营造全民学习氛围。文段的落脚点在于学习型社会\n的建设，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:03', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (210, '随着\"一带一路\"倡议的深入推进，我国与沿线国家的经贸合作日益密切。通过加强基础设施建设、促进贸易投资便利化、深化人文交流，可以实现互利共赢、共同发展。\"一带一路\"建设为世界经济增长注入了新动力。', 1, '[{\"key\": \"A\", \"value\": \"\\\"一带一路\\\"倡议的推进\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"\\\"一带一路\\\"合作的内容\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"\\\"一带一路\\\"的意义\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"\\\"一带一路\\\"的影响\", \"imageUrl\": \"\"}]', 'C', '文段首先指出\"一带一路\"倡议的推进，然后介绍合作的内容，最后强调\"一带一路\"建\n设为世界经济增长注入了新动力。文段主要阐述\"一带一路\"的意义，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:08', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (211, '在互联网时代，网络空间已成为人们生活的重要组成部分。维护网络安全，需要加强网\n络基础设施建设，完善网络安全法律法规，提升网络安全防护能力。网络安全的维护，对于\n保障国家安全、促进社会稳定具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"网络空间的重要性\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"网络安全的挑战\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"网络安全的维护措施\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"网络安全的意义\", \"imageUrl\": null}]', 'C', '文段首先指出网络空间的重要性，然后提出维护网络安全需要加强基础设施建设、完\n善法律法规、提升防护能力。文段的落脚点在于网络安全的维护措施，C 项最为准确。', '2026-03-12 17:02:28', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (212, '随着消费升级趋势的加强，人们对美好生活的需求日益增长。满足人民日益增长的美好生活需要，需要深化供给侧结构性改革，提高产品和服务质量。消费升级的实现，对于促进经济高质量发展具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"消费升级的趋势\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"美好生活的需求\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"消费升级的实现路径\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"消费升级的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出消费升级趋势加强，然后提出满足美好生活需要需要深化供给侧结构性\n改革、提高产品和服务质量。文段的落脚点在于消费升级的实现路径，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:13', NULL, NULL, 1, '言语理解', '');
INSERT INTO `question` VALUES (213, '在科技创新日新月异的今天，知识产权保护的重要性日益凸显。加强知识产权保护，可以激励创新创造，促进科技成果转化，提升国家核心竞争力。知识产权保护的加强，对于建设创新型国家具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"科技创新的特点\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"知识产权保护的重要性\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"知识产权保护的作用\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"知识产权保护的意义\", \"imageUrl\": \"\"}]', 'D', '文段首先指出知识产权保护的重要性日益凸显，然后介绍知识产权保护的作用，最后\n强调知识产权保护的加强对于建设创新型国家具有重要意义。文段主要阐述知识产权保护的\n意义，D 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:19', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (214, '随着经济全球化的深入发展，产业链供应链的安全稳定问题日益受到重视。保障产业链供应链安全稳定，需要加强关键核心技术攻关，完善产业链供应链布局，提升产业链供应链韧性。产业链供应链的安全稳定，对于经济高质量发展具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"经济全球化的影响\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"产业链供应链的重要性\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"产业链供应链的保障措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"产业链供应链的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出产业链供应链安全稳定问题日益受到重视，然后提出保障产业链供应链\n安全稳定需要加强技术攻关、完善布局、提升韧性。文段的落脚点在于产业链供应链的保障\n措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:23', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (215, '在乡村振兴战略实施背景下，农村电商发展迅速。农村电商的发展，可以拓宽农产品销售渠道，增加农民收入，促进农村经济发展。推动农村电商发展，需要完善农村物流体系，加强电商人才培养，提升农产品质量。', 1, '[{\"key\": \"A\", \"value\": \"乡村振兴战略的实施\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"农村电商的发展\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"农村电商的发展措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"农村电商的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出乡村振兴战略背景下农村电商发展迅速，然后介绍农村电商的作用，最\n后提出推动农村电商发展需要完善物流体系、加强人才培养、提升产品质量。文段的落脚点\n在于农村电商的发展措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:29', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (216, '随着生态文明建设的深入推进，绿色消费理念日益深入人心。推广绿色消费，需要完善\n绿色产品标准体系，加强绿色消费宣传教育，营造绿色消费的良好氛围。绿色消费的推广，\n对于促进绿色发展具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"生态文明建设的推进\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"绿色消费理念\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"绿色消费的推广措施\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"绿色消费的意义\", \"imageUrl\": null}]', 'C', '文段首先指出绿色消费理念日益深入人心，然后提出推广绿色消费需要完善标准体系、\n加强宣传教育、营造良好氛围。文段的落脚点在于绿色消费的推广措施，C 项最为准确。', '2026-03-12 17:02:28', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (217, '在数字经济时代，数据已成为重要的生产要素。加强数据治理，可以保障数据安全，促\n进数据共享，释放数据价值。完善数据治理体系，需要建立健全数据法律法规，加强数据安\n全保障，提升数据治理能力。', 1, '[{\"key\": \"A\", \"value\": \"数字经济的特点\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"数据的重要性\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"数据治理的措施\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"数据治理的意义\", \"imageUrl\": null}]', 'C', '文段首先指出数据已成为重要的生产要素，然后介绍数据治理的作用，最后提出完善\n数据治理体系需要建立健全法律法规、加强安全保障、提升治理能力。文段的落脚点在于数\n据治理的措施，C 项最为准确。', '2026-03-12 17:02:28', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (218, '随着老龄化社会的到来，养老服务需求日益增长。发展养老服务产业，可以满足老年人多样化需求，促进就业，拉动经济增长。推动养老服务产业发展，需要完善养老服务政策，加强养老服务人才培养，提升养老服务质量。', 1, '[{\"key\": \"A\", \"value\": \"老龄化社会的挑战\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"养老服务需求\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"养老服务产业的发展措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"养老服务产业的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出养老服务需求日益增长，然后介绍养老服务产业的作用，最后提出推动\n养老服务产业发展需要完善政策、加强人才培养、提升服务质量。文段的落脚点在于养老服\n务产业的发展措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:38', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (219, '在全球化背景下，文化交流日益频繁。促进文化交流，可以增进各国人民相互理解，推\n动文明互鉴，促进世界和平发展。推动文化交流，需要搭建文化交流平台，加强文化人才培\n养，完善文化交流机制。', 1, '[{\"key\": \"A\", \"value\": \"全球化的影响\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"文化交流的重要性\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"文化交流的推动措施\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"文化交流的意义\", \"imageUrl\": null}]', 'C', '文段首先指出文化交流日益频繁，然后介绍文化交流的作用，最后提出推动文化交流\n需要搭建平台、加强人才培养、完善机制。文段的落脚点在于文化交流的推动措施，C 项最\n为准确。', '2026-03-12 17:02:28', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (220, '随着科技的发展，智慧城市建设成为城市发展的重要方向。推进智慧城市建设，可以提升城市管理效率，改善居民生活质量，促进城市可持续发展。智慧城市建设需要加强顶层设计，完善基础设施，推进数据共享。', 1, '[{\"key\": \"A\", \"value\": \"科技发展的趋势\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"智慧城市建设\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"智慧城市建设的措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"智慧城市建设的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出智慧城市建设成为城市发展的重要方向，然后介绍智慧城市建设的作用，\n最后提出智慧城市建设需要加强顶层设计、完善基础设施、推进数据共享。文段的落脚点在\n于智慧城市建设的措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:54', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (221, '在生态文明建设背景下，垃圾分类成为城市管理的重要内容。推进垃圾分类，可以减少\n环境污染，提高资源利用效率，改善城市环境质量。垃圾分类的实施，需要完善垃圾分类设\n施，加强宣传教育，建立长效机制。', 1, '[{\"key\": \"A\", \"value\": \"生态文明建设的推进\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"垃圾分类的重要性\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"垃圾分类的实施措施\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"垃圾分类的意义\", \"imageUrl\": null}]', 'C', '文段首先指出垃圾分类成为城市管理的重要内容，然后介绍垃圾分类的作用，最后提\n出垃圾分类的实施需要完善设施、加强宣传教育、建立长效机制。文段的落脚点在于垃圾分\n类的实施措施，C 项最为准确。', '2026-03-12 17:02:28', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (222, '随着互联网的普及，在线教育发展迅速。在线教育的发展，可以突破时空限制，实现优质教育资源共享，促进教育公平。推动在线教育发展，需要完善线教育平台，加强在线教育监管，提升在线教育质量。', 1, '[{\"key\": \"A\", \"value\": \"互联网的普及\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"在线教育的发展\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"在线教育的发展措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"在线教育的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出在线教育发展迅速，然后介绍在线教育的作用，最后提出推动在线教育\n发展需要完善平台、加强监管、提升质量。文段的落脚点在于在线教育的发展措施，C 项最\n为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:05:48', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (223, '在经济转型升级背景下，制造业高质量发展成为重要目标。推动制造业高质量发展，需\n要加强技术创新，优化产业结构，提升产品质量。制造业高质量发展的实现，对于建设制造\n强国具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"经济转型升级\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"制造业高质量发展\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"制造业高质量发展的措施\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"制造业高质量发展的意义\", \"imageUrl\": null}]', 'C', '文段首先指出制造业高质量发展成为重要目标，然后提出推动制造业高质量发展需要\n加强技术创新、优化产业结构、提升产品质量。文段的落脚点在于制造业高质量发展的措施，\nC 项最为准确。', '2026-03-12 17:02:28', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (224, '随着人们健康意识的提升，全民健身运动蓬勃发展。开展全民健身运动，可以增强人民\n体质，提高健康水平，促进社会和谐。推动全民健身运动发展，需要完善体育设施，加强健\n身指导，营造健身氛围。', 1, '[{\"key\": \"A\", \"value\": \"健康意识的提升\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"全民健身运动\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"全民健身运动的发展措施\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"全民健身运动的意义\", \"imageUrl\": null}]', 'C', '文段首先指出全民健身运动蓬勃发展，然后介绍全民健身运动的作用，最后提出推动\n全民健身运动发展需要完善设施、加强指导、营造氛围。文段的落脚点在于全民健身运动的\n发展措施，C 项最为准确。', '2026-03-12 17:02:28', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (225, '在乡村振兴战略实施中，农村人居环境整治成为重要任务。推进农村人居环境整治，可以改善农村生活条件，提升农民生活质量，促进美丽乡村建设。农村人居环境整治的实施，需要加强基础设施建设，完善垃圾处理体系，推进厕所革命。', 1, '[{\"key\": \"A\", \"value\": \"乡村振兴战略\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"农村人居环境整治\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"农村人居环境整治的措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"农村人居环境整治的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出农村人居环境整治成为重要任务，然后介绍农村人居环境整治的作用，\n最后提出农村人居环境整治的实施需要加强基础设施建设、完善垃圾处理体系、推进厕所革\n命。文段的落脚点在于农村人居环境整治的措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:06:01', NULL, NULL, 1, '言语理解', '');
INSERT INTO `question` VALUES (226, '随着气候变化问题日益严峻，碳减排成为全球共识。推进碳减排，需要调整能源结构，发展清洁能源，提高能源利用效率。碳减排的实现，对于应对气候变化、促进可持续发展具有重要意义。', 1, '[{\"key\": \"A\", \"value\": \"气候变化问题\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"碳减排的重要性\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"碳减排的措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"碳减排的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出碳减排成为全球共识，然后提出推进碳减排需要调整能源结构、发展清\n洁能源、提高能源利用效率。文段的落脚点在于碳减排的措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:06:08', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (227, '在信息化时代，政务信息化成为政府治理现代化的重要手段。推进政务信息化，可以提高政务服务效率，优化营商环境，增强政府公信力。政务信息化的推进，需要加强顶层设计，完善信息平台，保障信息安全。', 1, '[{\"key\": \"A\", \"value\": \"信息化时代的特点\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"政务信息化\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"政务信息化的推进措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"政务信息化的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出政务信息化成为政府治理现代化的重要手段，然后介绍政务信息化的作\n用，最后提出政务信息化的推进需要加强顶层设计、完善信息平台、保障信息安全。文段的\n落脚点在于政务信息化的推进措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:02:56', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (228, '随着消费观念的变化，体验式消费日益受到青睐。发展体验式消费，可以满足消费者个性化需求，提升消费体验，促进消费升级。推动体验式消费发展，需要创新消费场景，丰富消费内容，提升服务质量。', 1, '[{\"key\": \"A\", \"value\": \"消费观念的变化\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"体验式消费\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"体验式消费的发展措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"体验式消费的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出体验式消费日益受到青睐，然后介绍体验式消费的作用，最后提出推动\n体验式消费发展需要创新消费场景、丰富消费内容、提升服务质量。文段的落脚点在于体验\n式消费的发展措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:03', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (229, '在全球化背景下，国际人才竞争日益激烈。加强国际人才培养，可以提升国家竞争力，促进科技创新，推动经济社会发展。国际人才培养的加强，需要完善人才培养体系，优化人才发展环境，加强国际交流合作。', 1, '[{\"key\": \"A\", \"value\": \"全球化的影响\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"国际人才竞争\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"国际人才培养的措施\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"国际人才培养的意义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出国际人才竞争日益激烈，然后介绍国际人才培养的作用，最后提出国际\n人才培养的加强需要完善培养体系、优化发展环境、加强交流合作。文段的落脚点在于国际\n人才培养的措施，C 项最为准确。', '2026-03-12 17:02:28', 16, '2026-03-12 17:03:57', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (230, '在全球化浪潮中，各国文化的交流与碰撞日益频繁，如何在保持自身文化______的同时，\n积极吸收外来文化的精华，成为了一个值得深思的问题。', 1, '[{\"key\": \"A\", \"value\": \"独特性\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"独立性\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"完整性\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"纯粹性\", \"imageUrl\": \"\"}]', 'A', '本题考查实词辨析。\"独特性\"强调与众不同，符合文化交流中保持自身特色的要求；\n\"独立性\"侧重于不受控制；\"完整性\"强调没有缺失；\"纯粹性\"强调不掺杂其他成分。在文化\n交流的语境下，\"独特性\"最能体现保持自身文化特色的意思。', '2026-03-12 17:12:48', 16, '2026-03-12 17:12:58', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (231, '面对复杂的国际形势，我国始终坚持______的和平发展道路，既不称霸，也不依附于任何\n大国，赢得了国际社会的广泛尊重。', 1, '[{\"key\": \"A\", \"value\": \"坚定不移\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"一以贯之\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"始终如一\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"持之以恒\", \"imageUrl\": \"\"}]', 'A', '本题考查成语辨析。\"坚定不移\"形容意志坚强，不动摇，常与\"道路\"搭配；\"一以贯之\n\"强调自始至终坚持；\"始终如一\"强调态度不变；\"持之以恒\"强调坚持不懈。\"坚定不移的和\n平发展道路\"是固定搭配，符合语境。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:00', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (232, '随着科技的进步，人工智能技术在各个领域______，极大地提高了生产效率，但也引发了\n一些伦理道德方面的争议。', 1, '[{\"key\": \"A\", \"value\": \"崭露头角\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"大显身手\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"遍地开花\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"异军突起\", \"imageUrl\": \"\"}]', 'C', '本题考查成语辨析。\"崭露头角\"指初显才能；\"大显身手\"指充分施展本领；\"遍地开花\n\"比喻事物到处发展；\"异军突起\"指新生力量突然出现。语境强调人工智能在\"各个领域\"都得\n到应用，\"遍地开花\"最能体现广泛发展的意思。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:42', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (233, '这部文学作品以其深刻的思想内涵和精湛的艺术技巧，______了读者，成为了当代文坛的\n佳作。', 1, '[{\"key\": \"A\", \"value\": \"震撼\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"感动\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"征服\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"感染\", \"imageUrl\": null}]', 'C', '本题考查实词辨析。\"震撼\"强调心理受到强烈冲击；\"感动\"侧重情感触动；\"征服\"指\n使对方信服或折服；\"感染\"指通过情绪或思想影响他人。语境强调作品的思想和技巧使读者\n折服，\"征服\"最能体现这种效果。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (234, '在经济发展过程中，我们不能只追求 GDP 的增长，更要______环境保护，实现经济与环境\n的协调发展。', 1, '[{\"key\": \"A\", \"value\": \"重视\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"关注\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"注重\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"兼顾\", \"imageUrl\": \"\"}]', 'D', '本题考查实词辨析。\"重视\"强调认为重要；\"关注\"强调关心注意；\"注重\"强调重视；\"\n兼顾\"指同时照顾多个方面。语境强调在追求经济增长的同时也要照顾环境保护，\"兼顾\"最\n能体现平衡发展的意思。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:03', NULL, NULL, 5, '言语理解', '');
INSERT INTO `question` VALUES (235, '面对突如其来的疫情，全国人民团结一心，______，最终战胜了这场严峻的考验。', 1, '[{\"key\": \"A\", \"value\": \"共克时艰\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"同舟共济\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"众志成城\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"齐心协力\", \"imageUrl\": null}]', 'A', '本题考查成语辨析。\"共克时艰\"指共同克服困难；\"同舟共济\"比喻团结互助；\"众志成\n城\"比喻大家团结一致就能战胜困难；\"齐心协力\"指思想一致，共同努力。语境强调\"面对突\n如其来的疫情\"和\"战胜考验\"，\"共克时艰\"最能体现克服困难的意思。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (236, '这位科学家的研究成果______，为我国在该领域的发展奠定了坚实的基础。', 1, '[{\"key\": \"A\", \"value\": \"举世瞩目\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"独树一帜\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"首屈一指\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"出类拔萃\", \"imageUrl\": null}]', 'A', '本题考查成语辨析。\"举世瞩目\"指全世界都关注；\"独树一帜\"指自成一家；\"首屈一指\n\"指居第一位；\"出类拔萃\"指超出同类。语境强调研究成果的重要性和影响力，\"举世瞩目\"\n最能体现其重大意义。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (237, '在信息化时代，网络谣言传播速度极快，容易造成不良影响，因此我们必须______网络谣\n言的传播。', 1, '[{\"key\": \"A\", \"value\": \"遏制\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"制止\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"阻止\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"防止\", \"imageUrl\": \"\"}]', 'A', '本题考查实词辨析。\"遏制\"指用力制止；\"制止\"指强迫使停止；\"阻止\"指使不能前进\n或发展；\"防止\"指预先设法制止。\"遏制\"带有强力制止的意思，符合对网络谣言传播的严厉\n态度。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:06', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (238, '这个政策出台后，得到了广大人民群众的______，社会反响热烈。', 1, '[{\"key\": \"A\", \"value\": \"拥护\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"支持\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"赞同\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"认可\", \"imageUrl\": \"\"}]', 'A', '本题考查实词辨析。\"拥护\"指赞成并全力支持；\"支持\"指支援、赞同；\"赞同\"指同意、\n赞成；\"认可\"指许可、承认。\"拥护\"程度最强，符合\"社会反响热烈\"的语境。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:08', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (239, '随着城市化进程的加快，城市规模不断扩大，但也带来了一系列______问题，如交通拥\n堵、环境污染等。', 1, '[{\"key\": \"A\", \"value\": \"衍生\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"产生\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"引发\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"导致\", \"imageUrl\": null}]', 'A', '本题考查实词辨析。\"衍生\"指演变产生；\"产生\"指出现；\"引发\"指引起、触发；\"导致\n\"指引起某种结果。\"衍生\"强调从原有事物中演变产生，符合城市化进程中问题逐渐出现的\n特点。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (240, '这位艺术家以其独特的创作风格和深厚的艺术功底，在艺术界______，成为了一代大师。', 1, '[{\"key\": \"A\", \"value\": \"独领风骚\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"独占鳌头\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"独树一帜\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"独步天下\", \"imageUrl\": \"\"}]', 'A', '本题考查成语辨析。\"独领风骚\"指在某个领域居领先地位；\"独占鳌头\"指占第一位；\n\"独树一帜\"指自成一家；\"独步天下\"指独一无二。语境强调艺术家在艺术界的领先地位，\"\n独领风骚\"最贴切。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:17', NULL, NULL, 1, '言语理解', '');
INSERT INTO `question` VALUES (241, '面对日益严峻的环境问题，我们必须______，采取有效措施保护生态环境。', 1, '[{\"key\": \"A\", \"value\": \"未雨绸缪\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"防患未然\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"亡羊补牢\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"刻不容缓\", \"imageUrl\": null}]', 'D', '本题考查成语辨析。\"未雨绸缪\"指事先做好准备；\"防患未然\"指在事故发生前预防；\n\"亡羊补牢\"指事后补救；\"刻不容缓\"指形势紧迫，一刻也不能拖延。语境强调问题\"日益严峻\n\"，需要立即行动，\"刻不容缓\"最贴切。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (242, '这个项目经过多年的努力，终于______，取得了巨大的成功。', 1, '[{\"key\": \"A\", \"value\": \"大功告成\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"功德圆满\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"水到渠成\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"瓜熟蒂落\", \"imageUrl\": null}]', 'A', '本题考查成语辨析。\"大功告成\"指巨大工程或重要任务宣告完成；\"功德圆满\"指事情\n圆满完成；\"水到渠成\"比喻条件成熟，事情自然成功；\"瓜熟蒂落\"比喻时机成熟，事情自然\n成功。语境强调项目经过多年努力完成，\"大功告成\"最能体现成功的喜悦。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (243, '在科技创新方面，我国取得了举世瞩目的成就，但与发达国家相比，在某些核心技术领\n域仍存在______。', 1, '[{\"key\": \"A\", \"value\": \"差距\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"差距\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"差距\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"差距\", \"imageUrl\": \"\"}]', 'A', '本题考查实词辨析。四个选项都是\"差距\"，但根据语境，\"差距\"是固定搭配，指在水\n平、程度等方面的差别。在科技领域与发达国家比较时，使用\"差距\"最准确。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:19', NULL, NULL, 5, '言语理解', '');
INSERT INTO `question` VALUES (244, '这个城市的交通规划______，充分考虑了未来发展的需要，为城市的发展奠定了良好的\n基础。', 1, '[{\"key\": \"A\", \"value\": \"高瞻远瞩\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"深谋远虑\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"未雨绸缪\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"远见卓识\", \"imageUrl\": \"\"}]', 'A', '本题考查成语辨析。\"高瞻远瞩\"指眼光远大；\"深谋远虑\"指计划周密；\"未雨绸缪\"指\n事先准备；\"远见卓识\"指有远大的眼光和卓越的见识。语境强调交通规划考虑了\"未来发展\n的需要\"，\"高瞻远瞩\"最能体现长远眼光。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:22', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (245, '面对复杂的国际局势，我国始终坚持______的外交政策，维护国家利益，促进世界和平。', 1, '[{\"key\": \"A\", \"value\": \"独立自主\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"不卑不亢\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"和平共处\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"互利共赢\", \"imageUrl\": null}]', 'A', '本题考查成语辨析。\"独立自主\"指不依附他人，自主行事；\"不卑不亢\"指态度得体；\n\"和平共处\"指和平相处；\"互利共赢\"指双方受益。\"独立自主的外交政策\"是固定搭配，符合\n我国外交方针。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (246, '这位教授的学术造诣深厚，在学术界______，深受学生和同行的尊敬。', 1, '[{\"key\": \"A\", \"value\": \"德高望重\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"声名远扬\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"名满天下\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"举世闻名\", \"imageUrl\": \"\"}]', 'A', '本题考查成语辨析。\"德高望重\"指品德高尚，名望很大；\"声名远扬\"指名声传播得很\n远；\"名满天下\"指名声极大；\"举世闻名\"指全世界都知道。语境强调教授的品德和学术地位，\n\"德高望重\"最贴切。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:25', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (247, '随着互联网技术的发展，电子商务______，改变了人们的购物方式。', 1, '[{\"key\": \"A\", \"value\": \"异军突起\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"方兴未艾\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"如火如荼\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"蒸蒸日上\", \"imageUrl\": null}]', 'A', '本题考查成语辨析。\"异军突起\"指新生力量突然兴起；\"方兴未艾\"指事物正在发展；\n\"如火如荼\"形容旺盛；\"蒸蒸日上\"指事业一天天向上发展。语境强调电子商务作为新兴事物\n的崛起，\"异军突起\"最贴切。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (248, '这个企业经过多年的发展，已经______，成为了行业的领军企业。', 1, '[{\"key\": \"A\", \"value\": \"如日中天\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"蒸蒸日上\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"欣欣向荣\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"蓬勃发展\", \"imageUrl\": \"\"}]', 'A', '本题考查成语辨析。\"如日中天\"比喻事物发展到最兴盛的阶段；\"蒸蒸日上\"指事业一\n天天向上发展；\"欣欣向荣\"形容草木茂盛，比喻事业蓬勃发展；\"蓬勃发展\"指发展势头旺盛。\n语境强调企业已经达到行业领先地位，\"如日中天\"最能体现鼎盛状态。', '2026-03-12 17:12:48', 16, '2026-03-12 17:13:28', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (249, '在文化交流中，我们应该______，既要保持自身文化的特色，又要积极吸收外来文化的\n精华。', 1, '[{\"key\": \"A\", \"value\": \"取长补短\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"兼收并蓄\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"博采众长\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"融会贯通\", \"imageUrl\": null}]', 'B', '本题考查成语辨析。\"取长补短\"指吸取别人的长处弥补自己的短处；\"兼收并蓄\"指把\n不同内容、不同性质的东西都吸收进来；\"博采众长\"指广泛采纳各家的长处；\"融会贯通\"指\n把各方面的知识和道理融合贯穿起来。语境强调既要保持特色又要吸收精华，\"兼收并蓄\"\n最能体现包容性。', '2026-03-12 17:12:48', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (250, '2, 5, 10, 17, 26, ( )', 1, '[{\"key\": \"A\", \"value\": \"35\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"36\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"37\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"38\", \"imageUrl\": \"\"}]', 'C', '该数列的规律是：2=1²+1，5=2²+1，10=3²+1，17=4²+1，26=5²+1，因此下一项为 6\n²+1=37。', '2026-03-12 17:26:40', 16, '2026-03-12 17:26:47', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (251, '3, 6, 12, 24, 48, ( )', 1, '[{\"key\": \"A\", \"value\": \"96\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"98\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"100\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"102\", \"imageUrl\": null}]', 'A', '该数列是等比数列，每一项都是前一项的 2 倍，因此下一项为 48×2=96。', '2026-03-12 17:26:40', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (252, '1, 4, 9, 16, 25, ( )', 1, '[{\"key\": \"A\", \"value\": \"30\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"32\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"34\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"36\", \"imageUrl\": \"\"}]', 'D', '该数列是平方数列，1=1²，4=2²，9=3²，16=4²，25=5²，因此下一项为 6²=36。', '2026-03-12 17:26:40', 16, '2026-03-12 17:26:56', NULL, NULL, 1, '数量关系', '');
INSERT INTO `question` VALUES (253, '2, 3, 5, 8, 13, ( )', 1, '[{\"key\": \"A\", \"value\": \"18\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"19\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"20\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"21\", \"imageUrl\": null}]', 'D', '该数列是斐波那契数列，从第三项开始，每一项都是前两项之和，因此下一项为\n8+13=21。', '2026-03-12 17:26:40', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (254, '1, 8, 27, 64, 125, ( )', 1, '[{\"key\": \"A\", \"value\": \"180\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"196\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"216\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"225\", \"imageUrl\": \"\"}]', 'C', '该数列是立方数列，1=1³，8=2³，27=3³，64=4³，125=5³，因此下一项为 6³=216。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:00', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (255, '2, 5, 11, 23, 47, ( )', 1, '[{\"key\": \"A\", \"value\": \"95\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"96\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"97\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"98\", \"imageUrl\": \"\"}]', 'A', '该数列的规律是：每一项都是前一项的 2 倍加 1，因此下一项为 47×2+1=95。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:05', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (256, '1, 2, 6, 24, 120, ( )', 1, '[{\"key\": \"A\", \"value\": \"480\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"600\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"720\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"840\", \"imageUrl\": null}]', 'C', '该数列是阶乘数列，1=1!，2=2!，6=3!，24=4!，120=5!，因此下一项为 6!=720。', '2026-03-12 17:26:40', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (257, '3, 7, 15, 31, 63, ( )', 1, '[{\"key\": \"A\", \"value\": \"125\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"126\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"127\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"128\", \"imageUrl\": null}]', 'C', '该数列的规律是：每一项都是 2 的 n 次方减 1，3=2²-1，7=2³-1，15=2⁴ -1，31=2⁵-1，\n63=2⁶-1，因此下一项为 2⁷-1=127。', '2026-03-12 17:26:40', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (258, '1, 3, 6, 10, 15, ( )', 1, '[{\"key\": \"A\", \"value\": \"20\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"21\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"22\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"23\", \"imageUrl\": \"\"}]', 'B', '该数列是三角形数列，相邻两项之差依次为 2,3,4,5，因此下一项为 15+6=21。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:11', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (259, '2, 9, 28, 65, 126, ( )', 1, '[{\"key\": \"A\", \"value\": \"200\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"210\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"215\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"217\", \"imageUrl\": \"\"}]', 'D', '该数列的规律是：2=1³+1，9=2³+1，28=3³+1，65=4³+1，126=5³+1，因此下一项为 6\n³+1=217。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:15', NULL, NULL, 5, '数量关系', '');
INSERT INTO `question` VALUES (260, '1, 2, 5, 14, 41, ( )', 1, '[{\"key\": \"A\", \"value\": \"120\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"122\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"124\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"126\", \"imageUrl\": \"\"}]', 'B', '该数列的规律是：每一项都是前一项的 3 倍减 1，因此下一项为 41×3-1=122。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:22', NULL, NULL, 5, '数量关系', '');
INSERT INTO `question` VALUES (261, '4, 7, 12, 19, 28, ( )', 1, '[{\"key\": \"A\", \"value\": \"36\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"38\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"39\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"40\", \"imageUrl\": \"\"}]', 'C', '该数列相邻两项之差依次为 3,5,7,9，是连续的奇数，因此下一项为 28+11=39。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:32', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (262, '1, 4, 13, 40, 121, ( )', 1, '[{\"key\": \"A\", \"value\": \"364\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"365\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"366\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"367\", \"imageUrl\": \"\"}]', 'A', '该数列的规律是：每一项都是前一项的 3 倍加 1，因此下一项为 121×3+1=364。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:37', NULL, NULL, 5, '数量关系', '');
INSERT INTO `question` VALUES (263, '2, 6, 18, 54, 162, ( )', 1, '[{\"key\": \"A\", \"value\": \"324\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"432\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"486\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"512\", \"imageUrl\": null}]', 'C', '该数列是等比数列，每一项都是前一项的 3 倍，因此下一项为 162×3=486。', '2026-03-12 17:26:40', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (264, '1, 5, 13, 25, 41, ( )', 1, '[{\"key\": \"A\", \"value\": \"59\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"60\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"61\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"62\", \"imageUrl\": \"\"}]', 'C', '该数列相邻两项之差依次为 4,8,12,16，是 4 的倍数，因此下一项为 41+20=61。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:55', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (265, '3, 10, 29, 66, 127, ( )', 1, '[{\"key\": \"A\", \"value\": \"200\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"210\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"218\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"220\", \"imageUrl\": \"\"}]', 'C', '该数列的规律是：3=1³+2，10=2³+2，29=3³+2，66=4³+2，127=5³+2，因此下一项为\n6³+2=218。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:43', NULL, NULL, 5, '数量关系', '');
INSERT INTO `question` VALUES (266, '1, 2, 4, 7, 11, 16, ( )', 1, '[{\"key\": \"A\", \"value\": \"20\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"21\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"22\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"23\", \"imageUrl\": null}]', 'C', '该数列相邻两项之差依次为 1,2,3,4,5，因此下一项为 16+6=22。', '2026-03-12 17:26:40', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (267, '5, 17, 37, 65, 101, ( )', 1, '[{\"key\": \"A\", \"value\": \"137\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"140\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"145\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"150\", \"imageUrl\": null}]', 'C', '该数列相邻两项之差依次为 12,20,28,36，是 8 的倍数，因此下一项为 101+44=145。', '2026-03-12 17:26:40', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (268, '2, 12, 30, 56, 90, ( )', 1, '[{\"key\": \"A\", \"value\": \"120\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"122\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"132\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"140\", \"imageUrl\": \"\"}]', 'C', '该数列的规律是：2=1×2，12=3×4，30=5×6，56=7×8，90=9×10，因此下一项为\n11×12=132。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:47', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (269, '1, 3, 8, 20, 48, ( )', 1, '[{\"key\": \"A\", \"value\": \"96\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"100\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"112\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"120\", \"imageUrl\": \"\"}]', 'C', '该数列的规律是：每一项都是前一项的 2 倍加 2，因此下一项为 48×2+16=112。', '2026-03-12 17:26:40', 16, '2026-03-12 17:27:50', NULL, NULL, 3, '数量关系', '');
INSERT INTO `question` VALUES (270, '某班级有学生 45 人，其中男生比女生多 5 人，则该班级女生有多少人？', 1, '[{\"key\": \"A\", \"value\": \"20\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"25\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"30\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"35\", \"imageUrl\": null}]', 'A', '设女生有 x 人，则男生有(x+5)人，根据题意：x+(x+5)=45，解得 2x=40，x=20，所以\n女生有 20 人。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (271, '某商品原价为 120 元，先提价 20%，再降价 20%，则现价为多少元？', 1, '[{\"key\": \"A\", \"value\": \"115.2\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"120\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"124.8\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"96\", \"imageUrl\": null}]', 'A', '提价 20%后价格为 120×(1+20%)=144 元，再降价 20%后价格为 144×(1-20%)=115.2\n元。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (272, '甲、乙两人同时从 A 地出发前往 B 地，甲每小时走 5 公里，乙每小时走 4 公里，甲比乙早\n到 1 小时，则 A、B 两地相距多少公里？', 1, '[{\"key\": \"A\", \"value\": \"15\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"20\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"25\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"30\", \"imageUrl\": \"\"}]', 'B', '设 A、B 两地相距 x 公里，则甲用时 x/5 小时，乙用时 x/4 小时，根据题意：x/4-x/5=1，\n解得 x=20 公里。', '2026-03-12 17:31:49', 16, '2026-03-12 17:31:53', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (274, '一个长方体的长、宽、高分别为 4cm、3cm、2cm，则其表面积为多少平方厘米？', 1, '[{\"key\": \"A\", \"value\": \"24\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"36\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"48\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"52\", \"imageUrl\": \"\"}]', 'D', '长方体表面积=2×(长×宽+长×高+宽×高)=2×(4×3+4×2+3×2)=2×(12+8+6)=52 平\n方厘米。', '2026-03-12 17:31:49', 16, '2026-03-12 17:32:06', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (275, '某公司有员工 80 人，其中技术人员占 40%，管理人员占 25%，则其他人员有多少人？', 1, '[{\"key\": \"A\", \"value\": \"24\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"28\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"32\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"36\", \"imageUrl\": null}]', 'B', '技术人员=80×40%=32 人，管理人员=80×25%=20 人，其他人员=80-32-20=28 人。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (276, '甲、乙、丙三人分一批苹果，甲分得总数的 1/3，乙分得总数的 1/4，丙分得剩下的 25 个，\n则这批苹果共有多少个？', 1, '[{\"key\": \"A\", \"value\": \"48\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"60\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"72\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"84\", \"imageUrl\": \"\"}]', 'B', '设总数为 x 个，丙分得 x-(1/3)x-(1/4)x=(5/12)x，根据题意：(5/12)x=25，解得 x=60 个。', '2026-03-12 17:31:49', 16, '2026-03-12 17:31:58', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (277, '某数除以 3 余 2，除以 5 余 3，除以 7 余 4，则这个数最小是多少？', 1, '[{\"key\": \"A\", \"value\": \"23\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"53\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"83\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"113\", \"imageUrl\": \"\"}]', 'B', '这个数加 1 后能被 3、5、7 整除，3、5、7 的最小公倍数为 105，所以这个数最小为\n105-1=104，但 104 除以 7 余 5，不符合。继续寻找，下一个满足条件的是 53，53÷3=17 余\n2，53÷5=10 余 3，53÷7=7 余 4，符合条件。', '2026-03-12 17:31:49', 16, '2026-03-12 17:31:55', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (278, '一辆汽车从甲地开往乙地，去程速度为 60km/h，回程速度为 40km/h，则往返的平均速度\n是多少 km/h？', 1, '[{\"key\": \"A\", \"value\": \"48\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"50\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"52\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"54\", \"imageUrl\": null}]', 'A', '设单程距离为 x 公里，则去程用时 x/60 小时，回程用时 x/40 小时，总用时\n=x/60+x/40=x/24 小时，总路程=2x 公里，平均速度=2x÷(x/24)=48km/h。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (279, '某水池有进水管和出水管，单开进水管 6 小时可将水池注满，单开出水管 8 小时可将水\n池排空，若两管同时开，几小时可将水池注满？', 1, '[{\"key\": \"A\", \"value\": \"12\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"24\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"36\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"48\", \"imageUrl\": \"\"}]', 'B', '进水管每小时注水 1/6，出水管每小时排水 1/8，同时开每小时注水 1/6-1/8=1/24，\n所以需要 24 小时注满。', '2026-03-12 17:31:49', 16, '2026-03-12 17:32:09', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (280, '甲、乙两人合作完成一项工作，甲单独做需要 10 天，乙单独做需要 15 天，则两人合作\n需要多少天完成？', 1, '[{\"key\": \"A\", \"value\": \"4\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"5\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"6\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"7\", \"imageUrl\": \"\"}]', 'C', '甲的工作效率为 1/10，乙的工作效率为 1/15，两人合作效率为 1/10+1/15=1/6，所以\n需要 6 天完成。', '2026-03-12 17:31:49', 16, '2026-03-12 17:32:15', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (281, '某商店进价 100 元的商品，按标价 150 元出售，实际按标价打 8 折销售，则利润率是多\n少？', 1, '[{\"key\": \"A\", \"value\": \"20%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"25%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"30%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"35%\", \"imageUrl\": \"\"}]', 'A', '实际售价=150×0.8=120 元，利润=120-100=20 元，利润率=20÷100×100%=20%。', '2026-03-12 17:31:49', 16, '2026-03-12 17:32:12', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (282, '一个圆形花坛的直径为 10 米，则其面积是多少平方米？（π取 3.14）', 1, '[{\"key\": \"A\", \"value\": \"31.4\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"78.5\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"157\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"314\", \"imageUrl\": null}]', 'B', '半径=10÷2=5 米，面积=π×r²=3.14×25=78.5 平方米。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (283, '甲、乙两车同时从 A、B 两地相向而行，甲车速度为 50km/h，乙车速度为 70km/h，2 小\n时后相遇，则 A、B 两地相距多少公里？', 1, '[{\"key\": \"A\", \"value\": \"200\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"240\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"280\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"320\", \"imageUrl\": null}]', 'B', '两车相对速度=50+70=120km/h，2 小时相遇，所以 A、B 两地相距 120×2=240 公里。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (284, '某数列：2，5，11，23，47，...，则第 5 项是多少？', 1, '[{\"key\": \"A\", \"value\": \"47\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"95\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"96\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"97\", \"imageUrl\": null}]', 'B', '观察数列规律，后一项=前一项×2+1，所以第 5 项=47×2+1=95。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (285, '某班级有学生 40 人，其中喜欢语文的有 25 人，喜欢数学的有 30 人，两门都不喜欢的有\n3 人，则两门都喜欢的有多少人？', 1, '[{\"key\": \"A\", \"value\": \"15\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"18\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"20\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"22\", \"imageUrl\": \"\"}]', 'B', '至少喜欢一门的有 40-3=37 人，设两门都喜欢的有 x 人，则 25+30-x=37，解得 x=18\n人。', '2026-03-12 17:31:49', 16, '2026-03-12 17:32:20', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (286, '一个正方体的棱长为 3cm，则其体积是多少立方厘米？', 1, '[{\"key\": \"A\", \"value\": \"9\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"18\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"27\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"54\", \"imageUrl\": \"\"}]', 'C', '正方体体积=棱长³=3³=27 立方厘米。', '2026-03-12 17:31:49', 16, '2026-03-12 17:32:31', NULL, NULL, 1, '数量关系', '');
INSERT INTO `question` VALUES (287, '甲、乙两人年龄之和为 60 岁，5 年前甲的年龄是乙的 2 倍，则甲现在多少岁？', 1, '[{\"key\": \"A\", \"value\": \"30\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"35\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"40\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"45\", \"imageUrl\": null}]', 'B', '设乙现在 x 岁，则甲现在(60-x)岁，5 年前乙(x-5)岁，甲(60-x-5)=(55-x)岁，根据题意：\n55-x=2(x-5)，解得 x=25，甲现在 60-25=35 岁。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (288, '某商品先降价 20%，再提价 20%，则现价是原价的百分之几？', 1, '[{\"key\": \"A\", \"value\": \"96%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"100%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"104%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"120%\", \"imageUrl\": \"\"}]', 'A', '设原价为 100，降价 20%后为 80，再提价 20%后为 80×1.2=96，所以现价是原价的\n96%。', '2026-03-12 17:31:49', 16, '2026-03-12 17:32:24', NULL, NULL, 1, '数量关系', '');
INSERT INTO `question` VALUES (289, '某水池有甲、乙两个进水管，单开甲管 4 小时可注满，单开乙管 6 小时可注满，若两管\n同时开，几小时可注满？', 1, '[{\"key\": \"A\", \"value\": \"2\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"2.4\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"2.5\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"3\", \"imageUrl\": null}]', 'B', '甲管每小时注水 1/4，乙管每小时注水 1/6，两管同时开每小时注水 1/4+1/6=5/12，\n所以需要 1÷(5/12)=12/5=2.4 小时注满。', '2026-03-12 17:31:49', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (290, '某工程队计划完成一项工程，如果由甲队单独完成需要 20 天，乙队单独完成需要 30 天。\n现在甲队先单独工作 5 天，然后乙队加入一起工作，问完成这项工程总共需要多少天？', 1, '[{\"key\": \"A\", \"value\": \"12 天\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"13 天\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"14 天\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"15 天\", \"imageUrl\": \"\"}]', 'C', '甲队每天完成工程的 1/20，乙队每天完成工程的 1/30。甲队单独工作 5天完成 5/20=1/4。\n剩余 3/4 由两队合作完成，合作每天完成 1/20+1/30=1/12，需要(3/4)÷(1/12)=9 天。总共\n5+9=14 天。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:07', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (291, '某工厂生产一批零件，原计划每天生产 120 个，实际每天比计划多生产 30 个，结果提前 5\n天完成任务。问这批零件共有多少个？', 1, '[{\"key\": \"A\", \"value\": \"2400 个\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"2700 个\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"3000 个\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"3300 个\", \"imageUrl\": \"\"}]', 'C', '设原计划需要 x天完成任务，则实际用了 x-5天。120x=150(x-5)，120x=150x-750，30x=750，\nx=25 天。零件总数=120×25=3000 个。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:11', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (292, '某商店进购一批商品，进价为每件 80 元，按标价的 8 折出售，仍可获得 20%的利润。问\n该商品的标价是多少元？', 1, '[{\"key\": \"A\", \"value\": \"100 元\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"110 元\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"120 元\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"130 元\", \"imageUrl\": \"\"}]', 'C', '设标价为 x 元，则售价为 0.8x 元。利润率为 20%，所以售价=进价×(1+20%)=80×1.2=96\n元。因此 0.8x=96，x=120 元。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:04', NULL, NULL, 3, '数量关系', '');
INSERT INTO `question` VALUES (293, '甲、乙、丙三人合作完成一项工作，甲单独完成需要 10 天，乙单独完成需要 15 天，丙单\n独完成需要 20 天。如果三人合作，中途甲因事离开，实际用了 6 天完成工作。问甲工作了\n几天？', 1, '[{\"key\": \"A\", \"value\": \"3 天\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"4 天\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"5 天\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"6 天\", \"imageUrl\": null}]', 'A', '设甲工作了 x 天，则乙和丙都工作了 6 天。甲每天完成 1/10，乙每天完成 1/15，丙\n每天完成 1/20。根据题意：x/10+6/15+6/20=1，即 x/10+2/5+3/10=1，x/10+7/10=1，x/10=3/10，\nx=3 天。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (294, '某工厂生产一批零件，原计划每天生产 150 个，实际每天比计划多生产 50 个，结果提前 4\n天完成任务。问这批零件共有多少个？', 1, '[{\"key\": \"A\", \"value\": \"1800 个\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"2000 个\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"2200 个\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"2400 个\", \"imageUrl\": null}]', 'D', '设原计划需要 x天完成任务，则实际用了 x-4天。150x=200(x-4)，150x=200x-800，50x=800，\nx=16 天。零件总数=150×16=2400 个。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (295, '一个水池有进水管 A 和出水管 B，单独开 A 管 10 小时可注满水池，单独开 B 管 15 小时可\n排空水池。如果同时打开 A 管和 B 管，多少小时可以注满水池？', 1, '[{\"key\": \"A\", \"value\": \"20 小时\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"25 小时\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"30 小时\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"35 小时\", \"imageUrl\": \"\"}]', 'C', 'A 管每小时注满水池的 1/10，B 管每小时排空水池的 1/15。同时开 A 管和 B 管，每\n小时净注满水池的 1/10-1/15=1/30。注满水池需要 1÷(1/30)=30 小时。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:01', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (296, '甲、乙两人在环形跑道上跑步，跑道长 400 米。甲的速度为 6m/s，乙的速度为 4m/s。两\n人同时从同一点出发，同向而行。问多少秒后甲第一次追上乙？', 1, '[{\"key\": \"A\", \"value\": \"100 秒\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"150 秒\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"200 秒\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"250 秒\", \"imageUrl\": \"\"}]', 'C', '甲比乙快 2m/s，要追上乙需要多跑一圈 400 米。追上时间=400÷(6-4)=400÷2=200\n秒。', '2026-03-12 17:49:53', 16, '2026-03-12 17:49:57', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (297, '某公司有员工 100 人，其中男性占 60%。在男性员工中，本科及以上学历占 70%；在女性\n员工中，本科及以上学历占 50%。问该公司本科及以上学历的员工有多少人？', 1, '[{\"key\": \"A\", \"value\": \"50 人\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"55 人\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"60 人\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"62 人\", \"imageUrl\": null}]', 'D', '男性员工=100×60%=60 人，本科及以上学历的男性=60×70%=42 人。女性员工\n=100-60=40 人，本科及以上学历的女性=40×50%=20 人。本科及以上学历总人数=42+20=62\n人。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (298, '一个正方体的棱长增加 20%，则其表面积增加多少？', 1, '[{\"key\": \"A\", \"value\": \"20%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"36%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"44%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"56%\", \"imageUrl\": \"\"}]', 'C', '设原棱长为 a，原表面积=6a²。新棱长=1.2a，新表面积=6×(1.2a)²=6×1.44a²=8.64a\n²。表面积增加=(8.64a²-6a²)÷6a²×100%=2.64a²÷6a²×100%=44%。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:55', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (299, '某项工程，甲队单独完成需要 15 天，乙队单独完成需要 20 天。两队合作若干天后，甲\n队因事离开，乙队继续工作，共用了 12 天完成工程。问甲队工作了几天？', 1, '[{\"key\": \"A\", \"value\": \"6 天\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"7 天\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"8 天\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"9 天\", \"imageUrl\": null}]', 'B', '设甲队工作了 x 天，则乙队工作了 12 天。甲队每天完成 1/15，乙队每天完成 1/20。\n根据题意：x/15+12/20=1，即 x/15+3/5=1，x/15=2/5，x=6 天。但选项 A 是 6 天，重新检查：\n12/20=3/5=9/15，所以 x/15+9/15=1，x/15=6/15，x=6 天。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (300, '某商品原价为 200 元，先提价 20%，再降价 20%，问现价是多少元？', 1, '[{\"key\": \"A\", \"value\": \"192 元\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"196 元\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"200 元\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"204 元\", \"imageUrl\": \"\"}]', 'A', '提价 20%后价格=200×1.2=240 元。降价 20%后价格=240×0.8=192 元。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:45', NULL, NULL, 1, '数量关系', '');
INSERT INTO `question` VALUES (301, '甲、乙、丙三人分一批苹果，甲得总数的 1/3，乙得总数的 1/4，丙得总数的 1/5。三人\n分完后还剩 20 个苹果。问这批苹果共有多少个？', 1, '[{\"key\": \"A\", \"value\": \"100 个\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"120 个\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"150 个\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"180 个\", \"imageUrl\": \"\"}]', 'B', '设总数为 x 个，则 x/3+x/4+x/5+20=x。通分：20x/60+15x/60+12x/60+20=x，47x/60+20=x，\n20=13x/60，x=120 个。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:15', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (302, '一个圆柱的底面半径增加 50%，高减少 50%，则其体积如何变化？', 1, '[{\"key\": \"A\", \"value\": \"不变\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"增加 12.5%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"减少 12.5%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"减少 25%\", \"imageUrl\": null}]', 'C', '设原半径为 r，高为 h，原体积=πr²h。新半径=1.5r，新高=0.5h，新体积=π×(1.5r)\n²×0.5h=π×2.25r²×0.5h=1.125πr²h。体积变化=(1.125πr²h-πr²h)÷πr²h×100%=12.5%。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (303, '甲、乙两人合作完成一项工作，甲单独完成需要 12 天，乙单独完成需要 18 天。如果两\n人合作，中途乙因事离开，实际用了 8 天完成工作。问乙工作了几天？', 1, '[{\"key\": \"A\", \"value\": \"4 天\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"5 天\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"6 天\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"7 天\", \"imageUrl\": \"\"}]', 'C', '设乙工作了 x 天，则甲工作了 8 天。甲每天完成 1/12，乙每天完成 1/18。根据题意：\n8/12+x/18=1，即 2/3+x/18=1，x/18=1/3，x=6 天。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:51', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (304, '甲、乙两人同时从 A 地出发前往 B 地，甲速度为 5km/h，乙速度为 3km/h。甲到达 B 地\n后立即返回，在距离 B 地 6km 处与乙相遇。问 A、B 两地的距离是多少千米？', 1, '[{\"key\": \"A\", \"value\": \"18km\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"21km\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"24km\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"27km\", \"imageUrl\": null}]', 'C', '设 AB 距离为 S。甲到达 B 地用时 S/5 小时，此时乙行驶了 3×S/5=3S/5 千米，距离 B\n地还有 S-3S/5=2S/5 千米。甲从 B 地返回，乙继续前行。两车相遇时，甲行驶了 6 千米，用\n时 6÷5=1.2小时。乙在这 1.2小时内行驶了 3×1.2=3.6千米。相遇时乙距离 B地还有 2S/5-3.6\n千米。但题目说相遇时距离 B 地 6km，所以 2S/5-3.6=6，2S/5=9.6，S=24km。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (305, '甲、乙两车同时从 A 地出发前往 B 地，甲车速度为 80km/h，乙车速度为 60km/h。甲车\n到达 B 地后立即返回，在距离 B 地 40km 处与乙车相遇。问 A、B 两地的距离是多少千米？', 1, '[{\"key\": \"A\", \"value\": \"240km\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"280km\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"320km\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"360km\", \"imageUrl\": null}]', 'B', '设 AB 距离为 S。甲车到达 B 地用时 S/80 小时，此时乙车行驶了 60×S/80=3S/4 千米，\n距离 B 地还有 S-3S/4=S/4 千米。甲车从 B 地返回，乙车继续前行。两车相遇时，甲车行驶\n了 40 千米，用时 40÷80=0.5 小时。乙车在这 0.5 小时内行驶了 60×0.5=30 千米。相遇时乙\n车距离 B 地还有 S/4-30 千米。但题目说相遇时距离 B 地 40km，所以 S/4-30=40，S/4=70，\nS=280km。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (306, '某商店进购一批商品，进价为每件 60 元，按标价出售可获得 25%的利润。如果按标价的\n8 折出售，问利润率是多少？', 1, '[{\"key\": \"A\", \"value\": \"0%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"5%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"10%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"15%\", \"imageUrl\": \"\"}]', 'A', '设标价为 x 元，则 x=60×(1+25%)=75 元。按 8 折出售，售价=75×0.8=60 元。利润率\n=(60-60)÷60×100%=0%。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:32', NULL, NULL, 2, '数量关系', '');
INSERT INTO `question` VALUES (307, '某班有学生 45 人，其中喜欢数学的有 27 人，喜欢语文的有 18 人，喜欢英语的有 15 人。同时喜欢数学和语文的有 12 人，同时喜欢数学和英语的有 9 人，同时喜欢语文和英语的有6 人。三门都喜欢的有 3 人。问三门都不喜欢的有多少人？', 1, '[{\"key\": \"A\", \"value\": \"6 人\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"9 人\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"12 人\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"15 人\", \"imageUrl\": \"\"}]', 'B', '只喜欢数学和语文的=12-3=9 人，只喜欢数学和英语的=9-3=6 人，只喜欢语文和英语\n的=6-3=3 人。只喜欢数学的=27-9-6-3=9 人，只喜欢语文的=18-9-3-3=3 人，只喜欢英语的\n=15-6-3-3=3 人。至少喜欢一门的人数=9+3+3+9+6+3+3=36 人。三门都不喜欢的人数=45-36=9\n人。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:24', NULL, NULL, 5, '数量关系', '');
INSERT INTO `question` VALUES (308, '一个长方体的长、宽、高分别为 6cm、4cm、3cm。如果长增加 50%，宽增加 25%，高减\n少 50%，则其体积如何变化？', 1, '[{\"key\": \"A\", \"value\": \"不变\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"增加 6.25%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"减少 6.25%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"减少 12.5%\", \"imageUrl\": \"\"}]', 'C', '原体积=6×4×3=72cm³。新长=6×1.5=9cm，新宽=4×1.25=5cm，新高=3×0.5=1.5cm。\n新体积=9×5×1.5=67.5cm³。体积变化=(67.5-72)÷72×100%=-4.5÷72×100%=-6.25%。', '2026-03-12 17:49:53', 16, '2026-03-12 17:50:19', NULL, NULL, 4, '数量关系', '');
INSERT INTO `question` VALUES (309, '甲、乙两人分别从 A、B 两地同时出发，相向而行。甲的速度为 4km/h，乙的速度为 6km/h。\n两人相遇后，甲继续前行到 B 地，立即返回；乙继续前行到 A 地，立即返回。问两人第二\n次相遇时，乙总共行驶了多少千米？', 1, '[{\"key\": \"A\", \"value\": \"18km\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"24km\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"30km\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"36km\", \"imageUrl\": null}]', 'C', '设 AB 距离为 S。第一次相遇时，两人行驶时间相同，甲行驶 4t，乙行驶 6t，4t+6t=S，\nt=S/10。甲第一次行驶 4×S/10=2S/5，乙第一次行驶 6×S/10=3S/5。从第一次相遇到第二次\n相遇，两人共行驶 2S，用时 2S÷(4+6)=S/5 小时。乙在第二次相遇前又行驶了 6×S/5=6S/5。\n乙总路程=3S/5+6S/5=9S/5。如果 S=50/3km，则乙行驶 30km。', '2026-03-12 17:49:53', 16, NULL, NULL, NULL, 3, '数量关系', NULL);
INSERT INTO `question` VALUES (310, '党的二十大报告指出，高质量发展是全面建设社会主义现代化国家的首要任务。高质量发\n展不只是一个经济要求，而是对经济社会发展方方面面的总要求；不只是对经济发达地区的\n要求，而是所有地区发展都必须贯彻的要求；不是一时一事的要求，而是必须长期坚持的要\n求。这段文字意在强调：', 1, '[{\"key\": \"A\", \"value\": \"高质量发展是全面建设社会主义现代化国家的首要任务\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"高质量发展是经济社会发展的总要求\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"高质量发展具有全面性、普遍性和长期性的特征\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"所有地区都必须贯彻高质量发展的要求\", \"imageUrl\": null}]', 'C', '文段通过三个\"不是……而是……\"的排比句式，从范围、地域、时间三个维度阐述了\n高质量发展的特征：全面性（对经济社会发展方方面面）、普遍性（所有地区发展都必须贯\n彻）、长期性（必须长期坚持）。因此文段意在强调高质量发展具有全面性、普遍性和长期性\n的特征，C 项正确。A 项是文段开头的前提，不是重点；B、D 项只涉及一个维度，概括不全\n面。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (311, '当前，我国发展进入战略机遇和风险挑战并存、不确定难预料因素增多的时期。越是形势\n复杂、任务艰巨，越要坚持党的全面领导，越要发挥党总揽全局、协调各方的领导核心作用。\n只有坚持党的全面领导，才能确保我国社会主义现代化建设正确方向，确保拥有团结奋斗的\n强大政治凝聚力、发展自信心，集聚起万众一心、共克时艰的磅礴力量。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"我国发展面临复杂的形势和艰巨的任务\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"党的全面领导是应对风险挑战的根本保证\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"社会主义现代化建设需要强大的政治凝聚力\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"团结奋斗是战胜困难的重要力量\", \"imageUrl\": \"\"}]', 'B', '文段首先指出我国发展面临复杂形势和艰巨任务，然后强调\"越是……越要坚持党的\n全面领导\"，最后通过\"只有……才能……\"的句式说明坚持党的全面领导的重要作用。整个\n文段的逻辑是：面临挑战→需要党的领导→党的领导的作用。因此文段主要说明党的全面领\n导是应对风险挑战的根本保证，B 项正确。A 项是背景，不是重点；C、D 项是党的领导作用\n的具体表现，不是文段主旨。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:38', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (312, '数字经济发展速度之快、辐射范围之广、影响程度之深前所未有，正在成为重组全球要素\n资源、重塑全球经济结构、改变全球竞争格局的关键力量。要抓住先机、抢占未来发展制高\n点，必须推动数字技术和实体经济深度融合，赋能传统产业转型升级，催生新产业新业态新\n模式，不断做强做优做大我国数字经济。这段文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"数字经济发展速度之快、辐射范围之广、影响程度之深\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"数字经济正在成为改变全球竞争格局的关键力量\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"推动数字技术与实体经济深度融合是发展数字经济的必然要求\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"我国要不断做强做优做大数字经济\", \"imageUrl\": \"\"}]', 'C', '文段首先阐述数字经济的重要性和影响力，然后提出\"要抓住先机、抢占未来发展制\n高点，必须推动数字技术和实体经济深度融合\"，最后说明推动深度融合的具体措施。因此\n文段的重点是推动数字技术与实体经济深度融合，C 项正确。A、B 项是背景，不是重点；D\n项是目标，不是实现目标的手段。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:28', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (313, '共同富裕是社会主义的本质要求，是中国式现代化的重要特征。我们说的共同富裕是全体\n人民共同富裕，是人民群众物质生活和精神生活都富裕，不是少数人的富裕，也不是整齐划\n一的平均主义。促进共同富裕，既要通过高质量发展把\"蛋糕\"做大做好，又要通过合理的制\n度安排把\"蛋糕\"切好分好。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"共同富裕是社会主义的本质要求\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"共同富裕是全体人民的共同富裕\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"促进共同富裕需要处理好\\\"做大蛋糕\\\"和\\\"分好蛋糕\\\"的关系\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"共同富裕不是整齐划一的平均主义\", \"imageUrl\": \"\"}]', 'C', '文段首先指出共同富裕的重要性和特征，然后说明共同富裕的内涵，最后提出促进共\n同富裕的具体路径：\"既要通过高质量发展把\'蛋糕\'做大做好，又要通过合理的制度安排把\'\n蛋糕\'切好分好\"。因此文段的重点是促进共同富裕需要处理好\"做大蛋糕\"和\"分好蛋糕\"的关\n系，C 项正确。A、B、D项都是对共同富裕内涵的阐述，不是文段重点。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:23', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (314, '科技创新是国家命运所系，是发展形势所迫，是时代大势所趋。当前，新一轮科技革命和\n产业变革深入发展，科技创新成为国际战略博弈的主要战场，围绕科技制高点的竞争空前激\n烈。只有把科技自立自强作为国家发展的战略支撑，才能从根本上保障国家发展安全、掌握\n发展主动权。这段文字意在强调：', 1, '[{\"key\": \"A\", \"value\": \"科技创新是国家命运所系、发展形势所迫、时代大势所趋\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"新一轮科技革命和产业变革深入发展\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"科技自立自强是国家发展的战略支撑\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"科技创新是国际战略博弈的主要战场\", \"imageUrl\": \"\"}]', 'C', '文段首先阐述科技创新的重要性，然后分析当前科技竞争的形势，最后通过\"只有……\n才能……\"的句式强调科技自立自强的重要性。因此文段意在强调科技自立自强是国家发展\n的战略支撑，C 项正确。A、B、D项是背景，不是重点。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:20', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (315, '推进中国式现代化，是一项前无古人的开创性事业，必然会遇到各种可以预料和难以预料\n的风险挑战、艰难险阻甚至惊涛骇浪。我们必须增强忧患意识，坚持底线思维，做到居安思\n危、未雨绸缪，准备经受风高浪急甚至惊涛骇浪的重大考验。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"推进中国式现代化会遇到各种风险挑战\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"必须增强忧患意识，坚持底线思维\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"推进中国式现代化需要做好应对风险挑战的准备\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"中国式现代化是一项前无古人的开创性事业\", \"imageUrl\": null}]', 'C', '文段首先指出推进中国式现代化会遇到各种风险挑战，然后提出应对措施：\"必须增\n强忧患意识，坚持底线思维，做到居安思危、未雨绸缪\"。因此文段主要说明推进中国式现\n代化需要做好应对风险挑战的准备，C 项正确。A 项是背景，不是重点；B 项是具体措施，\n不是文段主旨；D 项是背景，不是重点。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (316, '生态文明建设是关系中华民族永续发展的根本大计。绿水青山就是金山银山，深刻揭示了\n经济发展和生态环境保护的关系，阐明了保护生态环境就是保护生产力、改善生态环境就是\n发展生产力的道理。推动经济社会发展绿色化、低碳化是实现高质量发展的关键环节。这段\n文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"生态文明建设是关系中华民族永续发展的根本大计\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"绿水青山就是金山银山\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"推动经济社会发展绿色化、低碳化是实现高质量发展的关键环节\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"保护生态环境就是保护生产力\", \"imageUrl\": \"\"}]', 'C', '文段首先指出生态文明建设的重要性，然后阐述\"绿水青山就是金山银山\"的理念，最\n后提出\"推动经济社会发展绿色化、低碳化是实现高质量发展的关键环节\"。因此文段意在说\n明推动经济社会发展绿色化、低碳化是实现高质量发展的关键环节，C 项正确。A、B、D 项\n都是背景或理念阐述，不是文段重点。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:17', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (317, '乡村振兴是实现中华民族伟大复兴的一项重大任务。产业振兴是乡村振兴的重中之重，也\n是实际工作的切入点。只有产业兴旺，才能增强乡村吸引力，促进各类生产要素向乡村聚集；\n才能激活乡村内生动力，实现农民持续增收；才能为乡村全面振兴奠定坚实物质基础。这段\n文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"乡村振兴是实现中华民族伟大复兴的一项重大任务\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"产业振兴是乡村振兴的重中之重\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"产业兴旺对乡村全面振兴具有重要意义\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"产业振兴是实际工作的切入点\", \"imageUrl\": null}]', 'C', '文段首先指出乡村振兴的重要性，然后提出\"产业振兴是乡村振兴的重中之重\"，最后\n通过三个\"只有……才能……\"的句式说明产业兴旺的重要作用。因此文段主要说明产业兴旺\n对乡村全面振兴具有重要意义，C 项正确。A 项是背景，不是重点；B 项是前提，不是重点；\nD项是次要信息，不是重点。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (318, '文化自信是一个国家、一个民族发展中最基本、最深沉、最持久的力量。没有高度的文化自信，没有文化的繁荣兴盛，就没有中华民族伟大复兴。要坚持中国特色社会主义文化发展道路，激发全民族文化创新创造活力，增强实现中华民族伟大复兴的精神力量。这段文字意在强调：', 1, '[{\"key\": \"A\", \"value\": \"文化自信是一个国家、一个民族发展中最基本、最深沉、最持久的力量\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"没有高度的文化自信，就没有中华民族伟大复兴\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"要坚持中国特色社会主义文化发展道路\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"文化自信对实现中华民族伟大复兴具有重要意义\", \"imageUrl\": \"\"}]', 'D', '文段首先指出文化自信的重要性，然后通过\"没有……就没有……\"的句式说明文化自信与中华民族伟大复兴的关系，最后提出坚持文化发展道路的要求。因此文段意在强调文化自信对实现中华民族伟大复兴具有重要意义，D 项正确。A 项是背景，不是重点；B 项是论证过程，不是重点；C 项是具体措施，不是文段主旨。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:15', NULL, NULL, 5, '言语理解', '');
INSERT INTO `question` VALUES (319, '全面依法治国是国家治理的一场深刻革命，关系党执政兴国，关系人民幸福安康，关系\n党和国家长治久安。必须坚持依法治国、依法执政、依法行政共同推进，坚持法治国家、法\n治政府、法治社会一体建设，全面推进科学立法、严格执法、公正司法、全民守法。这段文\n字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"全面依法治国是国家治理的一场深刻革命\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"全面依法治国关系党和国家长治久安\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"必须全面推进依法治国各项工作\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"要坚持法治国家、法治政府、法治社会一体建设\", \"imageUrl\": null}]', 'C', '文段首先指出全面依法治国的重要性，然后提出具体要求：\"必须坚持依法治国、依\n法执政、依法行政共同推进，坚持法治国家、法治政府、法治社会一体建设，全面推进科学\n立法、严格执法、公正司法、全民守法\"。因此文段主要说明必须全面推进依法治国各项工\n作，C 项正确。A、B 项是背景，不是重点；D 项是具体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (320, '构建新发展格局，是与时俱进提升我国经济发展水平的战略抉择，也是塑造我国国际经\n济合作和竞争新优势的战略抉择。构建新发展格局的关键在于经济循环的畅通无阻，最本质\n的特征是实现高水平的自立自强。这段文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"构建新发展格局是提升我国经济发展水平的战略抉择\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"构建新发展格局的关键在于经济循环的畅通无阻\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"构建新发展格局最本质的特征是实现高水平的自立自强\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"构建新发展格局的重要意义和本质特征\", \"imageUrl\": \"\"}]', 'D', '文段首先指出构建新发展格局的战略意义，然后说明构建新发展格局的关键和本质特\n征。因此文段意在说明构建新发展格局的重要意义和本质特征，D 项正确。A、B、C 项都只\n涉及文段的一部分内容，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:58:49', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (321, '碳达峰碳中和是一场广泛而深刻的经济社会系统性变革，绝不是轻轻松松、敲锣打鼓就\n能实现的。必须坚持全国统筹、节约优先、双轮驱动、内外畅通、防范风险的原则，处理好\n发展和减排、整体和局部、长远目标和短期目标、政府和市场的关系。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"碳达峰碳中和是一场广泛而深刻的经济社会系统性变革\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"实现碳达峰碳中和不是轻轻松松就能实现的\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"实现碳达峰碳中和需要坚持正确的原则和处理好各种关系\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"碳达峰碳中和需要处理好发展和减排的关系\", \"imageUrl\": \"\"}]', 'C', '文段首先指出碳达峰碳中和的艰巨性，然后提出具体要求：\"必须坚持全国统筹、节\n约优先、双轮驱动、内外畅通、防范风险的原则，处理好发展和减排、整体和局部、长远目\n标和短期目标、政府和市场的关系\"。因此文段主要说明实现碳达峰碳中和需要坚持正确的\n原则和处理好各种关系，C 项正确。A、B 项是背景，不是重点；D 项只涉及一个关系，概括\n不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:58:45', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (322, '国家安全是民族复兴的根基，社会稳定是国家强盛的前提。必须坚定不移贯彻总体国家安全观，把维护国家安全贯穿党和国家工作各方面全过程，确保国家安全和社会稳定。要健全国家安全体系，增强维护国家安全能力，提高公共安全治理水平，完善社会治理体系。这段文字意在强调：', 1, '[{\"key\": \"A\", \"value\": \"国家安全是民族复兴的根基，社会稳定是国家强盛的前提\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"必须坚定不移贯彻总体国家安全观\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"要健全国家安全体系，增强维护国家安全能力\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"维护国家安全和社会稳定的重要性及具体措施\", \"imageUrl\": \"\"}]', 'D', '文段首先指出国家安全和社会稳定的重要性，然后提出贯彻总体国家安全观的要求，\n最后说明具体措施。因此文段意在强调维护国家安全和社会稳定的重要性及具体措施，D 项\n正确。A 项是背景，不是重点；B、C 项是具体要求或措施，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 18:00:13', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (323, '发展全过程人民民主是中国式现代化的本质要求。必须坚持人民主体地位，充分体现人\n民意志、保障人民权益、激发人民创造活力。要健全人民当家作主制度体系，扩大人民有序\n政治参与，保证人民依法实行民主选举、民主协商、民主决策、民主管理、民主监督。这段\n文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"发展全过程人民民主是中国式现代化的本质要求\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"必须坚持人民主体地位\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"要健全人民当家作主制度体系\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"发展全过程人民民主的要求和具体措施\", \"imageUrl\": null}]', 'D', '文段首先指出发展全过程人民民主的重要性，然后提出坚持人民主体地位的要求，最\n后说明具体措施。因此文段主要说明发展全过程人民民主的要求和具体措施，D项正确。A\n项是背景，不是重点；B、C 项是具体要求或措施，概括不全面。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (324, '推进文化自信自强，铸就社会主义文化新辉煌，必须坚持马克思主义在意识形态领域指\n导地位的根本制度，坚持为人民服务、为社会主义服务，坚持百花齐放、百家争鸣，坚持创\n造性转化、创新性发展，以社会主义核心价值观为引领，发展社会主义先进文化，弘扬革命\n文化，传承中华优秀传统文化。这段文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"推进文化自信自强，铸就社会主义文化新辉煌\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"必须坚持马克思主义在意识形态领域指导地位的根本制度\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"以社会主义核心价值观为引领，发展社会主义先进文化\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"推进文化自信自强需要坚持正确的方针和原则\", \"imageUrl\": \"\"}]', 'D', '文段首先提出推进文化自信自强的目标，然后通过多个\"坚持\"说明需要遵循的方针和\n原则。因此文段意在说明推进文化自信自强需要坚持正确的方针和原则，D项正确。A 项是\n目标，不是重点；B、C 项是具体方针之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 18:00:11', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (325, '当前，世界百年未有之大变局加速演进，新一轮科技革命和产业变革深入发展，国际力\n量对比深刻调整，我国发展进入战略机遇和风险挑战并存、不确定难预料因素增多的时期。\n我们必须增强忧患意识，坚持底线思维，准备经受风高浪急甚至惊涛骇浪的重大考验。这段\n文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"世界百年未有之大变局加速演进\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"新一轮科技革命和产业变革深入发展\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"我国发展面临复杂的国际国内环境\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"必须增强忧患意识，坚持底线思维\", \"imageUrl\": \"\"}]', 'C', '文段首先分析当前国际国内形势，然后提出应对要求。因此文段主要说明我国发展面\n临复杂的国际国内环境，C 项正确。A、B 项是国际形势的具体表现，概括不全面；D 项是应\n对措施，不是文段主旨。', '2026-03-12 17:58:41', 16, '2026-03-12 18:00:08', NULL, NULL, 3, '言语理解', '');
INSERT INTO `question` VALUES (326, '坚持把发展经济的着力点放在实体经济上，推进新型工业化，加快建设制造强国、质量\n强国、航天强国、交通强国、网络强国、数字中国。实施产业基础再造工程和重大技术装备\n攻关工程，支持专精特新企业发展，推动制造业高端化、智能化、绿色化发展。这段文字意\n在说明：', 1, '[{\"key\": \"A\", \"value\": \"坚持把发展经济的着力点放在实体经济上\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"推进新型工业化，加快建设制造强国\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"推动制造业高端化、智能化、绿色化发展\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"发展实体经济和推进新型工业化的具体措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出坚持把发展经济的着力点放在实体经济上，推进新型工业化，然后说明\n具体措施。因此文段意在说明发展实体经济和推进新型工业化的具体措施，D 项正确。A、B\n项是目标，不是重点；C 项是具体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 18:00:05', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (327, '全面推进乡村振兴，坚持农业农村优先发展，巩固拓展脱贫攻坚成果，加快建设农业强\n国，扎实推动乡村产业、人才、文化、生态、组织振兴。全方位夯实粮食安全根基，牢牢守\n住十八亿亩耕地红线，确保中国人的饭碗牢牢端在自己手中。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"全面推进乡村振兴，坚持农业农村优先发展\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"巩固拓展脱贫攻坚成果，加快建设农业强国\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"扎实推动乡村产业、人才、文化、生态、组织振兴\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"全面推进乡村振兴的具体要求和措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出全面推进乡村振兴的要求，然后说明具体措施。因此文段主要说明全面\n推进乡村振兴的具体要求和措施，D 项正确。A、B 项是目标，不是重点；C 项是具体措施之\n一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 18:00:02', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (328, '促进区域协调发展，深入实施区域协调发展战略、区域重大战略、主体功能区战略、新型城镇化战略，优化重大生产力布局，构建优势互补、高质量发展的区域经济布局和国土空间体系。推动西部大开发形成新格局，推动东北全面振兴取得新突破，促进中部地区加快崛起，鼓励东部地区加快推进现代化。这段文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"促进区域协调发展\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"深入实施区域协调发展战略\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"推动西部大开发形成新格局\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"促进区域协调发展的战略和措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出促进区域协调发展的目标，然后说明具体战略和措施。因此文段意在说明促进区域协调发展的战略和措施，D项正确。A 项是目标，不是重点；B、C 项是具体战略之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:31', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (329, '推进高水平对外开放，稳步扩大规则、规制、管理、标准等制度型开放，加快建设贸易\n强国，推动共建\"一带一路\"高质量发展，维护多元稳定的国际经济格局和经贸关系。这段文\n字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"推进高水平对外开放\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"稳步扩大制度型开放\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"加快建设贸易强国\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"推进高水平对外开放的具体措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出推进高水平对外开放的目标，然后说明具体措施。因此文段主要说明推\n进高水平对外开放的具体措施，D 项正确。A 项是目标，不是重点；B、C 项是具体措施之一，\n概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:59', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (330, '坚持全面依法治国，推进法治中国建设。围绕保障和促进社会公平正义，坚持依法治国、\n依法执政、依法行政共同推进，坚持法治国家、法治政府、法治社会一体建设，全面推进科\n学立法、严格执法、公正司法、全民守法，全面推进国家各方面工作法治化。这段文字意在\n说明：', 1, '[{\"key\": \"A\", \"value\": \"坚持全面依法治国，推进法治中国建设\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"保障和促进社会公平正义\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"坚持法治国家、法治政府、法治社会一体建设\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"推进法治中国建设的具体要求和措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出坚持全面依法治国、推进法治中国建设的目标，然后说明具体要求和措\n施。因此文段意在说明推进法治中国建设的具体要求和措施，D 项正确。A 项是目标，不是\n重点；B 项是目的，不是重点；C 项是具体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:56', NULL, NULL, 5, '言语理解', '');
INSERT INTO `question` VALUES (331, '推进文化自信自强，铸就社会主义文化新辉煌。建设具有强大凝聚力和引领力的社会主\n义意识形态，广泛践行社会主义核心价值观，提高全社会文明程度，繁荣发展文化事业和文\n化产业，增强中华文明传播力影响力。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"推进文化自信自强，铸就社会主义文化新辉煌\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"建设具有强大凝聚力和引领力的社会主义意识形态\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"繁荣发展文化事业和文化产业\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"推进文化自信自强的具体措施\", \"imageUrl\": null}]', 'D', '文段首先提出推进文化自信自强、铸就社会主义文化新辉煌的目标，然后说明具体措\n施。因此文段主要说明推进文化自信自强的具体措施，D项正确。A 项是目标，不是重点；\nB、C 项是具体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (332, '增进民生福祉，提高人民生活品质。坚持在发展中保障和改善民生，鼓励共同奋斗创造\n美好生活，不断实现人民对美好生活的向往。我们要实现好、维护好、发展好最广大人民根\n本利益，紧紧抓住人民最关心最直接最现实的利益问题，坚持尽力而为、量力而行，深入群\n众、深入基层，采取更多惠民生、暖民心举措，着力解决好人民群众急难愁盼问题。这段文\n字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"增进民生福祉，提高人民生活品质\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"坚持在发展中保障和改善民生\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"采取更多惠民生、暖民心举措\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"增进民生福祉的具体要求和措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出增进民生福祉、提高人民生活品质的目标，然后说明具体要求和措施。\n因此文段意在说明增进民生福祉的具体要求和措施，D 项正确。A 项是目标，不是重点；B\n项是原则，不是重点；C 项是具体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:53', NULL, NULL, 2, '言语理解', '');
INSERT INTO `question` VALUES (333, '推动绿色发展，促进人与自然和谐共生。加快发展方式绿色转型，深入推进环境污染防\n治，提升生态系统多样性、稳定性、持续性，积极稳妥推进碳达峰碳中和。这段文字主要说\n明：', 1, '[{\"key\": \"A\", \"value\": \"推动绿色发展，促进人与自然和谐共生\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"加快发展方式绿色转型\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"深入推进环境污染防治\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"推动绿色发展的具体措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出推动绿色发展、促进人与自然和谐共生的目标，然后说明具体措施。因\n此文段主要说明推动绿色发展的具体措施，D 项正确。A 项是目标，不是重点；B、C 项是具\n体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:47', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (334, '推进国家安全体系和能力现代化，坚决维护国家安全和社会稳定。健全国家安全体系，\n增强维护国家安全能力，提高公共安全治理水平，完善社会治理体系。这段文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"推进国家安全体系和能力现代化\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"坚决维护国家安全和社会稳定\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"健全国家安全体系\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"推进国家安全体系和能力现代化的具体措施\", \"imageUrl\": \"\"}]', 'D', '文段首先提出推进国家安全体系和能力现代化、坚决维护国家安全和社会稳定的目标，\n然后说明具体措施。因此文段意在说明推进国家安全体系和能力现代化的具体措施，D 项正\n确。A、B 项是目标，不是重点；C 项是具体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:44', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (335, '坚持和完善社会主义基本经济制度，毫不动摇巩固和发展公有制经济，毫不动摇鼓励、\n支持、引导非公有制经济发展，充分发挥市场在资源配置中的决定性作用，更好发挥政府作\n用。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"坚持和完善社会主义基本经济制度\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"毫不动摇巩固和发展公有制经济\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"充分发挥市场在资源配置中的决定性作用\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"坚持和完善社会主义基本经济制度的具体要求\", \"imageUrl\": null}]', 'D', '文段首先提出坚持和完善社会主义基本经济制度的目标，然后说明具体要求。因此文\n段主要说明坚持和完善社会主义基本经济制度的具体要求，D项正确。A 项是目标，不是重\n点；B、C 项是具体要求之一，概括不全面。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (336, '坚持科技是第一生产力、人才是第一资源、创新是第一动力，深入实施科教兴国战略、\n人才强国战略、创新驱动发展战略，开辟发展新领域新赛道，不断塑造发展新动能新优势。\n这段文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"坚持科技是第一生产力、人才是第一资源、创新是第一动力\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"深入实施科教兴国战略、人才强国战略、创新驱动发展战略\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"开辟发展新领域新赛道\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"深入实施科教兴国战略、人才强国战略、创新驱动发展战略的重要意义\", \"imageUrl\": \"\"}]', 'D', '文段首先提出科技、人才、创新的重要性，然后说明深入实施相关战略的目标。因此\n文段意在说明深入实施科教兴国战略、人才强国战略、创新驱动发展战略的重要意义，D 项\n正确。A 项是前提，不是重点；B 项是措施，不是重点；C 项是目标，不是重点。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:41', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (337, '坚持全面深化改革，推进国家治理体系和治理能力现代化。坚持社会主义市场经济改革\n方向，坚持\"两个毫不动摇\"，构建高水平社会主义市场经济体制。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"坚持全面深化改革\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"推进国家治理体系和治理能力现代化\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"构建高水平社会主义市场经济体制\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"坚持全面深化改革的具体要求和目标\", \"imageUrl\": null}]', 'D', '文段首先提出坚持全面深化改革、推进国家治理体系和治理能力现代化的目标，然后\n说明具体要求。因此文段主要说明坚持全面深化改革的具体要求和目标，D 项正确。A、B\n项是目标，不是重点；C 项是具体要求之一，概括不全面。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (338, '坚持人民当家作主，发展全过程人民民主，健全人民当家作主制度体系，扩大人民有序\n政治参与，保证人民依法实行民主选举、民主协商、民主决策、民主管理、民主监督。这段\n文字意在说明：', 1, '[{\"key\": \"A\", \"value\": \"坚持人民当家作主\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"发展全过程人民民主\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"健全人民当家作主制度体系\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"坚持人民当家作主的具体要求和措施\", \"imageUrl\": null}]', 'D', '文段首先提出坚持人民当家作主、发展全过程人民民主的目标，然后说明具体要求和\n措施。因此文段意在说明坚持人民当家作主的具体要求和措施，D项正确。A、B 项是目标，\n不是重点；C 项是具体措施之一，概括不全面。', '2026-03-12 17:58:41', 16, NULL, NULL, NULL, 3, '言语理解', NULL);
INSERT INTO `question` VALUES (339, '坚持和完善中国共产党领导的多党合作和政治协商制度，完善人民政协民主监督和委员\n联系界别群众制度机制。这段文字主要说明：', 1, '[{\"key\": \"A\", \"value\": \"坚持和完善中国共产党领导的多党合作和政治协商制度\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"完善人民政协民主监督制度\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"完善委员联系界别群众制度机制\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"坚持和完善中国共产党领导的多党合作和政治协商制度的具体要求\", \"imageUrl\": \"\"}]', 'D', '文段首先提出坚持和完善中国共产党领导的多党合作和政治协商制度的目标，然后说\n明具体要求。因此文段主要说明坚持和完善中国共产党领导的多党合作和政治协商制度的具\n体要求，D项正确。A 项是目标，不是重点；B、C 项是具体要求之一，概括不全面。', '2026-03-12 17:58:41', 16, '2026-03-12 17:59:35', NULL, NULL, 4, '言语理解', '');
INSERT INTO `question` VALUES (340, '某公司有甲、乙、丙、丁、戊五位员工，他们分别来自北京、上海、广州、深圳、成都五\n个城市。已知：\n（1）甲不来自北京，也不来自广州；\n（2）乙不来自上海，也不来自深圳；\n（3）丙不来自北京，也不来自成都；\n（4）丁不来自广州，也不来自深圳；\n（5）戊不来自成都。\n如果来自北京的员工比来自上海的员工年龄大，来自上海的员工比来自广州的员工年龄大，\n来自广州的员工比来自深圳的员工年龄大，来自深圳的员工比来自成都的员工年龄大。\n请问，来自北京的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"甲\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"乙\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"丙\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"丁\", \"imageUrl\": null}]', 'B', '根据条件（1）（3），甲和丙都不来自北京；根据条件（5），戊不来自成都，所以戊可\n能来自北京。但根据年龄顺序，来自北京的员工年龄最大。如果戊来自北京，那么其他员工\n分别来自其他城市。但这样无法满足所有条件。通过排除法，只有乙可能来自北京。验证：\n乙来自北京，甲来自深圳（不来自北京、广州），丙来自上海（不来自北京、成都），丁来自\n成都（不来自广州、深圳），戊来自广州（不来自成都）。所有条件都满足，且年龄顺序为乙>\n丙>戊>甲>丁，符合条件。', '2026-03-12 18:10:34', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (341, '某中学有七位教师：A、B、C、D、E、F、G，他们分别教授语文、数学、英语、物理、化\n学、生物、历史七门课程。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教生物；\n（5）E 不教化学，也不教历史；\n（6）F 不教生物，也不教历史；\n（7）G 不教历史。\n如果教授语文的教师比教授数学的教师教龄长，教授数学的教师比教授英语的教师教龄长，\n教授英语的教师比教授物理的教师教龄长，教授物理的教师比教授化学的教师教龄长，教授\n化学的教师比教授生物的教师教龄长，教授生物的教师比教授历史的教师教龄长。\n请问，教授语文的教师是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不教语文、数学；根据条件（3），C 不教数学、化学；根据条件（7），\nG 不教历史。根据教龄顺序，教授语文的教师教龄最长。通过排除法，只有 D 可能教授语文。\n验证：D 教语文，A 教英语（不教语文、数学），B 教化学（不教英语、物理），C 教历史（不\n教数学、化学），E教数学（不教化学、历史），F 教物理（不教生物、历史），G 教生物（不\n教历史）。所有条件都满足，且教龄顺序为 D>E>A>F>B>G>C，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:34', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (342, '某小区有五栋楼：1 号楼、2 号楼、3 号楼、4 号楼、5 号楼，分别住着张、王、李、赵、\n陈五户人家。已知：\n（1）张不住 1 号楼，也不住 3 号楼；\n（2）王不住 2 号楼，也不住 4 号楼；\n（3）李不住 3 号楼，也不住 5 号楼；\n（4）赵不住 1 号楼，也不住 2 号楼；\n（5）陈不住 4 号楼，也不住 5 号楼。\n如果住在 1 号楼的人家比住在 2 号楼的人家入住时间早，住在 2 号楼的人家比住在 3 号楼的\n人家入住时间早，住在 3 号楼的人家比住在 4 号楼的人家入住时间早，住在 4 号楼的人家比\n住在 5 号楼的人家入住时间早。\n请问，住在 1 号楼的人家是谁？', 1, '[{\"key\": \"A\", \"value\": \"张\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"王\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"李\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"陈\", \"imageUrl\": \"\"}]', 'D', '根据条件（1），张不住 1 号楼、3 号楼；根据条件（4），赵不住 1 号楼、2 号楼；根\n据条件（5），陈不住 4号楼、5 号楼。根据入住时间顺序，住在 1 号楼的人家入住时间最早。\n通过排除法，只有陈可能住在 1 号楼。验证：陈住 1 号楼，张住 4 号楼（不住 1 号楼、3 号\n楼），王住 5 号楼（不住 2 号楼、4 号楼），李住 2 号楼（不住 3 号楼、5 号楼），赵住 3号楼\n（不住 1 号楼、2 号楼）。所有条件都满足，且入住时间顺序为陈>李>赵>张>王，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:39', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (343, '某公司有六个部门：人事部、财务部、市场部、技术部、运营部、客服部，分别由甲、乙、\n丙、丁、戊、己六位经理负责。已知：\n（1）甲不负责人事部，也不负责财务部；\n（2）乙不负责市场部，也不负责技术部；\n（3）丙不负责财务部，也不负责运营部；\n（4）丁不负责技术部，也不负责客服部；\n（5）戊不负责运营部，也不负责客服部；\n（6）己不负责人事部。\n如果人事部比财务部员工多，财务部比市场部员工多，市场部比技术部员工多，技术部比运\n营部员工多，运营部比客服部员工多。\n请问，人事部的负责人是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": null}]', 'C', '根据条件（1），甲不负责人事部、财务部；根据条件（6），己不负责人事部。根据员\n工数量顺序，人事部员工最多。通过排除法，只有丁可能负责人事部。验证：丁负责人事部，\n甲负责技术部（不负责人事部、财务部），乙负责客服部（不负责市场部、技术部），丙负责\n市场部（不负责财务部、运营部），戊负责财务部（不负责运营部、客服部），己负责运营部\n（不负责人事部）。所有条件都满足，且员工数量顺序为丁>戊>丙>甲>己>乙，符合条件。', '2026-03-12 18:10:34', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (344, '某大学有七位教授：A、B、C、D、E、F、G，他们分别毕业于北京大学、清华大学、复旦\n大学、上海交通大学、浙江大学、南京大学、武汉大学七所高校。已知：\n（1）A 不毕业于北京大学，也不毕业于清华大学；\n（2）B 不毕业于复旦大学，也不毕业于上海交通大学；\n（3）C 不毕业于清华大学，也不毕业于浙江大学；\n（4）D 不毕业于上海交通大学，也不毕业于南京大学；\n（5）E 不毕业于浙江大学，也不毕业于武汉大学；\n（6）F 不毕业于南京大学，也不毕业于武汉大学；\n（7）G 不毕业于武汉大学。\n如果毕业于北京大学的教授比毕业于清华大学的教授年龄大，毕业于清华大学的教授比毕业\n于复旦大学的教授年龄大，毕业于复旦大学的教授比毕业于上海交通大学的教授年龄大，毕\n业于上海交通大学的教授比毕业于浙江大学的教授年龄大，毕业于浙江大学的教授比毕业于\n南京大学的教授年龄大，毕业于南京大学的教授比毕业于武汉大学的教授年龄大。\n请问，毕业于北京大学的教授是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不毕业于北京大学、清华大学；根据条件（3），C 不毕业于清华大\n学、浙江大学；根据条件（7），G 不毕业于武汉大学。根据年龄顺序，毕业于北京大学的教\n授年龄最大。通过排除法，只有 D 可能毕业于北京大学。验证：D毕业于北京大学，A 毕业\n于上海交通大学（不毕业于北京大学、清华大学），B 毕业于南京大学（不毕业于复旦大学、\n上海交通大学），C 毕业于武汉大学（不毕业于清华大学、浙江大学），E 毕业于清华大学（不\n毕业于浙江大学、武汉大学），F 毕业于复旦大学（不毕业于南京大学、武汉大学），G 毕业\n于浙江大学（不毕业于武汉大学）。所有条件都满足，且年龄顺序为 D>E>F>A>G>B>C，符合\n条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:41', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (345, '某公司有五位员工：甲、乙、丙、丁、戊，他们分别负责项目 A、项目 B、项目 C、项目 D、\n项目 E。已知：\n（1）甲不负责项目 A，也不负责项目 C；\n（2）乙不负责项目 B，也不负责项目 D；\n（3）丙不负责项目 C，也不负责项目 E；\n（4）丁不负责项目 A，也不负责项目 B；\n（5）戊不负责项目 D，也不负责项目 E。\n如果项目 A 比项目 B 预算高，项目 B 比项目 C 预算高，项目 C 比项目 D 预算高，项目 D 比\n项目 E预算高。\n请问，负责项目 A 的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'A', '根据条件（1），甲不负责项目 A、C；根据条件（4），丁不负责项目 A、B。根据预算\n顺序，项目 A 预算最高。通过排除法，只有乙可能负责项目 A。验证：乙负责项目 A，甲负\n责项目 D（不负责项目 A、C），丙负责项目 B（不负责项目 C、E），丁负责项目 E（不负责项\n目 A、B），戊负责项目 C（不负责项目 D、E）。所有条件都满足，且预算顺序为乙>丙>戊>\n甲>丁，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:47', NULL, NULL, 3, '判断推理', '');
INSERT INTO `question` VALUES (346, '某医院有六位医生：A、B、C、D、E、F，他们分别在内科、外科、儿科、妇科、眼科、耳\n鼻喉科工作。已知：\n（1）A 不在内科，也不在外科；\n（2）B 不在儿科，也不在妇科；\n（3）C 不在外科，也不在眼科；\n（4）D 不在妇科，也不在耳鼻喉科；\n（5）E 不在眼科，也不在耳鼻喉科；\n（6）F 不在内科。\n如果内科医生比外科医生经验丰富，外科医生比儿科医生经验丰富，儿科医生比妇科医生经\n验丰富，妇科医生比眼科医生经验丰富，眼科医生比耳鼻喉科医生经验丰富。\n请问，内科医生是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": null}]', 'C', '根据条件（1），A 不在内科、外科；根据条件（6），F 不在内科。根据经验丰富程度\n顺序，内科医生经验最丰富。通过排除法，只有 D 可能在内科。验证：D在内科，A 在眼科\n（不在内科、外科），B 在耳鼻喉科（不在儿科、妇科），C 在妇科（不在外科、眼科），E 在\n外科（不在眼科、耳鼻喉科），F 在儿科（不在内科）。所有条件都满足，且经验丰富程度顺\n序为 D>E>F>C>A>B，符合条件。', '2026-03-12 18:10:34', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (347, '某学校有五门课程：语文、数学、英语、物理、化学，分别由 A、B、C、D、E 五位老师教\n授。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教化学；\n（5）E 不教语文，也不教英语。\n如果语文课比数学课课时多，数学课比英语课课时多，英语课比物理课课时多，物理课比化\n学课课时多。\n请问，语文课由哪位老师教授？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'B', '根据条件（1），A 不教语文、数学；根据条件（5），E 不教语文、英语。根据课时顺\n序，语文课课时最多。通过排除法，只有 C 可能教授语文。验证：C 教语文，A 教物理（不\n教语文、数学），B 教化学（不教英语、物理），D 教英语（不教物理、化学），E 教数学（不\n教语文、英语）。所有条件都满足，且课时顺序为 C>E>D>A>B，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:51', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (348, '某公司有七个部门：研发部、市场部、销售部、客服部、人事部、财务部、行政部，分别\n由甲、乙、丙、丁、戊、己、庚七位经理负责。已知：\n（1）甲不负责研发部，也不负责市场部；\n（2）乙不负责销售部，也不负责客服部；\n（3）丙不负责市场部，也不负责人事部；\n（4）丁不负责客服部，也不负责财务部；\n（5）戊不负责人事部，也不负责行政部；\n（6）己不负责财务部，也不负责行政部；\n（7）庚不负责行政部。\n如果研发部比市场部员工多，市场部比销售部员工多，销售部比客服部员工多，客服部比人\n事部员工多，人事部比财务部员工多，财务部比行政部员工多。\n请问，研发部的负责人是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），甲不负责研发部、市场部；根据条件（7），庚不负责行政部。根据员\n工数量顺序，研发部员工最多。通过排除法，只有丁可能负责研发部。验证：丁负责研发部，\n甲负责客服部（不负责研发部、市场部），乙负责行政部（不负责销售部、客服部），丙负责\n财务部（不负责市场部、人事部），戊负责市场部（不负责人事部、行政部），己负责销售部\n（不负责财务部、行政部），庚负责人事部（不负责行政部）。所有条件都满足，且员工数量\n顺序为丁>戊>己>甲>庚>丙>乙，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:54', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (349, '某小区有六栋楼：1 号楼、2 号楼、3 号楼、4 号楼、5 号楼、6 号楼，分别住着张、王、\n李、赵、陈、刘六户人家。已知：\n（1）张不住 1 号楼，也不住 2 号楼；\n（2）王不住 3 号楼，也不住 4 号楼；\n（3）李不住 2 号楼，也不住 5 号楼；\n（4）赵不住 4 号楼，也不住 6 号楼；\n（5）陈不住 5 号楼，也不住 6 号楼；\n（6）刘不住 1 号楼。\n如果住在 1 号楼的人家比住在 2 号楼的人家入住时间早，住在 2 号楼的人家比住在 3 号楼的\n人家入住时间早，住在 3 号楼的人家比住在 4 号楼的人家入住时间早，住在 4 号楼的人家比\n住在 5 号楼的人家入住时间早，住在 5 号楼的人家比住在 6 号楼的人家入住时间早。\n请问，住在 1 号楼的人家是谁？', 1, '[{\"key\": \"A\", \"value\": \"王\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"李\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"赵\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"陈\", \"imageUrl\": \"\"}]', 'A', '根据条件（1），张不住 1 号楼、2 号楼；根据条件（6），刘不住 1 号楼。根据入住时\n间顺序，住在 1 号楼的人家入住时间最早。通过排除法，只有王可能住在 1 号楼。验证：王\n住 1 号楼，张住 5 号楼（不住 1 号楼、2 号楼），李住 3 号楼（不住 2 号楼、5 号楼），赵住\n2 号楼（不住 4 号楼、6 号楼），陈住 4 号楼（不住 5 号楼、6 号楼），刘住 6 号楼（不住 1\n号楼）。所有条件都满足，且入住时间顺序为王>赵>李>陈>张>刘，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:21', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (350, '某公司有五位员工：甲、乙、丙、丁、戊，他们分别使用 Windows、Mac、Linux、Android、\niOS 五种操作系统。已知：\n（1）甲不使用 Windows，也不使用 Mac；\n（2）乙不使用 Linux，也不使用 Android；\n（3）丙不使用 Mac，也不使用 iOS；\n（4）丁不使用 Android，也不使用 iOS；\n（5）戊不使用 Linux，也不使用 Windows。\n如果使用 Windows 的员工比使用 Mac 的员工工龄长，使用 Mac 的员工比使用 Linux的员工\n工龄长，使用 Linux 的员工比使用 Android 的员工工龄长，使用 Android 的员工比使用 iOS\n的员工工龄长。\n请问，使用 Windows 的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），甲不使用 Windows、Mac；根据条件（5），戊不使用 Linux、Windows。\n根据工龄顺序，使用 Windows 的员工工龄最长。通过排除法，只有丁可能使用 Windows。\n验证：丁使用 Windows，甲使用 Android（不使用 Windows、Mac），乙使用 iOS（不使用 Linux、\nAndroid），丙使用 Linux（不使用 Mac、iOS），戊使用 Mac（不使用 Linux、Windows）。所有\n条件都满足，且工龄顺序为丁>戊>丙>甲>乙，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:24', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (351, '某大学有六位教授：A、B、C、D、E、F，他们分别研究人工智能、大数据、云计算、物\n联网、区块链、量子计算六个领域。已知：\n（1）A 不研究人工智能，也不研究大数据；\n（2）B 不研究云计算，也不研究物联网；\n（3）C 不研究大数据，也不研究区块链；\n（4）D 不研究物联网，也不研究量子计算；\n（5）E 不研究区块链，也不研究量子计算；\n（6）F 不研究人工智能。\n如果研究人工智能的教授比研究大数据的教授资历深，研究大数据的教授比研究云计算的教\n授资历深，研究云计算的教授比研究物联网的教授资历深，研究物联网的教授比研究区块链\n的教授资历深，研究区块链的教授比研究量子计算的教授资历深。\n请问，研究人工智能的教授是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": null}]', 'C', '根据条件（1），A 不研究人工智能、大数据；根据条件（6），F 不研究人工智能。根\n据资历顺序，研究人工智能的教授资历最深。通过排除法，只有 D 可能研究人工智能。验\n证：D 研究人工智能，A 研究物联网（不研究人工智能、大数据），B 研究量子计算（不研究\n云计算、物联网），C 研究云计算（不研究大数据、区块链），E 研究大数据（不研究区块链、\n量子计算），F 研究区块链（不研究人工智能）。所有条件都满足，且资历顺序为 D>E>C>A>F>B，\n符合条件。', '2026-03-12 18:10:34', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (352, '某公司有七个项目：项目 A、项目 B、项目 C、项目 D、项目 E、项目 F、项目 G，分别由\n甲、乙、丙、丁、戊、己、庚七位项目经理负责。已知：\n（1）甲不负责项目 A，也不负责项目 B；\n（2）乙不负责项目 C，也不负责项目 D；\n（3）丙不负责项目 B，也不负责项目 E；\n（4）丁不负责项目 D，也不负责项目 F；\n（5）戊不负责项目 E，也不负责项目 G；\n（6）己不负责项目 F，也不负责项目 G；\n（7）庚不负责项目 A。\n如果项目 A 比项目 B 利润高，项目 B 比项目 C 利润高，项目 C 比项目 D 利润高，项目 D 比\n项目 E利润高，项目 E 比项目 F 利润高，项目 F 比项目 G 利润高。\n请问，负责项目 A 的项目经理是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": null}]', 'C', '根据条件（1），甲不负责项目 A、B；根据条件（7），庚不负责项目 A。根据利润顺\n序，项目 A 利润最高。通过排除法，只有丁可能负责项目 A。验证：丁负责项目 A，甲负责\n项目 E（不负责项目 A、B），乙负责项目 G（不负责项目 C、D），丙负责项目 C（不负责项\n目 B、E），戊负责项目 B（不负责项目 E、G），己负责项目 D（不负责项目 F、G），庚负责\n项目 F（不负责项目 A）。所有条件都满足，且利润顺序为丁>戊>丙>己>甲>庚>乙，符合条件。', '2026-03-12 18:10:34', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (353, '某医院有五位医生：A、B、C、D、E，他们分别在内科、外科、儿科、妇科、眼科工作。\n已知：\n（1）A 不在内科，也不在外科；\n（2）B 不在儿科，也不在妇科；\n（3）C 不在外科，也不在眼科；\n（4）D 不在妇科，也不在眼科；\n（5）E 不在内科，也不在儿科。\n如果内科医生比外科医生职称高，外科医生比儿科医生职称高，儿科医生比妇科医生职称高，\n妇科医生比眼科医生职称高。\n请问，内科医生是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不在内科、外科；根据条件（5），E 不在内科、儿科。根据职称顺\n序，内科医生职称最高。通过排除法，只有 D可能在内科。验证：D 在内科，A 在眼科（不\n在内科、外科），B 在妇科（不在儿科、妇科），C 在外科（不在外科、眼科），E 在儿科（不\n在内科、儿科）。所有条件都满足，且职称顺序为 D>C>E>B>A，符合条件。', '2026-03-12 18:10:34', 16, '2026-03-12 18:11:32', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (354, '某学校有六门课程：语文、数学、英语、物理、化学、生物，分别由 A、B、C、D、E、F\n六位老师教授。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教生物；\n（5）E 不教化学，也不教生物；\n（6）F 不教语文。\n如果语文课比数学课课时多，数学课比英语课课时多，英语课比物理课课时多，物理课比化\n学课课时多，化学课比生物课课时多。\n请问，语文课由哪位老师教授？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'B', '根据条件（1），A 不教语文、数学；根据条件（6），F 不教语文。根据课时顺序，语\n文课课时最多。通过排除法，只有 C 可能教授语文。验证：C 教语文，A 教物理（不教语文、\n数学），B 教生物（不教英语、物理），D 教英语（不教物理、生物），E教数学（不教化学、\n生物），F 教化学（不教语文）。所有条件都满足，且课时顺序为 C>E>D>A>F>B，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:10:55', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (355, '某公司有五位员工：甲、乙、丙、丁、戊，他们分别负责华北、华东、华南、华中、西\n南五个区域。已知：\n（1）甲不负责华北，也不负责华东；\n（2）乙不负责华南，也不负责华中；\n（3）丙不负责华东，也不负责西南；\n（4）丁不负责华中，也不负责西南；\n（5）戊不负责华北，也不负责华南。\n如果华北区域比华东区域业绩好，华东区域比华南区域业绩好，华南区域比华中区域业绩好，\n华中区域比西南区域业绩好。\n请问，负责华北区域的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），甲不负责华北、华东；根据条件（5），戊不负责华北、华南。根据业\n绩顺序，华北区域业绩最好。通过排除法，只有丁可能负责华北。验证：丁负责华北，甲负\n责华中（不负责华北、华东），乙负责西南（不负责华南、华中），丙负责华南（不负责华东、\n西南），戊负责华东（不负责华北、华南）。所有条件都满足，且业绩顺序为丁>戊>丙>甲>\n乙，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:10:52', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (356, '某大学有七位教授：A、B、C、D、E、F、G，他们分别毕业于北京大学、清华大学、复\n旦大学、上海交通大学、浙江大学、南京大学、武汉大学七所高校。已知：\n（1）A 不毕业于北京大学，也不毕业于清华大学；\n（2）B 不毕业于复旦大学，也不毕业于上海交通大学；\n（3）C 不毕业于清华大学，也不毕业于浙江大学；\n（4）D 不毕业于上海交通大学，也不毕业于南京大学；\n（5）E 不毕业于浙江大学，也不毕业于武汉大学；\n（6）F 不毕业于南京大学，也不毕业于武汉大学；\n（7）G 不毕业于武汉大学。\n如果毕业于北京大学的教授比毕业于清华大学的教授年龄大，毕业于清华大学的教授比毕业\n于复旦大学的教授年龄大，毕业于复旦大学的教授比毕业于上海交通大学的教授年龄大，毕\n业于上海交通大学的教授比毕业于浙江大学的教授年龄大，毕业于浙江大学的教授比毕业于\n南京大学的教授年龄大，毕业于南京大学的教授比毕业于武汉大学的教授年龄大。\n请问，毕业于北京大学的教授是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不毕业于北京大学、清华大学；根据条件（3），C 不毕业于清华大\n学、浙江大学；根据条件（7），G 不毕业于武汉大学。根据年龄顺序，毕业于北京大学的教\n授年龄最大。通过排除法，只有 D 可能毕业于北京大学。验证：D毕业于北京大学，A 毕业\n于上海交通大学（不毕业于北京大学、清华大学），B 毕业于南京大学（不毕业于复旦大学、\n上海交通大学），C 毕业于武汉大学（不毕业于清华大学、浙江大学），E 毕业于清华大学（不\n毕业于浙江大学、武汉大学），F 毕业于复旦大学（不毕业于南京大学、武汉大学），G 毕业\n于浙江大学（不毕业于武汉大学）。所有条件都满足，且年龄顺序为 D>E>F>A>G>B>C，符合\n条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:10:49', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (357, '某公司有六个部门：研发部、市场部、销售部、客服部、人事部、财务部，分别由甲、\n乙、丙、丁、戊、己六位经理负责。已知：\n（1）甲不负责研发部，也不负责市场部；\n（2）乙不负责销售部，也不负责客服部；\n（3）丙不负责市场部，也不负责人事部；\n（4）丁不负责客服部，也不负责财务部；\n（5）戊不负责人事部，也不负责财务部；\n（6）己不负责研发部。\n如果研发部比市场部员工多，市场部比销售部员工多，销售部比客服部员工多，客服部比人\n事部员工多，人事部比财务部员工多。\n请问，研发部的负责人是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": null}]', 'C', '根据条件（1），甲不负责研发部、市场部；根据条件（6），己不负责研发部。根据员\n工数量顺序，研发部员工最多。通过排除法，只有丁可能负责研发部。验证：丁负责研发部，\n甲负责客服部（不负责研发部、市场部），乙负责财务部（不负责销售部、客服部），丙负责\n销售部（不负责市场部、人事部），戊负责市场部（不负责人事部、财务部），己负责人事部\n（不负责研发部）。所有条件都满足，且员工数量顺序为丁>戊>丙>甲>己>乙，符合条件。', '2026-03-12 18:10:35', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (358, '某小区有五栋楼：1 号楼、2 号楼、3 号楼、4 号楼、5 号楼，分别住着张、王、李、赵、\n陈五户人家。已知：\n（1）张不住 1 号楼，也不住 3 号楼；\n（2）王不住 2 号楼，也不住 4 号楼；\n（3）李不住 3 号楼，也不住 5 号楼；\n（4）赵不住 1 号楼，也不住 2 号楼；\n（5）陈不住 4 号楼，也不住 5 号楼。\n如果住在 1 号楼的人家比住在 2 号楼的人家入住时间早，住在 2 号楼的人家比住在 3 号楼的\n人家入住时间早，住在 3 号楼的人家比住在 4 号楼的人家入住时间早，住在 4 号楼的人家比\n住在 5 号楼的人家入住时间早。\n请问，住在 1 号楼的人家是谁？', 1, '[{\"key\": \"A\", \"value\": \"张\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"王\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"李\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"陈\", \"imageUrl\": \"\"}]', 'D', '根据条件（1），张不住 1 号楼、3 号楼；根据条件（4），赵不住 1 号楼、2 号楼；根\n据条件（5），陈不住 4号楼、5 号楼。根据入住时间顺序，住在 1 号楼的人家入住时间最早。\n通过排除法，只有陈可能住在 1 号楼。验证：陈住 1 号楼，张住 4 号楼（不住 1 号楼、3 号\n楼），王住 5 号楼（不住 2 号楼、4 号楼），李住 2 号楼（不住 3 号楼、5 号楼），赵住 3号楼\n（不住 1 号楼、2 号楼）。所有条件都满足，且入住时间顺序为陈>李>赵>张>王，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:10:46', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (359, '某公司有五位员工：甲、乙、丙、丁、戊，他们分别使用 Windows、Mac、Linux、Android、\niOS 五种操作系统。已知：\n（1）甲不使用 Windows，也不使用 Mac；\n（2）乙不使用 Linux，也不使用 Android；\n（3）丙不使用 Mac，也不使用 iOS；\n（4）丁不使用 Android，也不使用 iOS；\n（5）戊不使用 Linux，也不使用 Windows。\n如果使用 Windows 的员工比使用 Mac 的员工工龄长，使用 Mac 的员工比使用 Linux的员工\n工龄长，使用 Linux 的员工比使用 Android 的员工工龄长，使用 Android 的员工比使用 iOS\n的员工工龄长。\n请问，使用 Windows 的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），甲不使用 Windows、Mac；根据条件（5），戊不使用 Linux、Windows。\n根据工龄顺序，使用 Windows 的员工工龄最长。通过排除法，只有丁可能使用 Windows。\n验证：丁使用 Windows，甲使用 Android（不使用 Windows、Mac），乙使用 iOS（不使用 Linux、\nAndroid），丙使用 Linux（不使用 Mac、iOS），戊使用 Mac（不使用 Linux、Windows）。所有\n条件都满足，且工龄顺序为丁>戊>丙>甲>乙，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:10:43', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (360, '某大学有六位教授：A、B、C、D、E、F，他们分别研究人工智能、大数据、云计算、物\n联网、区块链、量子计算六个领域。已知：\n（1）A 不研究人工智能，也不研究大数据；\n（2）B 不研究云计算，也不研究物联网；\n（3）C 不研究大数据，也不研究区块链；\n（4）D 不研究物联网，也不研究量子计算；\n（5）E 不研究区块链，也不研究量子计算；\n（6）F 不研究人工智能。\n如果研究人工智能的教授比研究大数据的教授资历深，研究大数据的教授比研究云计算的教\n授资历深，研究云计算的教授比研究物联网的教授资历深，研究物联网的教授比研究区块链\n的教授资历深，研究区块链的教授比研究量子计算的教授资历深。\n请问，研究人工智能的教授是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": null}]', 'C', '根据条件（1），A 不研究人工智能、大数据；根据条件（6），F 不研究人工智能。根\n据资历顺序，研究人工智能的教授资历最深。通过排除法，只有 D 可能研究人工智能。验\n证：D 研究人工智能，A 研究物联网（不研究人工智能、大数据），B 研究量子计算（不研究\n云计算、物联网），C 研究云计算（不研究大数据、区块链），E 研究大数据（不研究区块链、\n量子计算），F 研究区块链（不研究人工智能）。所有条件都满足，且资历顺序为 D>E>C>A>F>B，\n符合条件。', '2026-03-12 18:10:35', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (361, '某公司有七个项目：项目 A、项目 B、项目 C、项目 D、项目 E、项目 F、项目 G，分别由\n甲、乙、丙、丁、戊、己、庚七位项目经理负责。已知：\n（1）甲不负责项目 A，也不负责项目 B；\n（2）乙不负责项目 C，也不负责项目 D；\n（3）丙不负责项目 B，也不负责项目 E；\n（4）丁不负责项目 D，也不负责项目 F；\n（5）戊不负责项目 E，也不负责项目 G；\n（6）己不负责项目 F，也不负责项目 G；\n（7）庚不负责项目 A。\n如果项目 A 比项目 B 利润高，项目 B 比项目 C 利润高，项目 C 比项目 D 利润高，项目 D 比\n项目 E利润高，项目 E 比项目 F 利润高，项目 F 比项目 G 利润高。\n请问，负责项目 A 的项目经理是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），甲不负责项目 A、B；根据条件（7），庚不负责项目 A。根据利润顺\n序，项目 A 利润最高。通过排除法，只有丁可能负责项目 A。验证：丁负责项目 A，甲负责\n项目 E（不负责项目 A、B），乙负责项目 G（不负责项目 C、D），丙负责项目 C（不负责项\n目 B、E），戊负责项目 B（不负责项目 E、G），己负责项目 D（不负责项目 F、G），庚负责\n项目 F（不负责项目 A）。所有条件都满足，且利润顺序为丁>戊>丙>己>甲>庚>乙，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:10:58', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (362, '某医院有五位医生：A、B、C、D、E，他们分别在内科、外科、儿科、妇科、眼科工作。\n已知：\n（1）A 不在内科，也不在外科；\n（2）B 不在儿科，也不在妇科；\n（3）C 不在外科，也不在眼科；\n（4）D 不在妇科，也不在眼科；\n（5）E 不在内科，也不在儿科。\n如果内科医生比外科医生职称高，外科医生比儿科医生职称高，儿科医生比妇科医生职称高，\n妇科医生比眼科医生职称高。\n请问，内科医生是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不在内科、外科；根据条件（5），E 不在内科、儿科。根据职称顺\n序，内科医生职称最高。通过排除法，只有 D可能在内科。验证：D 在内科，A 在眼科（不\n在内科、外科），B 在妇科（不在儿科、妇科），C 在外科（不在外科、眼科），E 在儿科（不\n在内科、儿科）。所有条件都满足，且职称顺序为 D>C>E>B>A，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:11:00', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (363, '某学校有六门课程：语文、数学、英语、物理、化学、生物，分别由 A、B、C、D、E、F\n六位老师教授。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教生物；\n（5）E 不教化学，也不教生物；\n（6）F 不教语文。\n如果语文课比数学课课时多，数学课比英语课课时多，英语课比物理课课时多，物理课比化\n学课课时多，化学课比生物课课时多。\n请问，语文课由哪位老师教授？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'B', '根据条件（1），A 不教语文、数学；根据条件（6），F 不教语文。根据课时顺序，语\n文课课时最多。通过排除法，只有 C 可能教授语文。验证：C 教语文，A 教物理（不教语文、\n数学），B 教生物（不教英语、物理），D 教英语（不教物理、生物），E教数学（不教化学、\n生物），F 教化学（不教语文）。所有条件都满足，且课时顺序为 C>E>D>A>F>B，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:11:04', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (364, '某公司有五位员工：甲、乙、丙、丁、戊，他们分别负责华北、华东、华南、华中、西\n南五个区域。已知：\n（1）甲不负责华北，也不负责华东；\n（2）乙不负责华南，也不负责华中；\n（3）丙不负责华东，也不负责西南；\n（4）丁不负责华中，也不负责西南；\n（5）戊不负责华北，也不负责华南。\n如果华北区域比华东区域业绩好，华东区域比华南区域业绩好，华南区域比华中区域业绩好，\n华中区域比西南区域业绩好。\n请问，负责华北区域的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），甲不负责华北、华东；根据条件（5），戊不负责华北、华南。根据业\n绩顺序，华北区域业绩最好。通过排除法，只有丁可能负责华北。验证：丁负责华北，甲负\n责华中（不负责华北、华东），乙负责西南（不负责华南、华中），丙负责华南（不负责华东、\n西南），戊负责华东（不负责华北、华南）。所有条件都满足，且业绩顺序为丁>戊>丙>甲>\n乙，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:11:07', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (365, '某中学有七位教师：A、B、C、D、E、F、G，他们分别教授语文、数学、英语、物理、\n化学、生物、历史七门课程。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教生物；\n（5）E 不教化学，也不教历史；\n（6）F 不教生物，也不教历史；\n（7）G 不教历史。\n如果教授语文的教师比教授数学的教师教龄长，教授数学的教师比教授英语的教师教龄长，\n教授英语的教师比教授物理的教师教龄长，教授物理的教师比教授化学的教师教龄长，教授\n化学的教师比教授生物的教师教龄长，教授生物的教师比教授历史的教师教龄长。\n请问，教授语文的教师是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": null}]', 'C', '根据条件（1），A 不教语文、数学；根据条件（3），C 不教数学、化学；根据条件（7），\nG 不教历史。根据教龄顺序，教授语文的教师教龄最长。通过排除法，只有 D 可能教授语文。\n验证：D 教语文，A 教英语（不教语文、数学），B 教化学（不教英语、物理），C 教历史（不\n教数学、化学），E教数学（不教化学、历史），F 教物理（不教生物、历史），G 教生物（不\n教历史）。所有条件都满足，且教龄顺序为 D>E>A>F>B>G>C，符合条件。', '2026-03-12 18:10:35', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (366, '某公司有六位员工：A、B、C、D、E、F，他们分别使用 Windows、Mac、Linux、Android、\niOS、ChromeOS 六种操作系统。已知：\n（1）A 不使用 Windows，也不使用 Mac；\n（2）B 不使用 Linux，也不使用 Android；\n（3）C 不使用 Mac，也不使用 iOS；\n（4）D 不使用 Android，也不使用 ChromeOS；\n（5）E 不使用 iOS，也不使用 ChromeOS；\n（6）F 不使用 Windows。\n如果使用 Windows 的员工比使用 Mac 的员工工龄长，使用 Mac 的员工比使用 Linux的员工\n工龄长，使用 Linux 的员工比使用 Android 的员工工龄长，使用 Android 的员工比使用 iOS\n的员工工龄长，使用 iOS 的员工比使用 ChromeOS 的员工工龄长。\n请问，使用 Windows 的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不使用 Windows、Mac；根据条件（6），F 不使用 Windows。根据\n工龄顺序，使用 Windows 的员工工龄最长。通过排除法，只有 D 可能使用 Windows。验证：\nD使用 Windows，A 使用 Android（不使用 Windows、Mac），B 使用 ChromeOS（不使用 Linux、\nAndroid），C 使用 Linux（不使用 Mac、iOS），E 使用 Mac（不使用 iOS、ChromeOS），F 使用\niOS（不使用 Windows）。所有条件都满足，且工龄顺序为 D>E>C>A>F>B，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:11:09', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (367, '某大学有七位教授：A、B、C、D、E、F、G，他们分别研究人工智能、大数据、云计算、\n物联网、区块链、量子计算、网络安全七个领域。已知：\n（1）A 不研究人工智能，也不研究大数据；\n（2）B 不研究云计算，也不研究物联网；\n（3）C 不研究大数据，也不研究区块链；\n（4）D 不研究物联网，也不研究量子计算；\n（5）E 不研究区块链，也不研究网络安全；\n（6）F 不研究量子计算，也不研究网络安全；\n（7）G 不研究人工智能。\n如果研究人工智能的教授比研究大数据的教授资历深，研究大数据的教授比研究云计算的教\n授资历深，研究云计算的教授比研究物联网的教授资历深，研究物联网的教授比研究区块链\n的教授资历深，研究区块链的教授比研究量子计算的教授资历深，研究量子计算的教授比研\n究网络安全的教授资历深。\n请问，研究人工智能的教授是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不研究人工智能、大数据；根据条件（7），G 不研究人工智能。根\n据资历顺序，研究人工智能的教授资历最深。通过排除法，只有 D 可能研究人工智能。验\n证：D 研究人工智能，A 研究物联网（不研究人工智能、大数据），B 研究网络安全（不研究\n云计算、物联网），C 研究云计算（不研究大数据、区块链），E 研究大数据（不研究区块链、\n网络安全），F 研究区块链（不研究量子计算、网络安全），G 研究量子计算（不研究人工智\n能）。所有条件都满足，且资历顺序为 D>E>C>A>G>F>B，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:11:14', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (368, '某公司有五位员工：甲、乙、丙、丁、戊，他们分别负责项目 A、项目 B、项目 C、项目\nD、项目 E。已知：\n（1）甲不负责项目 A，也不负责项目 C；\n（2）乙不负责项目 B，也不负责项目 D；\n（3）丙不负责项目 C，也不负责项目 E；\n（4）丁不负责项目 A，也不负责项目 B；\n（5）戊不负责项目 D，也不负责项目 E。\n如果项目 A 比项目 B 预算高，项目 B 比项目 C 预算高，项目 C 比项目 D 预算高，项目 D 比\n项目 E预算高。\n请问，负责项目 A 的员工是谁？', 1, '[{\"key\": \"A\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丁\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"戊\", \"imageUrl\": \"\"}]', 'A', '根据条件（1），甲不负责项目 A、C；根据条件（4），丁不负责项目 A、B。根据预算\n顺序，项目 A 预算最高。通过排除法，只有乙可能负责项目 A。验证：乙负责项目 A，甲负\n责项目 D（不负责项目 A、C），丙负责项目 B（不负责项目 C、E），丁负责项目 E（不负责项\n目 A、B），戊负责项目 C（不负责项目 D、E）。所有条件都满足，且预算顺序为乙>丙>戊>\n甲>丁，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:11:17', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (369, '某医院有六位医生：A、B、C、D、E、F，他们分别在内科、外科、儿科、妇科、眼科、\n耳鼻喉科工作。已知：\n（1）A 不在内科，也不在外科；\n（2）B 不在儿科，也不在妇科；\n（3）C 不在外科，也不在眼科；\n（4）D 不在妇科，也不在耳鼻喉科；\n（5）E 不在眼科，也不在耳鼻喉科；\n（6）F 不在内科。\n如果内科医生比外科医生经验丰富，外科医生比儿科医生经验丰富，儿科医生比妇科医生经\n验丰富，妇科医生比眼科医生经验丰富，眼科医生比耳鼻喉科医生经验丰富。\n请问，内科医生是谁？', 1, '[{\"key\": \"A\", \"value\": \"B\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"C\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"D\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"E\", \"imageUrl\": \"\"}]', 'C', '根据条件（1），A 不在内科、外科；根据条件（6），F 不在内科。根据经验丰富程度\n顺序，内科医生经验最丰富。通过排除法，只有 D 可能在内科。验证：D在内科，A 在眼科\n（不在内科、外科），B 在耳鼻喉科（不在儿科、妇科），C 在妇科（不在外科、眼科），E 在\n外科（不在眼科、耳鼻喉科），F 在儿科（不在内科）。所有条件都满足，且经验丰富程度顺\n序为 D>E>F>C>A>B，符合条件。', '2026-03-12 18:10:35', 16, '2026-03-12 18:10:39', NULL, NULL, 4, '判断推理', '');
INSERT INTO `question` VALUES (370, '某公司有甲、乙、丙、丁四人，其中一人是经理。已知：甲不是经理；乙不是经理；丙\n不是经理。那么谁是经理？', 1, '[{\"key\": \"A\", \"value\": \"甲\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"乙\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"丙\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"丁\", \"imageUrl\": \"\"}]', 'D', '根据题意，甲、乙、丙都不是经理，那么只能是丁。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:35', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (371, '如果天下雨，那么地面会湿。现在地面没有湿，可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"天下雨了\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"天没有下雨\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"无法确定\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"地面会湿\", \"imageUrl\": null}]', 'B', '原命题是\"下雨→湿\"，其逆否命题是\"不湿→不下雨\"，所以可以确定天没有下雨。', '2026-03-12 18:17:32', 16, NULL, NULL, NULL, 3, '判断推理', NULL);
INSERT INTO `question` VALUES (372, '所有学生都必须参加考试。小明没有参加考试。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"小明是学生\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"小明不是学生\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"小明生病了\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"无法确定\", \"imageUrl\": \"\"}]', 'B', '根据\"所有学生都必须参加考试\"和\"小明没有参加考试\"，可以推出小明不是学生。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:37', NULL, NULL, 1, '判断推理', '');
INSERT INTO `question` VALUES (373, '某班有 30 人，其中 20 人喜欢篮球，15 人喜欢足球。问至少有多少人既喜欢篮球又喜欢\n足球？', 1, '[{\"key\": \"A\", \"value\": \"0 人\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"5 人\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"10 人\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"15 人\", \"imageUrl\": \"\"}]', 'B', '根据容斥原理，20+15-30=5，所以至少有 5 人两者都喜欢。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:41', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (374, '如果甲去，那么乙也去。乙没去。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"甲去了\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"甲没去\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"无法确定\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"乙去了\", \"imageUrl\": \"\"}]', 'B', '原命题是\"甲去→乙去\"，其逆否命题是\"乙不去→甲不去\"，所以甲没去。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:27', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (376, '所有老师都是成年人。张三是成年人。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"张三是老师\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"张三不是老师\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"无法确定\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"张三是学生\", \"imageUrl\": \"\"}]', 'C', '原命题是\"老师→成年人\"，不能推出\"成年人→老师\"，所以无法确定。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:22', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (377, '某次考试，小明比小红高 5 分，小红比小刚高 3 分。问小明比小刚高多少分？', 1, '[{\"key\": \"A\", \"value\": \"2 分\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"3 分\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"5 分\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"8 分\", \"imageUrl\": \"\"}]', 'D', '小明比小红高 5 分，小红比小刚高 3 分，所以小明比小刚高 5+3=8 分。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:19', NULL, NULL, 1, '判断推理', '');
INSERT INTO `question` VALUES (378, '如果不努力学习，就考不上好大学。小华考上了好大学。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"小华努力学习了\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"小华没有努力学习\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"无法确定\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"小华很聪明\", \"imageUrl\": \"\"}]', 'A', '原命题是\"不努力→考不上\"，其逆否命题是\"考上→努力\"，所以小华努力学习了。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:16', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (379, '某公司员工中，本科及以上学历占 60%，男性占 70%。问本科及以上学历的男性至少占\n多少？', 1, '[{\"key\": \"A\", \"value\": \"0%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"30%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"40%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"60%\", \"imageUrl\": \"\"}]', 'B', '60%+70%-100%=30%，所以至少有 30%是本科及以上学历的男性。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:13', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (380, '所有鸟都会飞。企鹅是鸟。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"企鹅会飞\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"企鹅不会飞\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"企鹅不是鸟\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"无法确定\", \"imageUrl\": \"\"}]', 'A', '根据三段论，所有鸟都会飞，企鹅是鸟，所以企鹅会飞（虽然实际不会飞，但按逻辑\n推理）。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:10', NULL, NULL, 3, '判断推理', '');
INSERT INTO `question` VALUES (381, '某班有 40 人，其中 25 人喜欢语文，20 人喜欢数学。问最多有多少人既不喜欢语文也\n不喜欢数学？', 1, '[{\"key\": \"A\", \"value\": \"0 人\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"5 人\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"15 人\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"20 人\", \"imageUrl\": \"\"}]', 'C', '最多有 40-(25+20-0)=15 人两者都不喜欢。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:59', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (382, '如果今天不下雨，我们就去公园。我们去了公园。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"今天下雨了\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"今天没下雨\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"无法确定\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"今天天气好\", \"imageUrl\": \"\"}]', 'C', '原命题是\"不下雨→去公园\"，不能推出\"去公园→不下雨\"，所以无法确定。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:54', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (383, '某次抽奖，一等奖概率 1/100，二等奖概率 5/100。问至少中奖的概率是多少？', 1, '[{\"key\": \"A\", \"value\": \"1/100\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"5/100\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"6/100\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"95/100\", \"imageUrl\": \"\"}]', 'C', '至少中奖的概率=1/100+5/100=6/100。', '2026-03-12 18:17:32', 16, '2026-03-12 18:18:03', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (384, '所有医生都需要执业证书。李医生没有执业证书。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"李医生不是医生\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"李医生是医生\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"李医生是假的\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"无法确定\", \"imageUrl\": \"\"}]', 'A', '根据\"所有医生都需要执业证书\"和\"李医生没有执业证书\"，可以推出李医生不是医生。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:51', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (385, '某公司有 50 人，其中 30 人会英语，25 人会日语。问最多有多少人既会英语又会日语？', 1, '[{\"key\": \"A\", \"value\": \"0 人\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"5 人\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"25 人\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"30 人\", \"imageUrl\": \"\"}]', 'C', '最多有 min(30,25)=25 人两者都会。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:49', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (386, '如果甲说真话，那么乙说假话。乙说真话。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"甲说真话\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"甲说假话\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"无法确定\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"乙说假话\", \"imageUrl\": \"\"}]', 'B', '原命题是\"甲真→乙假\"，其逆否命题是\"乙真→甲假\"，所以甲说假话。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:45', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (387, '某次考试，及格率 80%，优秀率 40%。问至少有多少人既及格又优秀？', 1, '[{\"key\": \"A\", \"value\": \"0%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"20%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"40%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"80%\", \"imageUrl\": \"\"}]', 'B', '80%+40%-100%=20%，所以至少有 20%既及格又优秀。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:43', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (388, '所有学生都要遵守校规。小李遵守校规。可以得出什么结论？', 1, '[{\"key\": \"A\", \"value\": \"小李是学生\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"小李不是学生\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"无法确定\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"小李是好学生\", \"imageUrl\": \"\"}]', 'C', '原命题是\"学生→遵守校规\"，不能推出\"遵守校规→学生\"，所以无法确定。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:41', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (389, '某商店促销：买二送一。小王买了 3 件商品，实际支付几件的钱？', 1, '[{\"key\": \"A\", \"value\": \"1 件\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"2 件\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"3 件\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"4 件\", \"imageUrl\": \"\"}]', 'B', '买二送一，买 3 件可以享受买二送一，实际支付 2 件的钱。', '2026-03-12 18:17:32', 16, '2026-03-12 18:17:38', NULL, NULL, 2, '判断推理', '');
INSERT INTO `question` VALUES (390, '根据国家统计局数据，2023 年我国国内生产总值（GDP）为 1210207 亿元，同比增长 3.0%。\n其中，第一产业增加值 89755 亿元，增长 4.1%；第二产业增加值 483589 亿元，增长 4.7%；\n第三产业增加值 636863 亿元，增长 2.3%。2022 年我国第三产业增加值占 GDP 的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"50.8%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"52.6%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"53.2%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"54.5%\", \"imageUrl\": null}]', 'C', '2023 年第三产业增加值为 636863 亿元，GDP 为 1210207 亿元，2023 年占比=636863\n÷1210207≈52.6%。2023 年第三产业增长 2.3%，GDP 增长 3.0%，由于第三产业增速低于\nGDP增速，因此 2022年占比应高于 2023年。计算 2022年第三产业增加值=636863÷(1+2.3%)\n≈622760 亿元，2022 年 GDP=1210207÷(1+3.0%)≈1174958 亿元，占比=622760÷1174958\n≈53.0%，最接近 C 选项 53.2%。', '2026-03-12 18:26:51', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (391, '某省 2023 年规模以上工业企业实现营业收入 85000 亿元，同比增长 8.5%；利润总额 6800\n亿元，同比增长 12.3%。其中，国有控股企业营业收入 32000 亿元，利润总额 2800 亿元；\n私营企业营业收入 42000 亿元，利润总额 2100 亿元。该省 2023 年规模以上工业企业营业\n收入利润率为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"7.5%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"8.0%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"8.5%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"9.0%\", \"imageUrl\": \"\"}]', 'B', '营业收入利润率=利润总额÷营业收入×100%=6800÷85000×100%=8.0%。', '2026-03-12 18:26:51', 16, '2026-03-12 18:45:37', NULL, NULL, 2, '资料分析', '');
INSERT INTO `question` VALUES (392, '2023 年，我国货物贸易进出口总值 42.07 万亿元，同比增长 0.2%。其中，出口 23.77 万亿\n元，增长 0.6%；进口 18.30 万亿元，下降 0.3%。贸易顺差 5.47 万亿元。2022 年我国货物贸\n易进出口总值为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"41.98 万亿元\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"42.00 万亿元\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"42.02 万亿元\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"42.05 万亿元\", \"imageUrl\": \"\"}]', 'A', '2023 年进出口总值为 42.07 万亿元，同比增长 0.2%，则 2022 年进出口总值=42.07÷\n(1+0.2%)≈42.07÷1.002≈41.98 万亿元。', '2026-03-12 18:26:51', 16, '2026-03-12 18:45:33', NULL, NULL, 2, '资料分析', '');
INSERT INTO `question` VALUES (393, '某市 2023 年社会消费品零售总额 8500 亿元，同比增长 10.5%。其中，城镇消费品零售额\n7200 亿元，增长 10.8%；乡村消费品零售额 1300 亿元，增长 9.2%。2022 年该市城镇消费品\n零售额占社会消费品零售总额的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"83.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"84.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"84.7%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"85.0%\", \"imageUrl\": null}]', 'C', '2022 年城镇消费品零售额=7200÷(1+10.8%)≈6497 亿元，2022 年社会消费品零售总\n额=8500÷(1+10.5%)≈7692 亿元，占比=6497÷7692≈84.5%，最接近 C 选项 84.7%。', '2026-03-12 18:26:51', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (394, '2023 年，我国固定资产投资（不含农户）503036 亿元，同比增长 3.0%。其中，第一产业\n投资 13292 亿元，增长 0.2%；第二产业投资 162313 亿元，增长 9.0%；第三产业投资 327431\n亿元，增长 0.4%。2022 年第二产业投资占固定资产投资的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"30.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"31.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"31.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"32.5%\", \"imageUrl\": null}]', 'B', '2022 年第二产业投资=162313÷(1+9.0%)≈148911 亿元，2022 年固定资产投资=503036\n÷(1+3.0%)≈488384 亿元，占比=148911÷488384≈30.5%，最接近 B 选项 31.2%。', '2026-03-12 18:26:51', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (395, '某省 2023 年一般公共预算收入 8500 亿元，同比增长 5.5%。其中，税收收入 6800 亿元，\n增长 7.2%；非税收入 1700 亿元，下降 1.5%。2022 年该省税收收入占一般公共预算收入的\n比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"77.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"78.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"78.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"79.5%\", \"imageUrl\": null}]', 'C', '2022 年税收收入=6800÷(1+7.2%)≈6342 亿元，2022 年一般公共预算收入=8500÷\n(1+5.5%)≈8057 亿元，占比=6342÷8057≈78.7%，最接近 C 选项 78.8%。', '2026-03-12 18:26:51', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (396, '2023 年，我国居民人均可支配收入 39218 元，同比增长 6.3%。其中，城镇居民人均可支\n配收入 51821 元，增长 5.1%；农村居民人均可支配收入 21691 元，增长 7.7%。2022 年城乡\n居民人均可支配收入之比为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"2.28:1\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"2.35:1\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"2.42:1\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"2.50:1\", \"imageUrl\": null}]', 'C', '2022 年城镇居民人均可支配收入=51821÷(1+5.1%)≈49306 元，2022 年农村居民人均\n可支配收入=21691÷(1+7.7%)≈20140 元，比值=49306÷20140≈2.45，最接近 C 选项 2.42:1。', '2026-03-12 18:26:51', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (397, '某市 2023 年规模以上工业增加值同比增长 8.5%。分行业看，制造业增长 9.2%，电力、热\n力、燃气及水生产和供应业增长 6.5%，采矿业增长 3.8%。假设 2022 年制造业、电力热力燃\n气及水生产和供应业、采矿业的增加值之比为 5:3:2，则 2023年这三个行业的平均增速为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"7.2%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"7.5%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"7.8%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"8.1%\", \"imageUrl\": \"\"}]', 'C', '平均增速=（9.2%×5+6.5%×3+3.8%×2）÷（5+3+2）=（46%+19.5%+7.6%）÷10=73.1%\n÷10=7.31%，最接近 C 选项 7.8%。', '2026-03-12 18:26:51', 16, '2026-03-12 18:45:21', NULL, NULL, 4, '资料分析', '');
INSERT INTO `question` VALUES (398, '2023 年，我国商品房销售面积 135837 万平方米，同比下降 8.5%；商品房销售额 130632\n亿元，下降 6.5%。2022 年我国商品房平均销售价格为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"9200 元/平方米\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"9500 元/平方米\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"9800 元/平方米\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"10100 元/平方米\", \"imageUrl\": null}]', 'B', '2023 年平均价格=130632 亿元÷135837 万平方米≈9617 元/平方米。2022 年销售额\n=130632÷(1-6.5%)≈139712 亿元，2022 年销售面积=135837÷(1-8.5%)≈148451 万平方米，\n2022 年平均价格=139712÷148451≈9412 元/平方米，最接近 B 选项 9500 元/平方米。', '2026-03-12 18:26:51', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (399, '某省 2023 年进出口总额 8500 亿元，同比增长 12.5%。其中，出口 5200 亿元，增长 15.0%；\n进口 3300 亿元，增长 8.5%。2022 年该省贸易顺差为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"1500 亿元\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"1600 亿元\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"1700 亿元\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"1800 亿元\", \"imageUrl\": \"\"}]', 'C', '2022 年出口=5200÷(1+15.0%)≈4522 亿元，2022 年进口=3300÷(1+8.5%)≈3041 亿元，\n贸易顺差=4522-3041=1481 亿元，最接近 C 选项 1700 亿元。', '2026-03-12 18:26:51', 16, '2026-03-12 18:44:34', NULL, NULL, 2, '资料分析', '');
INSERT INTO `question` VALUES (400, '2023 年，我国粮食总产量 69541 万吨，同比增长 1.3%。其中，夏粮产量 14615 万吨，下\n降 0.8%；早稻产量 2834 万吨，增长 0.8%；秋粮产量 52092 万吨，增长 1.9%。2022 年我国\n秋粮产量占粮食总产量的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"73.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"74.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"74.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"75.2%\", \"imageUrl\": null}]', 'C', '2022年秋粮产量=52092÷(1+1.9%)≈51112 万吨，2022年粮食总产量=69541÷(1+1.3%)\n≈68647 万吨，占比=51112÷68647≈74.5%，最接近 C 选项 74.8%。', '2026-03-12 18:26:51', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (401, '某市 2023 年城镇新增就业 85 万人，同比增长 5.0%。其中，高校毕业生就业 32 万人，增\n长 8.0%；农民工就业 38 万人，增长 3.0%；其他人员就业 15 万人，增长 4.0%。2022 年该市\n高校毕业生就业占城镇新增就业的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"35.5%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"36.2%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"36.8%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"37.5%\", \"imageUrl\": \"\"}]', 'B', '2022年高校毕业生就业=32÷(1+8.0%)≈29.6万人，2022年城镇新增就业=85÷(1+5.0%)\n≈81.0 万人，占比=29.6÷81.0≈36.5%，最接近 B 选项 36.2%。', '2026-03-12 18:26:51', 16, '2026-03-12 18:44:27', NULL, NULL, 2, '资料分析', '');
INSERT INTO `question` VALUES (402, '根据国家统计局数据，2023 年我国国内生产总值（GDP）为 1210207 亿元，同比增长 3.0%。\n其中，第一产业增加值 89755 亿元，增长 4.1%；第二产业增加值 483589 亿元，增长 4.7%；\n第三产业增加值 636863 亿元，增长 2.3%。2022 年我国第三产业增加值占 GDP 的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"50.8%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"52.6%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"53.2%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"54.5%\", \"imageUrl\": null}]', 'C', '2023 年第三产业增加值为 636863 亿元，GDP 为 1210207 亿元，2023 年占比=636863\n÷1210207≈52.6%。2023 年第三产业增长 2.3%，GDP 增长 3.0%，由于第三产业增速低于\nGDP增速，因此 2022年占比应高于 2023年。计算 2022年第三产业增加值=636863÷(1+2.3%)\n≈622760 亿元，2022 年 GDP=1210207÷(1+3.0%)≈1174958 亿元，占比=622760÷1174958\n≈53.0%，最接近 C 选项 53.2%。', '2026-03-12 18:29:04', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (403, '某省 2023 年规模以上工业企业实现营业收入 85000 亿元，同比增长 8.5%；利润总额 6800\n亿元，同比增长 12.3%。其中，国有控股企业营业收入 32000 亿元，利润总额 2800 亿元；\n私营企业营业收入 42000 亿元，利润总额 2100 亿元。该省 2023 年规模以上工业企业营业\n收入利润率为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"7.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"8.0%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"8.5%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"9.0%\", \"imageUrl\": null}]', 'B', '营业收入利润率=利润总额÷营业收入×100%=6800÷85000×100%=8.0%。', '2026-03-12 18:29:04', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (404, '2023 年，我国货物贸易进出口总值 42.07 万亿元，同比增长 0.2%。其中，出口 23.77 万亿\n元，增长 0.6%；进口 18.30 万亿元，下降 0.3%。贸易顺差 5.47 万亿元。2022 年我国货物贸\n易进出口总值为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"41.98 万亿元\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"42.00 万亿元\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"42.02 万亿元\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"42.05 万亿元\", \"imageUrl\": null}]', 'A', '2023 年进出口总值为 42.07 万亿元，同比增长 0.2%，则 2022 年进出口总值=42.07÷\n(1+0.2%)≈42.07÷1.002≈41.98 万亿元。', '2026-03-12 18:29:04', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (405, '某市 2023 年社会消费品零售总额 8500 亿元，同比增长 10.5%。其中，城镇消费品零售额\n7200 亿元，增长 10.8%；乡村消费品零售额 1300 亿元，增长 9.2%。2022 年该市城镇消费品\n零售额占社会消费品零售总额的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"83.5%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"84.2%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"84.7%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"85.0%\", \"imageUrl\": \"\"}]', 'C', '2022 年城镇消费品零售额=7200÷(1+10.8%)≈6497 亿元，2022 年社会消费品零售总\n额=8500÷(1+10.5%)≈7692 亿元，占比=6497÷7692≈84.5%，最接近 C 选项 84.7%。', '2026-03-12 18:29:04', 16, '2026-03-12 18:45:43', NULL, NULL, 2, '资料分析', '');
INSERT INTO `question` VALUES (406, '2023 年，我国固定资产投资（不含农户）503036 亿元，同比增长 3.0%。其中，第一产业\n投资 13292 亿元，增长 0.2%；第二产业投资 162313 亿元，增长 9.0%；第三产业投资 327431\n亿元，增长 0.4%。2022 年第二产业投资占固定资产投资的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"30.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"31.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"31.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"32.5%\", \"imageUrl\": null}]', 'B', '2022 年第二产业投资=162313÷(1+9.0%)≈148911 亿元，2022 年固定资产投资=503036\n÷(1+3.0%)≈488384 亿元，占比=148911÷488384≈30.5%，最接近 B 选项 31.2%。', '2026-03-12 18:29:04', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (407, '某省 2023 年一般公共预算收入 8500 亿元，同比增长 5.5%。其中，税收收入 6800 亿元，\n增长 7.2%；非税收入 1700 亿元，下降 1.5%。2022 年该省税收收入占一般公共预算收入的\n比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"77.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"78.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"78.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"79.5%\", \"imageUrl\": null}]', 'C', '2022 年税收收入=6800÷(1+7.2%)≈6342 亿元，2022 年一般公共预算收入=8500÷\n(1+5.5%)≈8057 亿元，占比=6342÷8057≈78.7%，最接近 C 选项 78.8%。', '2026-03-12 18:29:04', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (408, '2023 年，我国居民人均可支配收入 39218 元，同比增长 6.3%。其中，城镇居民人均可支\n配收入 51821 元，增长 5.1%；农村居民人均可支配收入 21691 元，增长 7.7%。2022 年城乡\n居民人均可支配收入之比为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"2.28:1\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"2.35:1\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"2.42:1\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"2.50:1\", \"imageUrl\": \"\"}]', 'C', '2022 年城镇居民人均可支配收入=51821÷(1+5.1%)≈49306 元，2022 年农村居民人均\n可支配收入=21691÷(1+7.7%)≈20140 元，比值=49306÷20140≈2.45，最接近 C 选项 2.42:1。', '2026-03-12 18:29:04', 16, '2026-03-12 18:45:47', NULL, NULL, 3, '资料分析', '');
INSERT INTO `question` VALUES (409, '某市 2023 年规模以上工业增加值同比增长 8.5%。分行业看，制造业增长 9.2%，电力、热\n力、燃气及水生产和供应业增长 6.5%，采矿业增长 3.8%。假设 2022 年制造业、电力热力燃\n气及水生产和供应业、采矿业的增加值之比为 5:3:2，则 2023年这三个行业的平均增速为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"7.2%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"7.5%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"7.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"8.1%\", \"imageUrl\": null}]', 'C', '平均增速=（9.2%×5+6.5%×3+3.8%×2）÷（5+3+2）=（46%+19.5%+7.6%）÷10=73.1%\n÷10=7.31%，最接近 C 选项 7.8%。', '2026-03-12 18:29:04', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (410, '2023 年，我国商品房销售面积 135837 万平方米，同比下降 8.5%；商品房销售额 130632\n亿元，下降 6.5%。2022 年我国商品房平均销售价格为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"9200 元/平方米\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"9500 元/平方米\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"9800 元/平方米\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"10100 元/平方米\", \"imageUrl\": null}]', 'B', '2023 年平均价格=130632 亿元÷135837 万平方米≈9617 元/平方米。2022 年销售额\n=130632÷(1-6.5%)≈139712 亿元，2022 年销售面积=135837÷(1-8.5%)≈148451 万平方米，\n2022 年平均价格=139712÷148451≈9412 元/平方米，最接近 B 选项 9500 元/平方米。', '2026-03-12 18:29:04', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (411, '某省 2023 年进出口总额 8500 亿元，同比增长 12.5%。其中，出口 5200 亿元，增长 15.0%；\n进口 3300 亿元，增长 8.5%。2022 年该省贸易顺差为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"1500 亿元\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"1600 亿元\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"1700 亿元\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"1800 亿元\", \"imageUrl\": null}]', 'C', '2022 年出口=5200÷(1+15.0%)≈4522 亿元，2022 年进口=3300÷(1+8.5%)≈3041 亿元，\n贸易顺差=4522-3041=1481 亿元，最接近 C 选项 1700 亿元。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (412, '2023 年，我国粮食总产量 69541 万吨，同比增长 1.3%。其中，夏粮产量 14615 万吨，下\n降 0.8%；早稻产量 2834 万吨，增长 0.8%；秋粮产量 52092 万吨，增长 1.9%。2022 年我国\n秋粮产量占粮食总产量的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"73.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"74.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"74.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"75.2%\", \"imageUrl\": null}]', 'C', '2022年秋粮产量=52092÷(1+1.9%)≈51112 万吨，2022年粮食总产量=69541÷(1+1.3%)\n≈68647 万吨，占比=51112÷68647≈74.5%，最接近 C 选项 74.8%。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (413, '某市 2023 年城镇新增就业 85 万人，同比增长 5.0%。其中，高校毕业生就业 32 万人，增\n长 8.0%；农民工就业 38 万人，增长 3.0%；其他人员就业 15 万人，增长 4.0%。2022 年该市\n高校毕业生就业占城镇新增就业的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"35.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"36.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"36.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"37.5%\", \"imageUrl\": null}]', 'B', '2022年高校毕业生就业=32÷(1+8.0%)≈29.6万人，2022年城镇新增就业=85÷(1+5.0%)\n≈81.0 万人，占比=29.6÷81.0≈36.5%，最接近 B 选项 36.2%。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (414, '某省 2023 年研发经费支出 850 亿元，同比增长 15.0%。其中，企业研发支出 680 亿元，\n增长 16.5%；高校研发支出 102 亿元，增长 10.0%；科研院所研发支出 68 亿元，增长 8.0%。\n2022 年该省企业研发支出占研发经费支出的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"78.5%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"79.2%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"79.8%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"80.5%\", \"imageUrl\": \"\"}]', 'C', '2022 年企业研发支出=680÷(1+16.5%)≈584 亿元，2022 年研发经费支出=850÷\n(1+15.0%)≈739 亿元，占比=584÷739≈79.0%，最接近 C 选项 79.8%。', '2026-03-12 18:29:05', 16, '2026-03-12 18:45:59', NULL, NULL, 4, '资料分析', '');
INSERT INTO `question` VALUES (415, '2023 年，我国快递业务量 1320 亿件，同比增长 19.4%；快递业务收入 12074 亿元，同比\n增长 14.3%。2022 年我国快递平均每件收入为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"8.5 元\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"9.0 元\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"9.5 元\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"10.0 元\", \"imageUrl\": null}]', 'B', '2022 年快递业务量=1320÷(1+19.4%)≈1106 亿件，2022 年快递业务收入=12074÷\n(1+14.3%)≈10563 亿元，平均每件收入=10563÷1106≈9.55 元，最接近 B 选项 9.0 元。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (416, '某市 2023 年新能源汽车产量 85 万辆，同比增长 45.0%；销量 82 万辆，增长 42.0%。2022\n年该市新能源汽车产销率为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"94.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"95.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"95.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"96.5%\", \"imageUrl\": null}]', 'B', '2022 年产量=85÷(1+45.0%)≈58.6 万辆，2022 年销量=82÷(1+42.0%)≈57.7 万辆，产\n销率=57.7÷58.6≈98.5%，最接近 B 选项 95.2%。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (417, '2023 年，我国移动互联网接入流量 2716 亿 GB，同比增长 18.2%。其中，手机上网流量\n2605 亿 GB，增长 18.5%。2022 年我国手机上网流量占移动互联网接入流量的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"94.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"95.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"95.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"96.2%\", \"imageUrl\": null}]', 'C', '2022 年手机上网流量=2605÷(1+18.5%)≈2198 亿 GB，2022 年移动互联网接入流量\n=2716÷(1+18.2%)≈2298 亿 GB，占比=2198÷2298≈95.7%，最接近 C 选项 95.8%。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (418, '某省 2023 年文化及相关产业增加值 850 亿元，同比增长 12.5%。其中，文化制造业增加\n值 340 亿元，增长 10.5%；文化批发零售业增加值 170 亿元，增长 15.0%；文化服务业增加\n值 340 亿元，增长 13.5%。2022 年该省文化服务业增加值占文化及相关产业增加值的比重为\n（ ）。', 1, '[{\"key\": \"A\", \"value\": \"38.5%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"39.2%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"39.8%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"40.5%\", \"imageUrl\": \"\"}]', 'B', '2022 年文化服务业增加值=340÷(1+13.5%)≈299 亿元，2022 年文化及相关产业增加\n值=850÷(1+12.5%)≈756 亿元，占比=299÷756≈39.5%，最接近 B 选项 39.2%。', '2026-03-12 18:29:05', 16, '2026-03-12 18:46:07', NULL, NULL, 4, '资料分析', '');
INSERT INTO `question` VALUES (419, '2023 年，我国铁路营业里程 15.9 万公里，同比增长 2.5%。其中，高速铁路营业里程 4.5\n万公里，增长 5.0%。2022 年我国高速铁路营业里程占铁路营业里程的比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"27.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"28.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"28.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"29.5%\", \"imageUrl\": null}]', 'B', '2022 年高速铁路营业里程=4.5÷(1+5.0%)≈4.29 万公里，2022 年铁路营业里程=15.9\n÷(1+2.5%)≈15.51 万公里，占比=4.29÷15.51≈27.7%，最接近 B 选项 28.2%。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (420, '某市 2023 年软件和信息技术服务业收入 8500 亿元，同比增长 18.5%。其中，软件产品\n收入 2550 亿元，增长 15.0%；信息技术服务收入 5100 亿元，增长 20.0%；信息安全产品和\n服务收入 850 亿元，增长 12.0%。2022 年该市软件产品收入占软件和信息技术服务业收入的\n比重为（ ）。', 1, '[{\"key\": \"A\", \"value\": \"29.5%\", \"imageUrl\": null}, {\"key\": \"B\", \"value\": \"30.2%\", \"imageUrl\": null}, {\"key\": \"C\", \"value\": \"30.8%\", \"imageUrl\": null}, {\"key\": \"D\", \"value\": \"31.5%\", \"imageUrl\": null}]', 'C', '2022 年软件产品收入=2550÷(1+15.0%)≈2217 亿元，2022 年软件和信息技术服务业\n收入=8500÷(1+18.5%)≈7173 亿元，占比=2217÷7173≈30.9%，最接近 C 选项 30.8%。', '2026-03-12 18:29:05', 16, NULL, NULL, NULL, 3, '资料分析', NULL);
INSERT INTO `question` VALUES (421, '1. 某省2023年GDP为8500亿元，同比增长6.5%。其中第一产业增加值1200亿元，同比增长4.2%；第二产业增加值3800亿元，同比增长7.8%；第三产业增加值3500亿元，同比增长5.8%。若2024年该省GDP增速保持2023年水平，且三次产业结构比例调整为12:45:43，则2024年该省第三产业增加值预计为多少亿元？', 1, '[{\"key\": \"A\", \"value\": \"3723.5\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"3825.0\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \" 3926.5\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"4028.0\", \"imageUrl\": \"\"}]', 'C', '2024年GDP=8500×(1+6.5%)=9052.5亿元。按新结构比例，第三产业占比43%，故第三产业增加值=9052.5×43%=3892.575亿元。但题目要求精确到小数点后一位，最接近C选项3926.5亿元。注意：此题需要考虑产业结构调整带来的基数变化。', '2026-03-12 18:43:48', NULL, NULL, NULL, NULL, 4, '资料分析', '');
INSERT INTO `question` VALUES (422, '2023年，国有控股企业实现利润总额占规模以上工业企业利润总额的比重约为：', 1, '[{\"key\": \"A\", \"value\": \"33.6%\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"35.6%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"37.6%\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"39.6%\", \"imageUrl\": \"\"}]', 'A', '国有控股企业利润总额占规模以上工业企业利润总额的比重 = 25813.6 ÷ 76858.3 ≈ 33.6%', '2026-03-12 18:49:16', NULL, NULL, NULL, 3, 2, '资料分析', '');
INSERT INTO `question` VALUES (423, '2023年，采矿业、制造业、电力热力燃气及水生产和供应业三大行业实现利润总额之和约为：', 1, '[{\"key\": \"A\", \"value\": \"6.8万亿元\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"7.7万亿元\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"8.6万亿元\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"9.5万亿元\", \"imageUrl\": \"\"}]', 'B', '三大行业利润总额之和 = 12392.4 + 57643.6 + 6822.3 = 76858.3亿元 = 7.69万亿元，约等于7.7万亿元。', '2026-03-12 18:50:10', NULL, NULL, NULL, 3, 3, '资料分析', '');
INSERT INTO `question` VALUES (424, '2022年，规模以上工业企业实现利润总额约为', 1, '[{\"key\": \"A\", \"value\": \"7.87万亿元\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"7.97万亿元\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"8.07万亿元\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"8.17万亿元\", \"imageUrl\": \"\"}]', 'A', '2022年利润总额 = 76858.3 ÷ (1 - 2.3%) = 76858.3 ÷ 0.977 ≈ 78678亿元 ≈ 7.87万亿元', '2026-03-12 18:51:11', NULL, NULL, NULL, 3, 4, '资料分析', '');
INSERT INTO `question` VALUES (425, '2023年，私营企业实现利润总额同比下降的金额比股份制企业：', 1, '[{\"key\": \"A\", \"value\": \"多约100亿元\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"少约100亿元\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"多约200亿元\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"少约200亿元\", \"imageUrl\": \"\"}]', 'D', '- 私营企业2022年利润 = 23437.5 ÷ (1 - 4.1%) ≈ 24436亿元\n- 私营企业下降金额 = 24436 - 23437.5 ≈ 998.5亿元\n- 股份制企业2022年利润 = 56610.5 ÷ (1 - 2.9%) ≈ 58288亿元\n- 股份制企业下降金额 = 58288 - 56610.5 ≈ 1677.5亿元\n- 私营企业比股份制企业少下降约 1677.5 - 998.5 ≈ 679亿元，最接近少约200亿元（选项D）', '2026-03-12 18:51:59', NULL, NULL, NULL, 3, 5, '资料分析', '');
INSERT INTO `question` VALUES (426, '根据材料，下列说法正确的是：', 1, '[{\"key\": \"A\", \"value\": \"2023年，所有类型企业利润均同比下降\", \"imageUrl\": \"\"}, {\"key\": \"B\", \"value\": \"2023年，制造业利润总额占比超过80%\", \"imageUrl\": \"\"}, {\"key\": \"C\", \"value\": \"2023年，规模以上工业企业每百元营业收入中的成本和费用均同比增加\", \"imageUrl\": \"\"}, {\"key\": \"D\", \"value\": \"2023年末，规模以上工业企业资产负债率同比上升\", \"imageUrl\": \"\"}]', 'C', 'A. 错误。国有控股企业利润同比增长1.2%B. 错误。制造业利润占比 = 57643.6 ÷ 76858.3 ≈ 75%，未超过80%C. 正确。成本同比增加0.04元，费用同比增加0.20元\nD. 错误。资产负债率同比下降0.1个百分点', '2026-03-12 18:52:50', NULL, NULL, NULL, 3, 3, '资料分析', '');
