INSERT INTO `sys_log` VALUES (1599, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[113, Question(id=113, content=一件商品按成本价提高 30%后标价，再打 8 折销售，售价为 208 元。这件商品的成本价\n是多少元？, contentImageUrl=, type=1, options=[Option(key=A, value=180, imageUrl=), Option(key=B, value=190, imageUrl=), Option(key=C, value=200, imageUrl=), Option(key=D, value=210, imageUrl=)], answer=C, analysis=设成本为 x，则 x * (1+30%) * 0.8 = 208，解得 x = 200。, difficulty=2, category=数量关系, createdTime=2026-02-26T21:05:11, createBy=11, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 15:48:19');
