INSERT INTO `sys_log` VALUES (1612, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[117, Question(id=117, content=某商店进了一批水果，第一天卖了总数的 1/3，第二天卖了剩余的 1/2，还剩 20 斤。这\n批水果共有多少斤？, contentImageUrl=, type=1, options=[Option(key=A, value=40, imageUrl=), Option(key=B, value=50, imageUrl=), Option(key=C, value=60, imageUrl=), Option(key=D, value=80, imageUrl=)], answer=C, analysis=设总量为 x。第一天卖 x/3，剩 2x/3。第二天卖(2x/3)*1/2 = x/3。剩 x - x/3 - x/3 = x/3\n= 20，故 x = 60。, difficulty=3, category=数量关系, createdTime=2026-02-26T21:05:11, createBy=11, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 7, '2026-03-12 15:48:56');
