INSERT INTO `sys_log` VALUES (1735, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@51e446ca, [Question(id=130, content=下列哪个国家被称为\"千岛之国\"？, contentImageUrl=null, type=1, options=[Option(key=A, value=印度尼西亚, imageUrl=null), Option(key=B, value=菲律宾, imageUrl=null), Option(key=C, value=日本, imageUrl=null), Option(key=D, value=马来西亚, imageUrl=null)], answer=A, analysis=印度尼西亚由上万个岛屿组成，是世界上最大的群岛国家，因此被称为\"千岛之国\"。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=131, content=中国古代四大发明中，哪一项发明最早？, contentImageUrl=null, type=1, options=[Option(key=A, value=造纸术, imageUrl=null), Option(key=B, value=印刷术, imageUrl=null), Option(key=C, value=火药, imageUrl=null), Option(key=D, value=指南针, imageUrl=null)], answer=A, analysis=造纸术发明于西汉时期（公元前 2 世纪），是最早的四大发明，其他三项发明时间较\n晚。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=132, content=地球自转一周需要多长时间？, contentImageUrl=null, type=1, options=[Option(key=A, value=24 小时, imageUrl=null), Option(key=B, value=12 小时, imageUrl=null), Option(key=C, value=365 天, imageUrl=null), Option(key=D, value=30 天, imageUrl=null)], answer=A, analysis=地球自转一周约为 24 小时，即一天的时间。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=133, content=下列哪个不属于世界三大宗教？, contentImageUrl=null, type=1, options=[Option(key=A, value=佛教, imageUrl=null), Option(key=B, value=基督教, imageUrl=null), Option(key=C, value=伊斯兰教, imageUrl=null), Option(key=D, value=道教, imageUrl=null)], answer=D, analysis=世界三大宗教是佛教、基督教和伊斯兰教，道教是中国本土宗教，不属于世界三大宗\n教。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=134, content=人体最大的器官是什么？, contentImageUrl=null, type=1, options=[Option(key=A, value=心脏, imageUrl=null), Option(key=B, value=肝脏, imageUrl=null), Option(key=C, value=皮肤, imageUrl=null), Option(key=D, value=肺, imageUrl=null)], answer=C, analysis=皮肤是人体最大的器官，成人皮肤面积约 1.5-2 平方米。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=135, content=中国的首都是哪个城市？, contentImageUrl=null, type=1, options=[Option(key=A, value=上海, imageUrl=null), Option(key=B, value=北京, imageUrl=null), Option(key=C, value=广州, imageUrl=null), Option(key=D, value=深圳, imageUrl=null)], answer=B, analysis=北京是中华人民共和国的首都，自 1949 年以来一直是中国的政治中心。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=136, content=下列哪种动物是哺乳动物？, contentImageUrl=null, type=1, options=[Option(key=A, value=鲨鱼, imageUrl=null), Option(key=B, value=鳄鱼, imageUrl=null), Option(key=C, value=海豚, imageUrl=null), Option(key=D, value=金枪鱼, imageUrl=null)], answer=C, analysis=海豚是哺乳动物，用肺呼吸，胎生哺乳；鲨鱼、鳄鱼和金枪鱼都不是哺乳动物。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=137, content=光在真空中的传播速度大约是多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=每秒 30 万公里, imageUrl=null), Option(key=B, value=每秒 3 万公里, imageUrl=null), Option(key=C, value=每秒 300 万公里, imageUrl=null), Option(key=D, value=每秒 3000 公里, imageUrl=null)], answer=A, analysis=光在真空中的传播速度约为每秒 30 万公里（299,792,458 米/秒）。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=138, content=下列哪个行星离太阳最近？, contentImageUrl=null, type=1, options=[Option(key=A, value=金星, imageUrl=null), Option(key=B, value=地球, imageUrl=null), Option(key=C, value=火星, imageUrl=null), Option(key=D, value=水星, imageUrl=null)], answer=D, analysis=水星是太阳系八大行星中离太阳最近的行星，平均距离约 5790 万公里。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=139, content=中国的国旗是什么？, contentImageUrl=null, type=1, options=[Option(key=A, value=五星红旗, imageUrl=null), Option(key=B, value=红旗, imageUrl=null), Option(key=C, value=红星旗, imageUrl=null), Option(key=D, value=五角星旗, imageUrl=null)], answer=A, analysis=中华人民共和国国旗是五星红旗，由红色旗面和五颗黄色五角星组成。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=140, content=一年有多少个月？, contentImageUrl=null, type=1, options=[Option(key=A, value=10 个, imageUrl=null), Option(key=B, value=11 个, imageUrl=null), Option(key=C, value=12 个, imageUrl=null), Option(key=D, value=13 个, imageUrl=null)], answer=C, analysis=公历一年有 12 个月，这是基本的常识。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=141, content=下列哪种水果是黄色的？, contentImageUrl=null, type=1, options=[Option(key=A, value=苹果, imageUrl=null), Option(key=B, value=香蕉, imageUrl=null), Option(key=C, value=草莓, imageUrl=null), Option(key=D, value=蓝莓, imageUrl=null)], answer=B, analysis=香蕉成熟后呈黄色，苹果多为红色或绿色，草莓为红色，蓝莓为蓝色。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=142, content=水的化学式是什么？, contentImageUrl=null, type=1, options=[Option(key=A, value=H2O, imageUrl=null), Option(key=B, value=CO2, imageUrl=null), Option(key=C, value=O2, imageUrl=null), Option(key=D, value=N2, imageUrl=null)], answer=A, analysis=水的化学式是 H2O，由两个氢原子和一个氧原子组成。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=143, content=下列哪个不是中国的传统节日？, contentImageUrl=null, type=1, options=[Option(key=A, value=春节, imageUrl=null), Option(key=B, value=中秋节, imageUrl=null), Option(key=C, value=圣诞节, imageUrl=null), Option(key=D, value=端午节, imageUrl=null)], answer=C, analysis=圣诞节是西方的传统节日，春节、中秋节和端午节都是中国的传统节日。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=144, content=人体共有多少块骨头？, contentImageUrl=null, type=1, options=[Option(key=A, value=206 块, imageUrl=null), Option(key=B, value=300 块, imageUrl=null), Option(key=C, value=150 块, imageUrl=null), Option(key=D, value=100 块, imageUrl=null)], answer=A, analysis=正常成年人共有 206 块骨头，这是解剖学的基本常识。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=145, content=下列哪种动物是食草动物？, contentImageUrl=null, type=1, options=[Option(key=A, value=老虎, imageUrl=null), Option(key=B, value=狮子, imageUrl=null), Option(key=C, value=兔子, imageUrl=null), Option(key=D, value=狼, imageUrl=null)], answer=C, analysis=兔子是食草动物，主要吃植物；老虎、狮子和狼都是食肉动物。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=146, content=太阳从哪个方向升起？, contentImageUrl=null, type=1, options=[Option(key=A, value=东方, imageUrl=null), Option(key=B, value=西方, imageUrl=null), Option(key=C, value=南方, imageUrl=null), Option(key=D, value=北方, imageUrl=null)], answer=A, analysis=由于地球自西向东自转，太阳看起来从东方升起，从西方落下。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=147, content=下列哪个不是颜色？, contentImageUrl=null, type=1, options=[Option(key=A, value=红色, imageUrl=null), Option(key=B, value=蓝色, imageUrl=null), Option(key=C, value=声音, imageUrl=null), Option(key=D, value=绿色, imageUrl=null)], answer=C, analysis=声音是听觉现象，不是颜色；红色、蓝色和绿色都是颜色。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=148, content=中国的货币单位是什么？, contentImageUrl=null, type=1, options=[Option(key=A, value=美元, imageUrl=null), Option(key=B, value=欧元, imageUrl=null), Option(key=C, value=人民币, imageUrl=null), Option(key=D, value=日元, imageUrl=null)], answer=C, analysis=人民币是中华人民共和国的法定货币，符号为¥。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=149, content=一年有多少个季节？, contentImageUrl=null, type=1, options=[Option(key=A, value=2 个, imageUrl=null), Option(key=B, value=3 个, imageUrl=null), Option(key=C, value=4 个, imageUrl=null), Option(key=D, value=5 个, imageUrl=null)], answer=C, analysis=一年有春、夏、秋、冬四个季节，这是基本的自然常识。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null)]]', '0:0:0:0:0:0:0:1', 171, '2026-03-12 16:02:23');
