INSERT INTO `sys_log` VALUES (1800, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@15886b4e, [Question(id=150, content=下列关于我国宪法规定的公民基本权利的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=公民的私有财产神圣不可侵犯, imageUrl=null), Option(key=B, value=公民有言论、出版、集会、结社、游行、示威的自由, imageUrl=null), Option(key=C, value=公民有劳动的权利和义务, imageUrl=null), Option(key=D, value=公民有休息的权利, imageUrl=null)], answer=C, analysis=我国宪法规定，公民有劳动的权利和义务。A 选项\"神圣不可侵犯\"表述不准确，宪法\n规定的是\"公民的合法的私有财产不受侵犯\"；B 选项表述正确，但不是最完整的表述；D 选\n项公民有休息的权利，但不是基本权利表述的核心。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=151, content=下列关于我国行政区划的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=全国分为省、自治区、直辖市, imageUrl=null), Option(key=B, value=省、自治区分为自治州、县、自治县、市, imageUrl=null), Option(key=C, value=县、自治县分为乡、民族乡、镇, imageUrl=null), Option(key=D, value=直辖市和较大的市分为区、县, imageUrl=null)], answer=A, analysis=宪法规定，全国分为省、自治区、直辖市。省、自治区分为自治州、县、自治县、市。\n县、自治县分为乡、民族乡、镇。直辖市和较大的市分为区、县。自治州分为县、自治县、\n市。A 选项表述正确且完整。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=152, content=下列关于我国民族区域自治制度的表述，错误的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=民族自治地方分为自治区、自治州、自治县三级, imageUrl=null), Option(key=B, value=民族自治地方的自治机关是自治区、自治州、自治县的人民代表大会和人民政府, imageUrl=null), Option(key=C, value=民族自治地方的人民代表大会常务委员会中应当有实行区域自治的民族的公民担任主任, imageUrl=null), Option(key=D, value=民族自治地方的人民法院院长必须由实行区域自治的民族的公民担任, imageUrl=null)], answer=D, analysis=民族自治地方的人民法院院长和人民检察院检察长，由实行区域自治的民族的公民担\n任，但不是\"必须\"，而是\"应当由\"。D 选项表述过于绝对，错误。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=153, content=下列关于我国人民代表大会制度的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=全国人民代表大会是最高国家权力机关, imageUrl=null), Option(key=B, value=全国人民代表大会常务委员会是全国人民代表大会的常设机关, imageUrl=null), Option(key=C, value=全国人民代表大会每届任期五年, imageUrl=null), Option(key=D, value=全国人民代表大会代表由省、自治区、直辖市、特别行政区和军队选出的代表组成, imageUrl=null)], answer=A, analysis=全国人民代表大会是最高国家权力机关，这是宪法明确规定的。B 选项表述正确，但\nA 选项更核心；C 选项表述正确，但不是人民代表大会制度的本质特征；D 选项表述正确，\n但 A 选项更根本。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=154, content=下列关于我国国家主席的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=国家主席是国家元首, imageUrl=null), Option(key=B, value=国家主席每届任期同全国人民代表大会每届任期相同, imageUrl=null), Option(key=C, value=国家主席连续任职不得超过两届, imageUrl=null), Option(key=D, value=国家主席缺位的时候，由副主席继任主席的职位, imageUrl=null)], answer=B, analysis=国家主席每届任期同全国人民代表大会每届任期相同，即五年。A 选项\"国家元首\"不\n是宪法表述；C 选项宪法没有规定国家主席连续任职不得超过两届；D 选项国家主席缺位的\n时候，由副主席继任主席的职位，但 B 选项更符合宪法原文表述。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=155, content=下列关于我国国务院的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=国务院即中央人民政府, imageUrl=null), Option(key=B, value=国务院是最高国家权力机关的执行机关, imageUrl=null), Option(key=C, value=国务院是最高国家行政机关, imageUrl=null), Option(key=D, value=国务院实行总理负责制, imageUrl=null)], answer=D, analysis=国务院实行总理负责制，这是宪法明确规定的。A、B、C 选项表述都正确，但 D 选项\n是国务院组织原则的核心特征。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=156, content=下列关于我国人民法院的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=最高人民法院是最高审判机关, imageUrl=null), Option(key=B, value=最高人民法院监督地方各级人民法院和专门人民法院的审判工作, imageUrl=null), Option(key=C, value=最高人民法院院长每届任期同全国人民代表大会每届任期相同, imageUrl=null), Option(key=D, value=最高人民法院院长连续任职不得超过两届, imageUrl=null)], answer=B, analysis=最高人民法院监督地方各级人民法院和专门人民法院的审判工作，这是宪法明确规定\n的。A 选项\"最高审判机关\"表述正确，但 B 选项更体现监督关系；C 选项表述正确，但不是\n核心；D 选项宪法没有规定连续任职不得超过两届。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=157, content=下列关于我国人民检察院的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=最高人民检察院是最高检察机关, imageUrl=null), Option(key=B, value=最高人民检察院领导地方各级人民检察院和专门人民检察院的工作, imageUrl=null), Option(key=C, value=最高人民检察院检察长每届任期同全国人民代表大会每届任期相同, imageUrl=null), Option(key=D, value=最高人民检察院检察长连续任职不得超过两届, imageUrl=null)], answer=B, analysis=最高人民检察院领导地方各级人民检察院和专门人民检察院的工作，这是宪法明确规\n定的。A 选项\"最高检察机关\"表述正确，但 B 选项更体现领导关系；C 选项表述正确，但不\n是核心；D选项宪法没有规定连续任职不得超过两届。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=158, content=下列关于我国监察委员会的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=中华人民共和国设立国家监察委员会和地方各级监察委员会, imageUrl=null), Option(key=B, value=国家监察委员会是最高监察机关, imageUrl=null), Option(key=C, value=国家监察委员会领导地方各级监察委员会的工作, imageUrl=null), Option(key=D, value=监察委员会由主任、副主任若干人、委员若干人组成, imageUrl=null)], answer=B, analysis=国家监察委员会是最高监察机关，这是宪法明确规定的。A、C、D 选项表述都正确，\n但 B 选项是监察委员会地位的核心表述。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=159, content=下列关于我国国旗的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=中华人民共和国国旗是五星红旗, imageUrl=null), Option(key=B, value=国旗由红色和黄色组成, imageUrl=null), Option(key=C, value=国旗旗面为红色，左上方缀黄色五角星五颗, imageUrl=null), Option(key=D, value=国旗中的四颗小五角星各有一尖正对着大星的中心点, imageUrl=null)], answer=C, analysis=国旗旗面为红色，左上方缀黄色五角星五颗，这是国旗法明确规定的。A 选项表述正\n确，但不够具体；B 选项表述正确，但不够详细；D选项表述正确，但 C 选项更完整。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=160, content=下列关于我国国徽的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=中华人民共和国国徽中间是五星照耀下的天安门, imageUrl=null), Option(key=B, value=国徽周围是谷穗和齿轮, imageUrl=null), Option(key=C, value=国徽以红色和金色为主色调, imageUrl=null), Option(key=D, value=国徽图案由中央人民政府委员会确定, imageUrl=null)], answer=A, analysis=国徽中间是五星照耀下的天安门，这是宪法明确规定的。B、C、D 选项表述都正确，\n但 A 选项是国徽图案的核心特征。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=161, content=下列关于我国首都的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=中华人民共和国首都是北京, imageUrl=null), Option(key=B, value=北京是直辖市, imageUrl=null), Option(key=C, value=北京是国家政治、经济、文化中心, imageUrl=null), Option(key=D, value=北京是国际交往中心, imageUrl=null)], answer=A, analysis=中华人民共和国首都是北京，这是宪法明确规定的。B、C、D 选项表述都正确，但 A\n选项是宪法规定的根本表述。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=162, content=下列关于我国国家机构的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=全国人民代表大会是最高国家权力机关, imageUrl=null), Option(key=B, value=国务院是最高国家行政机关, imageUrl=null), Option(key=C, value=中央军事委员会领导全国武装力量, imageUrl=null), Option(key=D, value=国家监察委员会是最高监察机关, imageUrl=null)], answer=A, analysis=全国人民代表大会是最高国家权力机关，这是宪法明确规定的国家机构根本原则。B、\nC、D 选项表述都正确，但 A 选项是国家机构体系的核心。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=163, content=下列关于我国公民基本义务的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=公民有维护国家统一和全国各民族团结的义务, imageUrl=null), Option(key=B, value=公民有遵守宪法和法律的义务, imageUrl=null), Option(key=C, value=公民有维护国家安全、荣誉和利益的义务, imageUrl=null), Option(key=D, value=公民有依法纳税的义务, imageUrl=null)], answer=A, analysis=公民有维护国家统一和全国各民族团结的义务，这是宪法明确规定的首要义务。B、\nC、D 选项表述都正确，但 A 选项是公民基本义务的首要内容。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=164, content=下列关于我国选举制度的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=中华人民共和国年满十八周岁的公民，不分民族、种族、性别、职业、家庭出身、宗教信, imageUrl=null), Option(key=B, value=依照法律被剥夺政治权利的人没有选举权和被选举权, imageUrl=null), Option(key=C, value=全国人民代表大会代表由省、自治区、直辖市、特别行政区和军队选出的代表组成, imageUrl=null), Option(key=D, value=全国人民代表大会代表的名额不超过三千人, imageUrl=null)], answer=A, analysis=年满十八周岁的公民，不分民族、种族、性别、职业、家庭出身、宗教信仰、教育程\n度、财产状况、居住期限，都有选举权和被选举权，这是宪法明确规定的选举制度基本原则。\nB、C、D 选项表述都正确，但 A 选项是选举制度的核心原则。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=165, content=下列关于我国国家赔偿制度的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=国家机关和国家机关工作人员行使职权，有本法规定的侵犯公民、法人和其他组织合法权, imageUrl=null), Option(key=B, value=国家赔偿以支付赔偿金为主要方式, imageUrl=null), Option(key=C, value=能够返还财产或者恢复原状的，予以返还财产或者恢复原状, imageUrl=null), Option(key=D, value=造成公民身体伤害的，应当支付医疗费、护理费，以及赔偿因误工减少的收入, imageUrl=null)], answer=A, analysis=国家机关和国家机关工作人员行使职权，有本法规定的侵犯公民、法人和其他组织合\n法权益的情形，造成损害的，受害人有依照本法取得国家赔偿的权利，这是国家赔偿法明确\n规定的国家赔偿制度基本原则。B、C、D 选项表述都正确，但 A 选项是国家赔偿制度的核心\n原则。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=166, content=下列关于我国行政复议制度的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=公民、法人或者其他组织认为行政机关的具体行政行为侵犯其合法权益，可以依法申请行, imageUrl=null), Option(key=B, value=行政复议机关负责法制工作的机构具体办理行政复议事项, imageUrl=null), Option(key=C, value=行政复议申请期限为知道该具体行政行为之日起六十日内, imageUrl=null), Option(key=D, value=行政复议决定作出前，申请人可以撤回行政复议申请, imageUrl=null)], answer=A, analysis=公民、法人或者其他组织认为行政机关的具体行政行为侵犯其合法权益，可以依法申\n请行政复议，这是行政复议法明确规定的行政复议制度基本原则。B、C、D 选项表述都正确，\n但 A 选项是行政复议制度的核心原则。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=167, content=下列关于我国行政诉讼制度的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权益，, imageUrl=null), Option(key=B, value=人民法院受理公民、法人和其他组织提起的下列诉讼：对行政拘留、暂扣或者吊销许可证, imageUrl=null), Option(key=C, value=人民法院审理行政案件，以法律和行政法规、地方性法规为依据, imageUrl=null), Option(key=D, value=人民法院审理行政案件，参照规章, imageUrl=null)], answer=A, analysis=公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权\n益，有权向人民法院提起诉讼，这是行政诉讼法明确规定的行政诉讼制度基本原则。B、C、\nD选项表述都正确，但 A 选项是行政诉讼制度的核心原则。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=168, content=下列关于我国行政许可制度的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=行政许可，是指行政机关根据公民、法人或者其他组织的申请，经依法审查，准予其从事, imageUrl=null), Option(key=B, value=设定和实施行政许可，应当遵循公开、公平、公正的原则, imageUrl=null), Option(key=C, value=符合法定条件、标准的，申请人有依法取得行政许可的平等权利，行政机关不得歧视, imageUrl=null), Option(key=D, value=实施行政许可，应当遵循便民的原则，提高办事效率，提供优质服务, imageUrl=null)], answer=A, analysis=行政许可，是指行政机关根据公民、法人或者其他组织的申请，经依法审查，准予其\n从事特定活动的行为，这是行政许可法明确规定的行政许可制度定义。B、C、D 选项表述都\n正确，但 A 选项是行政许可制度的核心定义。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=169, content=下列关于我国行政处罚制度的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=行政处罚，是指行政机关依法对违反行政管理秩序的公民、法人或者其他组织，以减损权, imageUrl=null), Option(key=B, value=行政处罚的种类：警告、罚款、没收违法所得、没收非法财物、责令停产停业、暂扣或者, imageUrl=null), Option(key=C, value=行政处罚由违法行为发生地的县级以上地方人民政府具有行政处罚权的行政机关管辖, imageUrl=null), Option(key=D, value=当事人对行政处罚决定不服申请行政复议或者提起行政诉讼的，行政处罚不停止执行，法, imageUrl=null)], answer=A, analysis=行政处罚，是指行政机关依法对违反行政管理秩序的公民、法人或者其他组织，以减\n损权益或者增加义务的方式予以惩戒的行为，这是行政处罚法明确规定的行政处罚制度定义。\nB、C、D 选项表述都正确，但 A 选项是行政处罚制度的核心定义。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null)]]', '0:0:0:0:0:0:0:1', 195, '2026-03-12 16:09:30');
