INSERT INTO `sys_log` VALUES (1808, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[169, Question(id=169, content=下列关于我国行政处罚制度的表述，正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=行政处罚，是指行政机关依法对违反行政管理秩序的公民、法人或者其他组织，以减损权, imageUrl=), Option(key=B, value=行政处罚的种类：警告、罚款、没收违法所得、没收非法财物、责令停产停业、暂扣或者, imageUrl=), Option(key=C, value=行政处罚由违法行为发生地的县级以上地方人民政府具有行政处罚权的行政机关管辖, imageUrl=), Option(key=D, value=当事人对行政处罚决定不服申请行政复议或者提起行政诉讼的，行政处罚不停止执行，法, imageUrl=)], answer=A, analysis=行政处罚，是指行政机关依法对违反行政管理秩序的公民、法人或者其他组织，以减\n损权益或者增加义务的方式予以惩戒的行为，这是行政处罚法明确规定的行政处罚制度定义。\nB、C、D 选项表述都正确，但 A 选项是行政处罚制度的核心定义。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:09:30, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 8, '2026-03-12 16:09:52');
