INSERT INTO `sys_log` VALUES (1810, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[158, Question(id=158, content=下列关于我国监察委员会的表述，正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=中华人民共和国设立国家监察委员会和地方各级监察委员会, imageUrl=), Option(key=B, value=国家监察委员会是最高监察机关, imageUrl=), Option(key=C, value=国家监察委员会领导地方各级监察委员会的工作, imageUrl=), Option(key=D, value=监察委员会由主任、副主任若干人、委员若干人组成, imageUrl=)], answer=B, analysis=国家监察委员会是最高监察机关，这是宪法明确规定的。A、C、D 选项表述都正确，\n但 B 选项是监察委员会地位的核心表述。, difficulty=3, category=常识判断, createdTime=2026-03-12T16:09:30, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:09:57');
