INSERT INTO `sys_log` VALUES (1815, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[167, Question(id=167, content=下列关于我国行政诉讼制度的表述，正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权益，, imageUrl=), Option(key=B, value=人民法院受理公民、法人和其他组织提起的下列诉讼：对行政拘留、暂扣或者吊销许可证, imageUrl=), Option(key=C, value=人民法院审理行政案件，以法律和行政法规、地方性法规为依据, imageUrl=), Option(key=D, value=人民法院审理行政案件，参照规章, imageUrl=)], answer=A, analysis=公民、法人或者其他组织认为行政机关和行政机关工作人员的行政行为侵犯其合法权\n益，有权向人民法院提起诉讼，这是行政诉讼法明确规定的行政诉讼制度基本原则。B、C、\nD选项表述都正确，但 A 选项是行政诉讼制度的核心原则。, difficulty=5, category=常识判断, createdTime=2026-03-12T16:09:30, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:10:09');
