INSERT INTO `sys_log` VALUES (1818, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[150, Question(id=150, content=下列关于我国宪法规定的公民基本权利的表述，正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=公民的私有财产神圣不可侵犯, imageUrl=), Option(key=B, value=公民有言论、出版、集会、结社、游行、示威的自由, imageUrl=), Option(key=C, value=公民有劳动的权利和义务, imageUrl=), Option(key=D, value=公民有休息的权利, imageUrl=)], answer=C, analysis=我国宪法规定，公民有劳动的权利和义务。A 选项\"神圣不可侵犯\"表述不准确，宪法\n规定的是\"公民的合法的私有财产不受侵犯\"；B 选项表述正确，但不是最完整的表述；D 选\n项公民有休息的权利，但不是基本权利表述的核心。, difficulty=2, category=常识判断, createdTime=2026-03-12T16:09:29, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:10:17');
