INSERT INTO `sys_log` VALUES (1820, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[152, Question(id=152, content=下列关于我国民族区域自治制度的表述，错误的是：, contentImageUrl=, type=1, options=[Option(key=A, value=民族自治地方分为自治区、自治州、自治县三级, imageUrl=), Option(key=B, value=民族自治地方的自治机关是自治区、自治州、自治县的人民代表大会和人民政府, imageUrl=), Option(key=C, value=民族自治地方的人民代表大会常务委员会中应当有实行区域自治的民族的公民担任主任, imageUrl=), Option(key=D, value=民族自治地方的人民法院院长必须由实行区域自治的民族的公民担任, imageUrl=)], answer=D, analysis=民族自治地方的人民法院院长和人民检察院检察长，由实行区域自治的民族的公民担\n任，但不是\"必须\"，而是\"应当由\"。D 选项表述过于绝对，错误。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:09:29, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:10:32');
