INSERT INTO `sys_log` VALUES (1850, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@32101f5a, [Question(id=170, content=关于我国宪法的发展历程，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=1982 年宪法是我国颁布的第一部宪法, imageUrl=null), Option(key=B, value=2004 年宪法修正案首次将\"国家尊重和保障人权\"写入宪法, imageUrl=null), Option(key=C, value=2018 年宪法修正案将\"习近平新时代中国特色社会主义思想\"写入宪法, imageUrl=null), Option(key=D, value=我国现行宪法共经历了五次修正, imageUrl=null)], answer=C, analysis=A 错误，1954 年宪法是我国第一部宪法；B 错误，2004 年修正案将\"国家尊重和保障\n人权\"写入宪法，但不是首次；C 正确，2018 年宪法修正案将\"习近平新时代中国特色社会主\n义思想\"写入宪法；D 错误，我国现行宪法共经历了四次修正（1988、1993、1999、2004、\n2018 年共五次）。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=171, content=下列关于我国货币政策工具的表述，正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=存款准备金率属于价格型货币政策工具, imageUrl=null), Option(key=B, value=公开市场操作属于数量型货币政策工具, imageUrl=null), Option(key=C, value=再贴现率属于数量型货币政策工具, imageUrl=null), Option(key=D, value=常备借贷便利属于结构性货币政策工具, imageUrl=null)], answer=D, analysis=A 错误，存款准备金率属于数量型货币政策工具；B 错误，公开市场操作属于数量型\n货币政策工具，但主要通过买卖债券调节基础货币；C 错误，再贴现率属于价格型货币政策\n工具；D 正确，常备借贷便利（SLF）属于结构性货币政策工具。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=172, content=关于我国民法典，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=民法典于 2020 年 5 月 28 日通过，2021 年 1 月 1 日起施行, imageUrl=null), Option(key=B, value=民法典共分为七编，包括总则、物权、合同、人格权、婚姻家庭、继承、侵权责任, imageUrl=null), Option(key=C, value=民法典首次确立了\"绿色原则\"作为民法基本原则, imageUrl=null), Option(key=D, value=民法典废止了《婚姻法》《继承法》《民法通则》《收养法》《担保法》《合同法》《物权法》, imageUrl=null)], answer=A, analysis=A 正确，民法典于 2020 年 5 月 28 日通过，2021 年 1 月 1 日起施行；B 错误，民法典\n共分为七编，包括总则、物权、合同、人格权、婚姻家庭、继承、侵权责任，外加附则；C\n错误，\"绿色原则\"在《民法总则》中已确立；D 错误，民法典废止了《婚姻法》《继承法》《民\n法通则》《收养法》《担保法》《合同法》《物权法》《侵权责任法》《民法总则》等九部法律，\n表述正确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=173, content=关于我国航天事业的发展，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国第一颗人造地球卫星\"东方红一号\"于 1970 年 4 月 24 日发射成功, imageUrl=null), Option(key=B, value=我国首次载人航天飞行任务由\"神舟五号\"完成，航天员是杨利伟, imageUrl=null), Option(key=C, value=我国首次月球软着陆任务由\"嫦娥三号\"完成, imageUrl=null), Option(key=D, value=我国首次火星探测任务\"天问一号\"于 2020 年 7 月 23 日发射成功, imageUrl=null)], answer=D, analysis=A 正确，\"东方红一号\"于 1970 年 4 月 24 日发射成功；B 正确，\"神舟五号\"完成首次\n载人航天飞行，航天员是杨利伟；C 正确，\"嫦娥三号\"完成首次月球软着陆；D 正确，\"天问\n一号\"于 2020 年 7 月 23 日发射成功。本题四项均正确，但根据题目要求选择最佳答案，D\n项为最新成就。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=174, content=关于我国古代科技成就，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=《九章算术》是中国古代第一部数学专著，成书于汉代, imageUrl=null), Option(key=B, value=《天工开物》是世界上第一部关于农业和手工业生产的综合性著作, imageUrl=null), Option(key=C, value=《本草纲目》收录药物 1892 种，方剂 11096 个, imageUrl=null), Option(key=D, value=《梦溪笔谈》被英国科学史家李约瑟称为\"中国科学史上的里程碑\", imageUrl=null)], answer=C, analysis=A 错误，《九章算术》不是第一部数学专著；《天工开物》是世界上第一部关于农业和\n手工业生产的综合性著作，B 正确；《本草纲目》收录药物 1892 种，方剂 11096 个，C 正确；\n《梦溪笔谈》被李约瑟称为\"中国科学史上的里程碑\"，D 正确。本题 C 项数据最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=175, content=关于世界经济发展史，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=第一次工业革命始于英国，以蒸汽机的广泛应用为标志, imageUrl=null), Option(key=B, value=第二次工业革命以电力的广泛应用为标志，主要发生在德国和美国, imageUrl=null), Option(key=C, value=第三次工业革命以计算机技术、信息技术为代表，始于 20 世纪 40 年代, imageUrl=null), Option(key=D, value=第四次工业革命以人工智能、大数据、云计算、物联网等为代表，始于 21 世纪初, imageUrl=null)], answer=A, analysis=A 正确，第一次工业革命始于英国，以蒸汽机的广泛应用为标志；B 错误，第二次工\n业革命以电力的广泛应用为标志，主要发生在德国、美国、英国等；C 错误，第三次工业革\n命以计算机技术、信息技术为代表，始于 20 世纪 50 年代；D错误，第四次工业革命以人工\n智能、大数据、云计算、物联网等为代表，始于 21 世纪 10 年代。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=176, content=关于我国行政区划，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国共有 34 个省级行政区，包括 23 个省、5 个自治区、4 个直辖市、2 个特别行政区, imageUrl=null), Option(key=B, value=我国面积最大的省级行政区是新疆维吾尔自治区, imageUrl=null), Option(key=C, value=我国人口最多的省级行政区是广东省, imageUrl=null), Option(key=D, value=我国海岸线最长的省级行政区是广东省, imageUrl=null)], answer=A, analysis=A 正确，我国共有 34 个省级行政区，包括 23 个省、5 个自治区、4 个直辖市、2 个\n特别行政区；B 正确，新疆维吾尔自治区是我国面积最大的省级行政区；C 正确，广东省是\n我国人口最多的省级行政区；D 错误，我国海岸线最长的省级行政区是广东省，但本题 A 项\n表述最完整准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=177, content=关于我国环境保护法律法规，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=《环境保护法》于 1989 年颁布实施，是我国第一部综合性环境保护法律, imageUrl=null), Option(key=B, value=《大气污染防治法》于 2015 年修订，首次将\"大气污染防治\"写入法律, imageUrl=null), Option(key=C, value=《水污染防治法》于 2017 年修订，首次将\"水污染防治\"写入法律, imageUrl=null), Option(key=D, value=《土壤污染防治法》于 2018 年颁布实施，是我国首部土壤污染防治领域的专门法律, imageUrl=null)], answer=D, analysis=A 错误，《环境保护法》于 1989 年颁布实施，但不是第一部综合性环境保护法律；B\n错误，《大气污染防治法》于 2015 年修订，但不是首次将\"大气污染防治\"写入法律；C 错误，\n《水污染防治法》于 2017 年修订，但不是首次将\"水污染防治\"写入法律；D 正确，《土壤污\n染防治法》于 2018 年颁布实施，是我国首部土壤污染防治领域的专门法律。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=178, content=关于我国能源发展，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国是世界上最大的能源生产国和消费国, imageUrl=null), Option(key=B, value=我国煤炭消费占能源消费总量的比重已降至 50%以下, imageUrl=null), Option(key=C, value=我国可再生能源装机容量已超过化石能源装机容量, imageUrl=null), Option(key=D, value=我国已成为世界上最大的光伏发电和风电装机国, imageUrl=null)], answer=A, analysis=A 正确，我国是世界上最大的能源生产国和消费国；B 错误，我国煤炭消费占能源消\n费总量的比重仍在 50%以上；C 错误，我国可再生能源装机容量尚未超过化石能源装机容量；\nD正确，我国已成为世界上最大的光伏发电和风电装机国。本题 A 项表述最全面。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=179, content=关于我国金融体系，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=中国人民银行是我国的中央银行，负责制定和执行货币政策, imageUrl=null), Option(key=B, value=中国银保监会负责对银行业和保险业进行监督管理, imageUrl=null), Option(key=C, value=中国证监会负责对证券业进行监督管理, imageUrl=null), Option(key=D, value=国家外汇管理局负责管理国家外汇储备, imageUrl=null)], answer=A, analysis=A 正确，中国人民银行是我国的中央银行，负责制定和执行货币政策；B 正确，中国\n银保监会负责对银行业和保险业进行监督管理；C 正确，中国证监会负责对证券业进行监督\n管理；D 正确，国家外汇管理局负责管理国家外汇储备。本题 A 项表述最核心。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=180, content=关于我国教育法律法规，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=《教育法》于 1995 年颁布实施，是我国教育领域的根本大法, imageUrl=null), Option(key=B, value=《义务教育法》于 2006 年修订，首次将\"义务教育\"写入法律, imageUrl=null), Option(key=C, value=《高等教育法》于 1998 年颁布实施，是我国高等教育领域的基本法律, imageUrl=null), Option(key=D, value=《教师法》于 1993 年颁布实施，首次将\"教师\"职业写入法律, imageUrl=null)], answer=A, analysis=A 正确，《教育法》于 1995 年颁布实施，是我国教育领域的根本大法；B 错误，《义\n务教育法》于 2006 年修订，但不是首次将\"义务教育\"写入法律；C 正确，《高等教育法》于\n1998 年颁布实施，是我国高等教育领域的基本法律；D 错误，《教师法》于 1993 年颁布实\n施，但不是首次将\"教师\"职业写入法律。本题 A 项表述最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=181, content=关于我国交通运输发展，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国高速公路总里程已超过 17 万公里，居世界第一, imageUrl=null), Option(key=B, value=我国高速铁路总里程已超过 4 万公里，居世界第一, imageUrl=null), Option(key=C, value=我国港口货物吞吐量已连续多年居世界第一, imageUrl=null), Option(key=D, value=我国机场数量已超过 500 个，居世界第一, imageUrl=null)], answer=A, analysis=A 正确，我国高速公路总里程已超过 17 万公里，居世界第一；B 正确，我国高速铁\n路总里程已超过 4 万公里，居世界第一；C 正确，我国港口货物吞吐量已连续多年居世界第\n一；D错误，我国机场数量已超过 500 个，但不是世界第一。本题 A 项表述最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=182, content=关于我国农业发展，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国是世界上最大的农产品生产国和消费国, imageUrl=null), Option(key=B, value=我国粮食产量已连续多年稳定在 6.5 亿吨以上, imageUrl=null), Option(key=C, value=我国水稻、小麦、玉米三大主粮自给率均超过 95%, imageUrl=null), Option(key=D, value=我国已成为世界上最大的农产品进口国, imageUrl=null)], answer=A, analysis=A 正确，我国是世界上最大的农产品生产国和消费国；B 正确，我国粮食产量已连续\n多年稳定在 6.5 亿吨以上；C 正确，我国水稻、小麦、玉米三大主粮自给率均超过 95%；D\n正确，我国已成为世界上最大的农产品进口国。本题 A 项表述最全面。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=183, content=关于我国社会保障体系，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国已建成世界上最大的社会保障体系, imageUrl=null), Option(key=B, value=我国基本养老保险参保人数已超过 10 亿人, imageUrl=null), Option(key=C, value=我国基本医疗保险参保率已超过 95%, imageUrl=null), Option(key=D, value=我国失业保险参保人数已超过 2 亿人, imageUrl=null)], answer=A, analysis=A 正确，我国已建成世界上最大的社会保障体系；B 正确，我国基本养老保险参保人\n数已超过 10 亿人；C 正确，我国基本医疗保险参保率已超过 95%；D 正确，我国失业保险\n参保人数已超过 2 亿人。本题 A 项表述最全面。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=184, content=关于我国科技创新，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国研发经费投入已超过 2.5 万亿元，居世界第二, imageUrl=null), Option(key=B, value=我国专利申请量已连续多年居世界第一, imageUrl=null), Option(key=C, value=我国高新技术企业数量已超过 30 万家, imageUrl=null), Option(key=D, value=我国已成为世界上最大的科技人力资源国, imageUrl=null)], answer=A, analysis=A 正确，我国研发经费投入已超过 2.5 万亿元，居世界第二；B 正确，我国专利申请\n量已连续多年居世界第一；C 正确，我国高新技术企业数量已超过 30 万家；D 正确，我国\n已成为世界上最大的科技人力资源国。本题 A 项表述最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=185, content=关于我国文化产业发展，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国文化产业增加值已超过 5 万亿元，占 GDP 比重超过 4%, imageUrl=null), Option(key=B, value=我国电影票房收入已超过 600 亿元，居世界第一, imageUrl=null), Option(key=C, value=我国图书出版品种已超过 50 万种，居世界第一, imageUrl=null), Option(key=D, value=我国网络游戏市场规模已超过 3000 亿元，居世界第一, imageUrl=null)], answer=A, analysis=A 正确，我国文化产业增加值已超过 5 万亿元，占 GDP 比重超过 4%；B 错误，我国\n电影票房收入已超过 600 亿元，但不是世界第一；C 正确，我国图书出版品种已超过 50 万\n种，居世界第一；D 正确，我国网络游戏市场规模已超过 3000 亿元，居世界第一。本题 A\n项表述最全面。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=186, content=关于我国生态文明建设，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国森林覆盖率已超过 23%，森林蓄积量已超过 175 亿立方米, imageUrl=null), Option(key=B, value=我国湿地保护率已超过 50%, imageUrl=null), Option(key=C, value=我国自然保护区面积已超过国土面积的 15%, imageUrl=null), Option(key=D, value=我国荒漠化土地面积已连续多年实现净减少, imageUrl=null)], answer=A, analysis=A 正确，我国森林覆盖率已超过 23%，森林蓄积量已超过 175 亿立方米；B 错误，我\n国湿地保护率已超过 50%，但表述不够准确；C 错误，我国自然保护区面积已超过国土面积\n的 15%，但表述不够准确；D正确，我国荒漠化土地面积已连续多年实现净减少。本题 A 项\n表述最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=187, content=关于我国对外开放，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国已与 180 多个国家和地区建立了外交关系, imageUrl=null), Option(key=B, value=我国已成为世界上最大的货物贸易国, imageUrl=null), Option(key=C, value=我国已成为世界上最大的外资流入国, imageUrl=null), Option(key=D, value=我国已成为世界上最大的对外投资国, imageUrl=null)], answer=A, analysis=A 正确，我国已与 180 多个国家和地区建立了外交关系；B 正确，我国已成为世界上\n最大的货物贸易国；C 错误，我国已成为世界上最大的外资流入国，但表述不够准确；D 错\n误，我国已成为世界上最大的对外投资国，但表述不够准确。本题 A 项表述最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=188, content=关于我国脱贫攻坚，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国已实现现行标准下农村贫困人口全部脱贫, imageUrl=null), Option(key=B, value=我国贫困县已全部摘帽, imageUrl=null), Option(key=C, value=我国消除了绝对贫困, imageUrl=null), Option(key=D, value=我国创造了人类减贫史上的奇迹, imageUrl=null)], answer=A, analysis=A 正确，我国已实现现行标准下农村贫困人口全部脱贫；B 正确，我国贫困县已全部\n摘帽；C 正确，我国消除了绝对贫困；D 正确，我国创造了人类减贫史上的奇迹。本题 A 项\n表述最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=189, content=关于我国疫情防控，下列说法正确的是：, contentImageUrl=null, type=1, options=[Option(key=A, value=我国率先控制住疫情，率先复工复产, imageUrl=null), Option(key=B, value=我国疫苗研发和接种工作走在世界前列, imageUrl=null), Option(key=C, value=我国向国际社会提供了大量疫苗和防疫物资, imageUrl=null), Option(key=D, value=我国为全球抗疫作出了重要贡献, imageUrl=null)], answer=A, analysis=A 正确，我国率先控制住疫情，率先复工复产；B 正确，我国疫苗研发和接种工作走\n在世界前列；C 正确，我国向国际社会提供了大量疫苗和防疫物资；D正确，我国为全球抗\n疫作出了重要贡献。本题 A 项表述最准确。, difficulty=3, category=常识判断, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null)]]', '0:0:0:0:0:0:0:1', 170, '2026-03-12 16:16:19');
