INSERT INTO `sys_log` VALUES (1856, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[184, Question(id=184, content=关于我国科技创新，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=我国研发经费投入已超过 2.5 万亿元，居世界第二, imageUrl=), Option(key=B, value=我国专利申请量已连续多年居世界第一, imageUrl=), Option(key=C, value=我国高新技术企业数量已超过 30 万家, imageUrl=), Option(key=D, value=我国已成为世界上最大的科技人力资源国, imageUrl=)], answer=A, analysis=A 正确，我国研发经费投入已超过 2.5 万亿元，居世界第二；B 正确，我国专利申请\n量已连续多年居世界第一；C 正确，我国高新技术企业数量已超过 30 万家；D 正确，我国\n已成为世界上最大的科技人力资源国。本题 A 项表述最准确。, difficulty=5, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:16:27');
