INSERT INTO `sys_log` VALUES (1860, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[180, Question(id=180, content=关于我国教育法律法规，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=《教育法》于 1995 年颁布实施，是我国教育领域的根本大法, imageUrl=), Option(key=B, value=《义务教育法》于 2006 年修订，首次将\"义务教育\"写入法律, imageUrl=), Option(key=C, value=《高等教育法》于 1998 年颁布实施，是我国高等教育领域的基本法律, imageUrl=), Option(key=D, value=《教师法》于 1993 年颁布实施，首次将\"教师\"职业写入法律, imageUrl=)], answer=A, analysis=A 正确，《教育法》于 1995 年颁布实施，是我国教育领域的根本大法；B 错误，《义\n务教育法》于 2006 年修订，但不是首次将\"义务教育\"写入法律；C 正确，《高等教育法》于\n1998 年颁布实施，是我国高等教育领域的基本法律；D 错误，《教师法》于 1993 年颁布实\n施，但不是首次将\"教师\"职业写入法律。本题 A 项表述最准确。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:16:34');
