INSERT INTO `sys_log` VALUES (1862, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[183, Question(id=183, content=关于我国社会保障体系，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=我国已建成世界上最大的社会保障体系, imageUrl=), Option(key=B, value=我国基本养老保险参保人数已超过 10 亿人, imageUrl=), Option(key=C, value=我国基本医疗保险参保率已超过 95%, imageUrl=), Option(key=D, value=我国失业保险参保人数已超过 2 亿人, imageUrl=)], answer=A, analysis=A 正确，我国已建成世界上最大的社会保障体系；B 正确，我国基本养老保险参保人\n数已超过 10 亿人；C 正确，我国基本医疗保险参保率已超过 95%；D 正确，我国失业保险\n参保人数已超过 2 亿人。本题 A 项表述最全面。, difficulty=3, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:16:40');
