INSERT INTO `sys_log` VALUES (1865, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[179, Question(id=179, content=关于我国金融体系，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=中国人民银行是我国的中央银行，负责制定和执行货币政策, imageUrl=), Option(key=B, value=中国银保监会负责对银行业和保险业进行监督管理, imageUrl=), Option(key=C, value=中国证监会负责对证券业进行监督管理, imageUrl=), Option(key=D, value=国家外汇管理局负责管理国家外汇储备, imageUrl=)], answer=A, analysis=A 正确，中国人民银行是我国的中央银行，负责制定和执行货币政策；B 正确，中国\n银保监会负责对银行业和保险业进行监督管理；C 正确，中国证监会负责对证券业进行监督\n管理；D 正确，国家外汇管理局负责管理国家外汇储备。本题 A 项表述最核心。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:16:55');
