INSERT INTO `sys_log` VALUES (1867, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[178, Question(id=178, content=关于我国能源发展，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=我国是世界上最大的能源生产国和消费国, imageUrl=), Option(key=B, value=我国煤炭消费占能源消费总量的比重已降至 50%以下, imageUrl=), Option(key=C, value=我国可再生能源装机容量已超过化石能源装机容量, imageUrl=), Option(key=D, value=我国已成为世界上最大的光伏发电和风电装机国, imageUrl=)], answer=A, analysis=A 正确，我国是世界上最大的能源生产国和消费国；B 错误，我国煤炭消费占能源消\n费总量的比重仍在 50%以上；C 错误，我国可再生能源装机容量尚未超过化石能源装机容量；\nD正确，我国已成为世界上最大的光伏发电和风电装机国。本题 A 项表述最全面。, difficulty=3, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:16:59');
