INSERT INTO `sys_log` VALUES (1869, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[177, Question(id=177, content=关于我国环境保护法律法规，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=《环境保护法》于 1989 年颁布实施，是我国第一部综合性环境保护法律, imageUrl=), Option(key=B, value=《大气污染防治法》于 2015 年修订，首次将\"大气污染防治\"写入法律, imageUrl=), Option(key=C, value=《水污染防治法》于 2017 年修订，首次将\"水污染防治\"写入法律, imageUrl=), Option(key=D, value=《土壤污染防治法》于 2018 年颁布实施，是我国首部土壤污染防治领域的专门法律, imageUrl=)], answer=D, analysis=A 错误，《环境保护法》于 1989 年颁布实施，但不是第一部综合性环境保护法律；B\n错误，《大气污染防治法》于 2015 年修订，但不是首次将\"大气污染防治\"写入法律；C 错误，\n《水污染防治法》于 2017 年修订，但不是首次将\"水污染防治\"写入法律；D 正确，《土壤污\n染防治法》于 2018 年颁布实施，是我国首部土壤污染防治领域的专门法律。, difficulty=5, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 11, '2026-03-12 16:17:03');
