INSERT INTO `sys_log` VALUES (1875, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[175, Question(id=175, content=关于世界经济发展史，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=第一次工业革命始于英国，以蒸汽机的广泛应用为标志, imageUrl=), Option(key=B, value=第二次工业革命以电力的广泛应用为标志，主要发生在德国和美国, imageUrl=), Option(key=C, value=第三次工业革命以计算机技术、信息技术为代表，始于 20 世纪 40 年代, imageUrl=), Option(key=D, value=第四次工业革命以人工智能、大数据、云计算、物联网等为代表，始于 21 世纪初, imageUrl=)], answer=A, analysis=A 正确，第一次工业革命始于英国，以蒸汽机的广泛应用为标志；B 错误，第二次工\n业革命以电力的广泛应用为标志，主要发生在德国、美国、英国等；C 错误，第三次工业革\n命以计算机技术、信息技术为代表，始于 20 世纪 50 年代；D错误，第四次工业革命以人工\n智能、大数据、云计算、物联网等为代表，始于 21 世纪 10 年代。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:17:16');
