INSERT INTO `sys_log` VALUES (1877, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[174, Question(id=174, content=关于我国古代科技成就，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=《九章算术》是中国古代第一部数学专著，成书于汉代, imageUrl=), Option(key=B, value=《天工开物》是世界上第一部关于农业和手工业生产的综合性著作, imageUrl=), Option(key=C, value=《本草纲目》收录药物 1892 种，方剂 11096 个, imageUrl=), Option(key=D, value=《梦溪笔谈》被英国科学史家李约瑟称为\"中国科学史上的里程碑\", imageUrl=)], answer=C, analysis=A 错误，《九章算术》不是第一部数学专著；《天工开物》是世界上第一部关于农业和\n手工业生产的综合性著作，B 正确；《本草纲目》收录药物 1892 种，方剂 11096 个，C 正确；\n《梦溪笔谈》被李约瑟称为\"中国科学史上的里程碑\"，D 正确。本题 C 项数据最准确。, difficulty=3, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:17:27');
