INSERT INTO `sys_log` VALUES (1879, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[173, Question(id=173, content=关于我国航天事业的发展，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=我国第一颗人造地球卫星\"东方红一号\"于 1970 年 4 月 24 日发射成功, imageUrl=), Option(key=B, value=我国首次载人航天飞行任务由\"神舟五号\"完成，航天员是杨利伟, imageUrl=), Option(key=C, value=我国首次月球软着陆任务由\"嫦娥三号\"完成, imageUrl=), Option(key=D, value=我国首次火星探测任务\"天问一号\"于 2020 年 7 月 23 日发射成功, imageUrl=)], answer=D, analysis=A 正确，\"东方红一号\"于 1970 年 4 月 24 日发射成功；B 正确，\"神舟五号\"完成首次\n载人航天飞行，航天员是杨利伟；C 正确，\"嫦娥三号\"完成首次月球软着陆；D 正确，\"天问\n一号\"于 2020 年 7 月 23 日发射成功。本题四项均正确，但根据题目要求选择最佳答案，D\n项为最新成就。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:17:31');
