INSERT INTO `sys_log` VALUES (1881, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[172, Question(id=172, content=关于我国民法典，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=民法典于 2020 年 5 月 28 日通过，2021 年 1 月 1 日起施行, imageUrl=), Option(key=B, value=民法典共分为七编，包括总则、物权、合同、人格权、婚姻家庭、继承、侵权责任, imageUrl=), Option(key=C, value=民法典首次确立了\"绿色原则\"作为民法基本原则, imageUrl=), Option(key=D, value=民法典废止了《婚姻法》《继承法》《民法通则》《收养法》《担保法》《合同法》《物权法》, imageUrl=)], answer=A, analysis=A 正确，民法典于 2020 年 5 月 28 日通过，2021 年 1 月 1 日起施行；B 错误，民法典\n共分为七编，包括总则、物权、合同、人格权、婚姻家庭、继承、侵权责任，外加附则；C\n错误，\"绿色原则\"在《民法总则》中已确立；D 错误，民法典废止了《婚姻法》《继承法》《民\n法通则》《收养法》《担保法》《合同法》《物权法》《侵权责任法》《民法总则》等九部法律，\n表述正确。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 16:17:35');
