INSERT INTO `sys_log` VALUES (1883, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[171, Question(id=171, content=下列关于我国货币政策工具的表述，正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=存款准备金率属于价格型货币政策工具, imageUrl=), Option(key=B, value=公开市场操作属于数量型货币政策工具, imageUrl=), Option(key=C, value=再贴现率属于数量型货币政策工具, imageUrl=), Option(key=D, value=常备借贷便利属于结构性货币政策工具, imageUrl=)], answer=D, analysis=A 错误，存款准备金率属于数量型货币政策工具；B 错误，公开市场操作属于数量型\n货币政策工具，但主要通过买卖债券调节基础货币；C 错误，再贴现率属于价格型货币政策\n工具；D 正确，常备借贷便利（SLF）属于结构性货币政策工具。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 8, '2026-03-12 16:17:38');
