INSERT INTO `sys_log` VALUES (1885, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[170, Question(id=170, content=关于我国宪法的发展历程，下列说法正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=1982 年宪法是我国颁布的第一部宪法, imageUrl=), Option(key=B, value=2004 年宪法修正案首次将\"国家尊重和保障人权\"写入宪法, imageUrl=), Option(key=C, value=2018 年宪法修正案将\"习近平新时代中国特色社会主义思想\"写入宪法, imageUrl=), Option(key=D, value=我国现行宪法共经历了五次修正, imageUrl=)], answer=C, analysis=A 错误，1954 年宪法是我国第一部宪法；B 错误，2004 年修正案将\"国家尊重和保障\n人权\"写入宪法，但不是首次；C 正确，2018 年宪法修正案将\"习近平新时代中国特色社会主\n义思想\"写入宪法；D 错误，我国现行宪法共经历了四次修正（1988、1993、1999、2004、\n2018 年共五次）。, difficulty=4, category=常识判断, createdTime=2026-03-12T16:16:18, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 16:17:41');
