INSERT INTO `sys_log` VALUES (1897, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[156, Question(id=156, content=下列关于我国人民法院的表述，正确的是：, contentImageUrl=, type=1, options=[Option(key=A, value=中级人民法院是最高审判机关, imageUrl=), Option(key=B, value=最高人民法院监督地方各级人民法院和专门人民法院的审判工作, imageUrl=), Option(key=C, value=最高人民法院院长每届任期同全国人民代表大会每届任期相同, imageUrl=), Option(key=D, value=最高人民法院院长连续任职不得超过两届, imageUrl=)], answer=B, analysis=最高人民法院监督地方各级人民法院和专门人民法院的审判工作，这是宪法明确规定\n的。A 选项\"最高审判机关\"表述错误， B 选项更体现监督关系；C 选项表述正确，但不是\n核心；D 选项宪法没有规定连续任职不得超过两届。, difficulty=3, category=常识判断, createdTime=2026-03-12T16:09:30, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 16:18:46');
