INSERT INTO `sys_log` VALUES (2053, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[231, Question(id=231, content=面对复杂的国际形势，我国始终坚持______的和平发展道路，既不称霸，也不依附于任何\n大国，赢得了国际社会的广泛尊重。, contentImageUrl=, type=1, options=[Option(key=A, value=坚定不移, imageUrl=), Option(key=B, value=一以贯之, imageUrl=), Option(key=C, value=始终如一, imageUrl=), Option(key=D, value=持之以恒, imageUrl=)], answer=A, analysis=本题考查成语辨析。\"坚定不移\"形容意志坚强，不动摇，常与\"道路\"搭配；\"一以贯之\n\"强调自始至终坚持；\"始终如一\"强调态度不变；\"持之以恒\"强调坚持不懈。\"坚定不移的和\n平发展道路\"是固定搭配，符合语境。, difficulty=2, category=言语理解, createdTime=2026-03-12T17:12:48, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 11, '2026-03-12 17:13:01');
INSERT INTO `sys_log` VALUES (2054, 'teacher02', 'list', 'com.examsystem.controller.teacher.TeacherQuestionController.list', '[1, 10, null, null, 言语理解]', '0:0:0:0:0:0:0:1', 2, '2026-03-12 17:13:01');
INSERT INTO `sys_log` VALUES (2055, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[234, Question(id=234, content=在经济发展过程中，我们不能只追求 GDP 的增长，更要______环境保护，实现经济与环境\n的协调发展。, contentImageUrl=, type=1, options=[Option(key=A, value=重视, imageUrl=), Option(key=B, value=关注, imageUrl=), Option(key=C, value=注重, imageUrl=), Option(key=D, value=兼顾, imageUrl=)], answer=D, analysis=本题考查实词辨析。\"重视\"强调认为重要；\"关注\"强调关心注意；\"注重\"强调重视；\"\n兼顾\"指同时照顾多个方面。语境强调在追求经济增长的同时也要照顾环境保护，\"兼顾\"最\n能体现平衡发展的意思。, difficulty=5, category=言语理解, createdTime=2026-03-12T17:12:48, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 17:13:04');
INSERT INTO `sys_log` VALUES (2056, 'teacher02', 'list', 'com.examsystem.controller.teacher.TeacherQuestionController.list', '[1, 10, null, null, 言语理解]', '0:0:0:0:0:0:0:1', 3, '2026-03-12 17:13:04');
INSERT INTO `sys_log` VALUES (2057, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[237, Question(id=237, content=在信息化时代，网络谣言传播速度极快，容易造成不良影响，因此我们必须______网络谣\n言的传播。, contentImageUrl=, type=1, options=[Option(key=A, value=遏制, imageUrl=), Option(key=B, value=制止, imageUrl=), Option(key=C, value=阻止, imageUrl=), Option(key=D, value=防止, imageUrl=)], answer=A, analysis=本题考查实词辨析。\"遏制\"指用力制止；\"制止\"指强迫使停止；\"阻止\"指使不能前进\n或发展；\"防止\"指预先设法制止。\"遏制\"带有强力制止的意思，符合对网络谣言传播的严厉\n态度。, difficulty=2, category=言语理解, createdTime=2026-03-12T17:12:48, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 11, '2026-03-12 17:13:06');
INSERT INTO `sys_log` VALUES (2058, 'teacher02', 'list', 'com.examsystem.controller.teacher.TeacherQuestionController.list', '[1, 10, null, null, 言语理解]', '0:0:0:0:0:0:0:1', 4, '2026-03-12 17:13:06');
INSERT INTO `sys_log` VALUES (2059, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[238, Question(id=238, content=这个政策出台后，得到了广大人民群众的______，社会反响热烈。, contentImageUrl=, type=1, options=[Option(key=A, value=拥护, imageUrl=), Option(key=B, value=支持, imageUrl=), Option(key=C, value=赞同, imageUrl=), Option(key=D, value=认可, imageUrl=)], answer=A, analysis=本题考查实词辨析。\"拥护\"指赞成并全力支持；\"支持\"指支援、赞同；\"赞同\"指同意、\n赞成；\"认可\"指许可、承认。\"拥护\"程度最强，符合\"社会反响热烈\"的语境。, difficulty=4, category=言语理解, createdTime=2026-03-12T17:12:48, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 17:13:09');
