INSERT INTO `sys_log` VALUES (2071, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[246, Question(id=246, content=这位教授的学术造诣深厚，在学术界______，深受学生和同行的尊敬。, contentImageUrl=, type=1, options=[Option(key=A, value=德高望重, imageUrl=), Option(key=B, value=声名远扬, imageUrl=), Option(key=C, value=名满天下, imageUrl=), Option(key=D, value=举世闻名, imageUrl=)], answer=A, analysis=本题考查成语辨析。\"德高望重\"指品德高尚，名望很大；\"声名远扬\"指名声传播得很\n远；\"名满天下\"指名声极大；\"举世闻名\"指全世界都知道。语境强调教授的品德和学术地位，\n\"德高望重\"最贴切。, difficulty=4, category=言语理解, createdTime=2026-03-12T17:12:48, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 8, '2026-03-12 17:13:26');
