INSERT INTO `sys_log` VALUES (2080, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[232, Question(id=232, content=随着科技的进步，人工智能技术在各个领域______，极大地提高了生产效率，但也引发了\n一些伦理道德方面的争议。, contentImageUrl=, type=1, options=[Option(key=A, value=崭露头角, imageUrl=), Option(key=B, value=大显身手, imageUrl=), Option(key=C, value=遍地开花, imageUrl=), Option(key=D, value=异军突起, imageUrl=)], answer=C, analysis=本题考查成语辨析。\"崭露头角\"指初显才能；\"大显身手\"指充分施展本领；\"遍地开花\n\"比喻事物到处发展；\"异军突起\"指新生力量突然出现。语境强调人工智能在\"各个领域\"都得\n到应用，\"遍地开花\"最能体现广泛发展的意思。, difficulty=3, category=言语理解, createdTime=2026-03-12T17:12:48, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 7, '2026-03-12 17:13:42');
