INSERT INTO `sys_log` VALUES (2147, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@4fbe4cb, [Question(id=270, content=某班级有学生 45 人，其中男生比女生多 5 人，则该班级女生有多少人？, contentImageUrl=null, type=1, options=[Option(key=A, value=20, imageUrl=null), Option(key=B, value=25, imageUrl=null), Option(key=C, value=30, imageUrl=null), Option(key=D, value=35, imageUrl=null)], answer=A, analysis=设女生有 x 人，则男生有(x+5)人，根据题意：x+(x+5)=45，解得 2x=40，x=20，所以\n女生有 20 人。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=271, content=某商品原价为 120 元，先提价 20%，再降价 20%，则现价为多少元？, contentImageUrl=null, type=1, options=[Option(key=A, value=115.2, imageUrl=null), Option(key=B, value=120, imageUrl=null), Option(key=C, value=124.8, imageUrl=null), Option(key=D, value=96, imageUrl=null)], answer=A, analysis=提价 20%后价格为 120×(1+20%)=144 元，再降价 20%后价格为 144×(1-20%)=115.2\n元。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=272, content=甲、乙两人同时从 A 地出发前往 B 地，甲每小时走 5 公里，乙每小时走 4 公里，甲比乙早\n到 1 小时，则 A、B 两地相距多少公里？, contentImageUrl=null, type=1, options=[Option(key=A, value=15, imageUrl=null), Option(key=B, value=20, imageUrl=null), Option(key=C, value=25, imageUrl=null), Option(key=D, value=30, imageUrl=null)], answer=B, analysis=设 A、B 两地相距 x 公里，则甲用时 x/5 小时，乙用时 x/4 小时，根据题意：x/4-x/5=1，\n解得 x=20 公里。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=273, content=某数列：1，3，6，10，15，...，则第 6 项是多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=20, imageUrl=null), Option(key=B, value=21, imageUrl=null), Option(key=C, value=22, imageUrl=null), Option(key=D, value=23, imageUrl=null)], answer=B, analysis=观察数列规律，相邻两项的差分别为 2、3、4、5，所以第 6 项与第 5 项的差为 6，第\n6 项=15+6=21。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=274, content=一个长方体的长、宽、高分别为 4cm、3cm、2cm，则其表面积为多少平方厘米？, contentImageUrl=null, type=1, options=[Option(key=A, value=24, imageUrl=null), Option(key=B, value=36, imageUrl=null), Option(key=C, value=48, imageUrl=null), Option(key=D, value=52, imageUrl=null)], answer=D, analysis=长方体表面积=2×(长×宽+长×高+宽×高)=2×(4×3+4×2+3×2)=2×(12+8+6)=52 平\n方厘米。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=275, content=某公司有员工 80 人，其中技术人员占 40%，管理人员占 25%，则其他人员有多少人？, contentImageUrl=null, type=1, options=[Option(key=A, value=24, imageUrl=null), Option(key=B, value=28, imageUrl=null), Option(key=C, value=32, imageUrl=null), Option(key=D, value=36, imageUrl=null)], answer=B, analysis=技术人员=80×40%=32 人，管理人员=80×25%=20 人，其他人员=80-32-20=28 人。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=276, content=甲、乙、丙三人分一批苹果，甲分得总数的 1/3，乙分得总数的 1/4，丙分得剩下的 25 个，\n则这批苹果共有多少个？, contentImageUrl=null, type=1, options=[Option(key=A, value=48, imageUrl=null), Option(key=B, value=60, imageUrl=null), Option(key=C, value=72, imageUrl=null), Option(key=D, value=84, imageUrl=null)], answer=B, analysis=设总数为 x 个，丙分得 x-(1/3)x-(1/4)x=(5/12)x，根据题意：(5/12)x=25，解得 x=60 个。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=277, content=某数除以 3 余 2，除以 5 余 3，除以 7 余 4，则这个数最小是多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=23, imageUrl=null), Option(key=B, value=53, imageUrl=null), Option(key=C, value=83, imageUrl=null), Option(key=D, value=113, imageUrl=null)], answer=B, analysis=这个数加 1 后能被 3、5、7 整除，3、5、7 的最小公倍数为 105，所以这个数最小为\n105-1=104，但 104 除以 7 余 5，不符合。继续寻找，下一个满足条件的是 53，53÷3=17 余\n2，53÷5=10 余 3，53÷7=7 余 4，符合条件。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=278, content=一辆汽车从甲地开往乙地，去程速度为 60km/h，回程速度为 40km/h，则往返的平均速度\n是多少 km/h？, contentImageUrl=null, type=1, options=[Option(key=A, value=48, imageUrl=null), Option(key=B, value=50, imageUrl=null), Option(key=C, value=52, imageUrl=null), Option(key=D, value=54, imageUrl=null)], answer=A, analysis=设单程距离为 x 公里，则去程用时 x/60 小时，回程用时 x/40 小时，总用时\n=x/60+x/40=x/24 小时，总路程=2x 公里，平均速度=2x÷(x/24)=48km/h。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=279, content=某水池有进水管和出水管，单开进水管 6 小时可将水池注满，单开出水管 8 小时可将水\n池排空，若两管同时开，几小时可将水池注满？, contentImageUrl=null, type=1, options=[Option(key=A, value=12, imageUrl=null), Option(key=B, value=24, imageUrl=null), Option(key=C, value=36, imageUrl=null), Option(key=D, value=48, imageUrl=null)], answer=B, analysis=进水管每小时注水 1/6，出水管每小时排水 1/8，同时开每小时注水 1/6-1/8=1/24，\n所以需要 24 小时注满。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=280, content=甲、乙两人合作完成一项工作，甲单独做需要 10 天，乙单独做需要 15 天，则两人合作\n需要多少天完成？, contentImageUrl=null, type=1, options=[Option(key=A, value=4, imageUrl=null), Option(key=B, value=5, imageUrl=null), Option(key=C, value=6, imageUrl=null), Option(key=D, value=7, imageUrl=null)], answer=C, analysis=甲的工作效率为 1/10，乙的工作效率为 1/15，两人合作效率为 1/10+1/15=1/6，所以\n需要 6 天完成。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=281, content=某商店进价 100 元的商品，按标价 150 元出售，实际按标价打 8 折销售，则利润率是多\n少？, contentImageUrl=null, type=1, options=[Option(key=A, value=20%, imageUrl=null), Option(key=B, value=25%, imageUrl=null), Option(key=C, value=30%, imageUrl=null), Option(key=D, value=35%, imageUrl=null)], answer=A, analysis=实际售价=150×0.8=120 元，利润=120-100=20 元，利润率=20÷100×100%=20%。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=282, content=一个圆形花坛的直径为 10 米，则其面积是多少平方米？（π取 3.14）, contentImageUrl=null, type=1, options=[Option(key=A, value=31.4, imageUrl=null), Option(key=B, value=78.5, imageUrl=null), Option(key=C, value=157, imageUrl=null), Option(key=D, value=314, imageUrl=null)], answer=B, analysis=半径=10÷2=5 米，面积=π×r²=3.14×25=78.5 平方米。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=283, content=甲、乙两车同时从 A、B 两地相向而行，甲车速度为 50km/h，乙车速度为 70km/h，2 小\n时后相遇，则 A、B 两地相距多少公里？, contentImageUrl=null, type=1, options=[Option(key=A, value=200, imageUrl=null), Option(key=B, value=240, imageUrl=null), Option(key=C, value=280, imageUrl=null), Option(key=D, value=320, imageUrl=null)], answer=B, analysis=两车相对速度=50+70=120km/h，2 小时相遇，所以 A、B 两地相距 120×2=240 公里。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=284, content=某数列：2，5，11，23，47，...，则第 5 项是多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=47, imageUrl=null), Option(key=B, value=95, imageUrl=null), Option(key=C, value=96, imageUrl=null), Option(key=D, value=97, imageUrl=null)], answer=B, analysis=观察数列规律，后一项=前一项×2+1，所以第 5 项=47×2+1=95。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=285, content=某班级有学生 40 人，其中喜欢语文的有 25 人，喜欢数学的有 30 人，两门都不喜欢的有\n3 人，则两门都喜欢的有多少人？, contentImageUrl=null, type=1, options=[Option(key=A, value=15, imageUrl=null), Option(key=B, value=18, imageUrl=null), Option(key=C, value=20, imageUrl=null), Option(key=D, value=22, imageUrl=null)], answer=B, analysis=至少喜欢一门的有 40-3=37 人，设两门都喜欢的有 x 人，则 25+30-x=37，解得 x=18\n人。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=286, content=一个正方体的棱长为 3cm，则其体积是多少立方厘米？, contentImageUrl=null, type=1, options=[Option(key=A, value=9, imageUrl=null), Option(key=B, value=18, imageUrl=null), Option(key=C, value=27, imageUrl=null), Option(key=D, value=54, imageUrl=null)], answer=C, analysis=正方体体积=棱长³=3³=27 立方厘米。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=287, content=甲、乙两人年龄之和为 60 岁，5 年前甲的年龄是乙的 2 倍，则甲现在多少岁？, contentImageUrl=null, type=1, options=[Option(key=A, value=30, imageUrl=null), Option(key=B, value=35, imageUrl=null), Option(key=C, value=40, imageUrl=null), Option(key=D, value=45, imageUrl=null)], answer=B, analysis=设乙现在 x 岁，则甲现在(60-x)岁，5 年前乙(x-5)岁，甲(60-x-5)=(55-x)岁，根据题意：\n55-x=2(x-5)，解得 x=25，甲现在 60-25=35 岁。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=288, content=某商品先降价 20%，再提价 20%，则现价是原价的百分之几？, contentImageUrl=null, type=1, options=[Option(key=A, value=96%, imageUrl=null), Option(key=B, value=100%, imageUrl=null), Option(key=C, value=104%, imageUrl=null), Option(key=D, value=120%, imageUrl=null)], answer=A, analysis=设原价为 100，降价 20%后为 80，再提价 20%后为 80×1.2=96，所以现价是原价的\n96%。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=289, content=某水池有甲、乙两个进水管，单开甲管 4 小时可注满，单开乙管 6 小时可注满，若两管\n同时开，几小时可注满？, contentImageUrl=null, type=1, options=[Option(key=A, value=2, imageUrl=null), Option(key=B, value=2.4, imageUrl=null), Option(key=C, value=2.5, imageUrl=null), Option(key=D, value=3, imageUrl=null)], answer=B, analysis=甲管每小时注水 1/4，乙管每小时注水 1/6，两管同时开每小时注水 1/4+1/6=5/12，\n所以需要 1÷(5/12)=12/5=2.4 小时注满。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null)]]', '0:0:0:0:0:0:0:1', 172, '2026-03-12 17:31:49');
