INSERT INTO `sys_log` VALUES (2149, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[272, Question(id=272, content=甲、乙两人同时从 A 地出发前往 B 地，甲每小时走 5 公里，乙每小时走 4 公里，甲比乙早\n到 1 小时，则 A、B 两地相距多少公里？, contentImageUrl=, type=1, options=[Option(key=A, value=15, imageUrl=), Option(key=B, value=20, imageUrl=), Option(key=C, value=25, imageUrl=), Option(key=D, value=30, imageUrl=)], answer=B, analysis=设 A、B 两地相距 x 公里，则甲用时 x/5 小时，乙用时 x/4 小时，根据题意：x/4-x/5=1，\n解得 x=20 公里。, difficulty=2, category=数量关系, createdTime=2026-03-12T17:31:49, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 17:31:53');
