INSERT INTO `sys_log` VALUES (2153, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[276, Question(id=276, content=甲、乙、丙三人分一批苹果，甲分得总数的 1/3，乙分得总数的 1/4，丙分得剩下的 25 个，\n则这批苹果共有多少个？, contentImageUrl=, type=1, options=[Option(key=A, value=48, imageUrl=), Option(key=B, value=60, imageUrl=), Option(key=C, value=72, imageUrl=), Option(key=D, value=84, imageUrl=)], answer=B, analysis=设总数为 x 个，丙分得 x-(1/3)x-(1/4)x=(5/12)x，根据题意：(5/12)x=25，解得 x=60 个。, difficulty=2, category=数量关系, createdTime=2026-03-12T17:31:49, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 17:31:58');
