INSERT INTO `sys_log` VALUES (2200, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@695f94e, [Question(id=290, content=某工程队计划完成一项工程，如果由甲队单独完成需要 20 天，乙队单独完成需要 30 天。\n现在甲队先单独工作 5 天，然后乙队加入一起工作，问完成这项工程总共需要多少天？, contentImageUrl=null, type=1, options=[Option(key=A, value=12 天, imageUrl=null), Option(key=B, value=13 天, imageUrl=null), Option(key=C, value=14 天, imageUrl=null), Option(key=D, value=15 天, imageUrl=null)], answer=C, analysis=甲队每天完成工程的 1/20，乙队每天完成工程的 1/30。甲队单独工作 5天完成 5/20=1/4。\n剩余 3/4 由两队合作完成，合作每天完成 1/20+1/30=1/12，需要(3/4)÷(1/12)=9 天。总共\n5+9=14 天。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=291, content=某工厂生产一批零件，原计划每天生产 120 个，实际每天比计划多生产 30 个，结果提前 5\n天完成任务。问这批零件共有多少个？, contentImageUrl=null, type=1, options=[Option(key=A, value=2400 个, imageUrl=null), Option(key=B, value=2700 个, imageUrl=null), Option(key=C, value=3000 个, imageUrl=null), Option(key=D, value=3300 个, imageUrl=null)], answer=C, analysis=设原计划需要 x天完成任务，则实际用了 x-5天。120x=150(x-5)，120x=150x-750，30x=750，\nx=25 天。零件总数=120×25=3000 个。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=292, content=某商店进购一批商品，进价为每件 80 元，按标价的 8 折出售，仍可获得 20%的利润。问\n该商品的标价是多少元？, contentImageUrl=null, type=1, options=[Option(key=A, value=100 元, imageUrl=null), Option(key=B, value=110 元, imageUrl=null), Option(key=C, value=120 元, imageUrl=null), Option(key=D, value=130 元, imageUrl=null)], answer=C, analysis=设标价为 x 元，则售价为 0.8x 元。利润率为 20%，所以售价=进价×(1+20%)=80×1.2=96\n元。因此 0.8x=96，x=120 元。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=293, content=甲、乙、丙三人合作完成一项工作，甲单独完成需要 10 天，乙单独完成需要 15 天，丙单\n独完成需要 20 天。如果三人合作，中途甲因事离开，实际用了 6 天完成工作。问甲工作了\n几天？, contentImageUrl=null, type=1, options=[Option(key=A, value=3 天, imageUrl=null), Option(key=B, value=4 天, imageUrl=null), Option(key=C, value=5 天, imageUrl=null), Option(key=D, value=6 天, imageUrl=null)], answer=A, analysis=设甲工作了 x 天，则乙和丙都工作了 6 天。甲每天完成 1/10，乙每天完成 1/15，丙\n每天完成 1/20。根据题意：x/10+6/15+6/20=1，即 x/10+2/5+3/10=1，x/10+7/10=1，x/10=3/10，\nx=3 天。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=294, content=某工厂生产一批零件，原计划每天生产 150 个，实际每天比计划多生产 50 个，结果提前 4\n天完成任务。问这批零件共有多少个？, contentImageUrl=null, type=1, options=[Option(key=A, value=1800 个, imageUrl=null), Option(key=B, value=2000 个, imageUrl=null), Option(key=C, value=2200 个, imageUrl=null), Option(key=D, value=2400 个, imageUrl=null)], answer=D, analysis=设原计划需要 x天完成任务，则实际用了 x-4天。150x=200(x-4)，150x=200x-800，50x=800，\nx=16 天。零件总数=150×16=2400 个。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=295, content=一个水池有进水管 A 和出水管 B，单独开 A 管 10 小时可注满水池，单独开 B 管 15 小时可\n排空水池。如果同时打开 A 管和 B 管，多少小时可以注满水池？, contentImageUrl=null, type=1, options=[Option(key=A, value=20 小时, imageUrl=null), Option(key=B, value=25 小时, imageUrl=null), Option(key=C, value=30 小时, imageUrl=null), Option(key=D, value=35 小时, imageUrl=null)], answer=C, analysis=A 管每小时注满水池的 1/10，B 管每小时排空水池的 1/15。同时开 A 管和 B 管，每\n小时净注满水池的 1/10-1/15=1/30。注满水池需要 1÷(1/30)=30 小时。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=296, content=甲、乙两人在环形跑道上跑步，跑道长 400 米。甲的速度为 6m/s，乙的速度为 4m/s。两\n人同时从同一点出发，同向而行。问多少秒后甲第一次追上乙？, contentImageUrl=null, type=1, options=[Option(key=A, value=100 秒, imageUrl=null), Option(key=B, value=150 秒, imageUrl=null), Option(key=C, value=200 秒, imageUrl=null), Option(key=D, value=250 秒, imageUrl=null)], answer=C, analysis=甲比乙快 2m/s，要追上乙需要多跑一圈 400 米。追上时间=400÷(6-4)=400÷2=200\n秒。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=297, content=某公司有员工 100 人，其中男性占 60%。在男性员工中，本科及以上学历占 70%；在女性\n员工中，本科及以上学历占 50%。问该公司本科及以上学历的员工有多少人？, contentImageUrl=null, type=1, options=[Option(key=A, value=50 人, imageUrl=null), Option(key=B, value=55 人, imageUrl=null), Option(key=C, value=60 人, imageUrl=null), Option(key=D, value=62 人, imageUrl=null)], answer=D, analysis=男性员工=100×60%=60 人，本科及以上学历的男性=60×70%=42 人。女性员工\n=100-60=40 人，本科及以上学历的女性=40×50%=20 人。本科及以上学历总人数=42+20=62\n人。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=298, content=一个正方体的棱长增加 20%，则其表面积增加多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=20%, imageUrl=null), Option(key=B, value=36%, imageUrl=null), Option(key=C, value=44%, imageUrl=null), Option(key=D, value=56%, imageUrl=null)], answer=C, analysis=设原棱长为 a，原表面积=6a²。新棱长=1.2a，新表面积=6×(1.2a)²=6×1.44a²=8.64a\n²。表面积增加=(8.64a²-6a²)÷6a²×100%=2.64a²÷6a²×100%=44%。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=299, content=某项工程，甲队单独完成需要 15 天，乙队单独完成需要 20 天。两队合作若干天后，甲\n队因事离开，乙队继续工作，共用了 12 天完成工程。问甲队工作了几天？, contentImageUrl=null, type=1, options=[Option(key=A, value=6 天, imageUrl=null), Option(key=B, value=7 天, imageUrl=null), Option(key=C, value=8 天, imageUrl=null), Option(key=D, value=9 天, imageUrl=null)], answer=B, analysis=设甲队工作了 x 天，则乙队工作了 12 天。甲队每天完成 1/15，乙队每天完成 1/20。\n根据题意：x/15+12/20=1，即 x/15+3/5=1，x/15=2/5，x=6 天。但选项 A 是 6 天，重新检查：\n12/20=3/5=9/15，所以 x/15+9/15=1，x/15=6/15，x=6 天。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=300, content=某商品原价为 200 元，先提价 20%，再降价 20%，问现价是多少元？, contentImageUrl=null, type=1, options=[Option(key=A, value=192 元, imageUrl=null), Option(key=B, value=196 元, imageUrl=null), Option(key=C, value=200 元, imageUrl=null), Option(key=D, value=204 元, imageUrl=null)], answer=A, analysis=提价 20%后价格=200×1.2=240 元。降价 20%后价格=240×0.8=192 元。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=301, content=甲、乙、丙三人分一批苹果，甲得总数的 1/3，乙得总数的 1/4，丙得总数的 1/5。三人\n分完后还剩 20 个苹果。问这批苹果共有多少个？, contentImageUrl=null, type=1, options=[Option(key=A, value=100 个, imageUrl=null), Option(key=B, value=120 个, imageUrl=null), Option(key=C, value=150 个, imageUrl=null), Option(key=D, value=180 个, imageUrl=null)], answer=B, analysis=设总数为 x 个，则 x/3+x/4+x/5+20=x。通分：20x/60+15x/60+12x/60+20=x，47x/60+20=x，\n20=13x/60，x=120 个。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=302, content=一个圆柱的底面半径增加 50%，高减少 50%，则其体积如何变化？, contentImageUrl=null, type=1, options=[Option(key=A, value=不变, imageUrl=null), Option(key=B, value=增加 12.5%, imageUrl=null), Option(key=C, value=减少 12.5%, imageUrl=null), Option(key=D, value=减少 25%, imageUrl=null)], answer=C, analysis=设原半径为 r，高为 h，原体积=πr²h。新半径=1.5r，新高=0.5h，新体积=π×(1.5r)\n²×0.5h=π×2.25r²×0.5h=1.125πr²h。体积变化=(1.125πr²h-πr²h)÷πr²h×100%=12.5%。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=303, content=甲、乙两人合作完成一项工作，甲单独完成需要 12 天，乙单独完成需要 18 天。如果两\n人合作，中途乙因事离开，实际用了 8 天完成工作。问乙工作了几天？, contentImageUrl=null, type=1, options=[Option(key=A, value=4 天, imageUrl=null), Option(key=B, value=5 天, imageUrl=null), Option(key=C, value=6 天, imageUrl=null), Option(key=D, value=7 天, imageUrl=null)], answer=C, analysis=设乙工作了 x 天，则甲工作了 8 天。甲每天完成 1/12，乙每天完成 1/18。根据题意：\n8/12+x/18=1，即 2/3+x/18=1，x/18=1/3，x=6 天。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=304, content=甲、乙两人同时从 A 地出发前往 B 地，甲速度为 5km/h，乙速度为 3km/h。甲到达 B 地\n后立即返回，在距离 B 地 6km 处与乙相遇。问 A、B 两地的距离是多少千米？, contentImageUrl=null, type=1, options=[Option(key=A, value=18km, imageUrl=null), Option(key=B, value=21km, imageUrl=null), Option(key=C, value=24km, imageUrl=null), Option(key=D, value=27km, imageUrl=null)], answer=C, analysis=设 AB 距离为 S。甲到达 B 地用时 S/5 小时，此时乙行驶了 3×S/5=3S/5 千米，距离 B\n地还有 S-3S/5=2S/5 千米。甲从 B 地返回，乙继续前行。两车相遇时，甲行驶了 6 千米，用\n时 6÷5=1.2小时。乙在这 1.2小时内行驶了 3×1.2=3.6千米。相遇时乙距离 B地还有 2S/5-3.6\n千米。但题目说相遇时距离 B 地 6km，所以 2S/5-3.6=6，2S/5=9.6，S=24km。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=305, content=甲、乙两车同时从 A 地出发前往 B 地，甲车速度为 80km/h，乙车速度为 60km/h。甲车\n到达 B 地后立即返回，在距离 B 地 40km 处与乙车相遇。问 A、B 两地的距离是多少千米？, contentImageUrl=null, type=1, options=[Option(key=A, value=240km, imageUrl=null), Option(key=B, value=280km, imageUrl=null), Option(key=C, value=320km, imageUrl=null), Option(key=D, value=360km, imageUrl=null)], answer=B, analysis=设 AB 距离为 S。甲车到达 B 地用时 S/80 小时，此时乙车行驶了 60×S/80=3S/4 千米，\n距离 B 地还有 S-3S/4=S/4 千米。甲车从 B 地返回，乙车继续前行。两车相遇时，甲车行驶\n了 40 千米，用时 40÷80=0.5 小时。乙车在这 0.5 小时内行驶了 60×0.5=30 千米。相遇时乙\n车距离 B 地还有 S/4-30 千米。但题目说相遇时距离 B 地 40km，所以 S/4-30=40，S/4=70，\nS=280km。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=306, content=某商店进购一批商品，进价为每件 60 元，按标价出售可获得 25%的利润。如果按标价的\n8 折出售，问利润率是多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=0%, imageUrl=null), Option(key=B, value=5%, imageUrl=null), Option(key=C, value=10%, imageUrl=null), Option(key=D, value=15%, imageUrl=null)], answer=A, analysis=设标价为 x 元，则 x=60×(1+25%)=75 元。按 8 折出售，售价=75×0.8=60 元。利润率\n=(60-60)÷60×100%=0%。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=307, content=某班有学生 45 人，其中喜欢数学的有 27 人，喜欢语文的有 18 人，喜欢英语的有 15 人。\n同时喜欢数学和语文的有 12 人，同时喜欢数学和英语的有 9 人，同时喜欢语文和英语的有\n6 人。三门都喜欢的有 3 人。问三门都不喜欢的有多少人？, contentImageUrl=null, type=1, options=[Option(key=A, value=6 人, imageUrl=null), Option(key=B, value=9 人, imageUrl=null), Option(key=C, value=12 人, imageUrl=null), Option(key=D, value=15 人, imageUrl=null)], answer=B, analysis=只喜欢数学和语文的=12-3=9 人，只喜欢数学和英语的=9-3=6 人，只喜欢语文和英语\n的=6-3=3 人。只喜欢数学的=27-9-6-3=9 人，只喜欢语文的=18-9-3-3=3 人，只喜欢英语的\n=15-6-3-3=3 人。至少喜欢一门的人数=9+3+3+9+6+3+3=36 人。三门都不喜欢的人数=45-36=9\n人。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=308, content=一个长方体的长、宽、高分别为 6cm、4cm、3cm。如果长增加 50%，宽增加 25%，高减\n少 50%，则其体积如何变化？, contentImageUrl=null, type=1, options=[Option(key=A, value=不变, imageUrl=null), Option(key=B, value=增加 6.25%, imageUrl=null), Option(key=C, value=减少 6.25%, imageUrl=null), Option(key=D, value=减少 12.5%, imageUrl=null)], answer=C, analysis=原体积=6×4×3=72cm³。新长=6×1.5=9cm，新宽=4×1.25=5cm，新高=3×0.5=1.5cm。\n新体积=9×5×1.5=67.5cm³。体积变化=(67.5-72)÷72×100%=-4.5÷72×100%=-6.25%。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=309, content=甲、乙两人分别从 A、B 两地同时出发，相向而行。甲的速度为 4km/h，乙的速度为 6km/h。\n两人相遇后，甲继续前行到 B 地，立即返回；乙继续前行到 A 地，立即返回。问两人第二\n次相遇时，乙总共行驶了多少千米？, contentImageUrl=null, type=1, options=[Option(key=A, value=18km, imageUrl=null), Option(key=B, value=24km, imageUrl=null), Option(key=C, value=30km, imageUrl=null), Option(key=D, value=36km, imageUrl=null)], answer=C, analysis=设 AB 距离为 S。第一次相遇时，两人行驶时间相同，甲行驶 4t，乙行驶 6t，4t+6t=S，\nt=S/10。甲第一次行驶 4×S/10=2S/5，乙第一次行驶 6×S/10=3S/5。从第一次相遇到第二次\n相遇，两人共行驶 2S，用时 2S÷(4+6)=S/5 小时。乙在第二次相遇前又行驶了 6×S/5=6S/5。\n乙总路程=3S/5+6S/5=9S/5。如果 S=50/3km，则乙行驶 30km。, difficulty=3, category=数量关系, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null)]]', '0:0:0:0:0:0:0:1', 178, '2026-03-12 17:49:54');
