INSERT INTO `sys_log` VALUES (2204, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[295, Question(id=295, content=一个水池有进水管 A 和出水管 B，单独开 A 管 10 小时可注满水池，单独开 B 管 15 小时可\n排空水池。如果同时打开 A 管和 B 管，多少小时可以注满水池？, contentImageUrl=, type=1, options=[Option(key=A, value=20 小时, imageUrl=), Option(key=B, value=25 小时, imageUrl=), Option(key=C, value=30 小时, imageUrl=), Option(key=D, value=35 小时, imageUrl=)], answer=C, analysis=A 管每小时注满水池的 1/10，B 管每小时排空水池的 1/15。同时开 A 管和 B 管，每\n小时净注满水池的 1/10-1/15=1/30。注满水池需要 1÷(1/30)=30 小时。, difficulty=4, category=数量关系, createdTime=2026-03-12T17:49:53, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 17:50:01');
