INSERT INTO `sys_log` VALUES (2206, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[292, Question(id=292, content=某商店进购一批商品，进价为每件 80 元，按标价的 8 折出售，仍可获得 20%的利润。问\n该商品的标价是多少元？, contentImageUrl=, type=1, options=[Option(key=A, value=100 元, imageUrl=), Option(key=B, value=110 元, imageUrl=), Option(key=C, value=120 元, imageUrl=), Option(key=D, value=130 元, imageUrl=)], answer=C, analysis=设标价为 x 元，则售价为 0.8x 元。利润率为 20%，所以售价=进价×(1+20%)=80×1.2=96\n元。因此 0.8x=96，x=120 元。, difficulty=3, category=数量关系, createdTime=2026-03-12T17:49:53, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 17:50:05');
