INSERT INTO `sys_log` VALUES (2208, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[290, Question(id=290, content=某工程队计划完成一项工程，如果由甲队单独完成需要 20 天，乙队单独完成需要 30 天。\n现在甲队先单独工作 5 天，然后乙队加入一起工作，问完成这项工程总共需要多少天？, contentImageUrl=, type=1, options=[Option(key=A, value=12 天, imageUrl=), Option(key=B, value=13 天, imageUrl=), Option(key=C, value=14 天, imageUrl=), Option(key=D, value=15 天, imageUrl=)], answer=C, analysis=甲队每天完成工程的 1/20，乙队每天完成工程的 1/30。甲队单独工作 5天完成 5/20=1/4。\n剩余 3/4 由两队合作完成，合作每天完成 1/20+1/30=1/12，需要(3/4)÷(1/12)=9 天。总共\n5+9=14 天。, difficulty=4, category=数量关系, createdTime=2026-03-12T17:49:53, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 17:50:08');
