INSERT INTO `sys_log` VALUES (2210, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[291, Question(id=291, content=某工厂生产一批零件，原计划每天生产 120 个，实际每天比计划多生产 30 个，结果提前 5\n天完成任务。问这批零件共有多少个？, contentImageUrl=, type=1, options=[Option(key=A, value=2400 个, imageUrl=), Option(key=B, value=2700 个, imageUrl=), Option(key=C, value=3000 个, imageUrl=), Option(key=D, value=3300 个, imageUrl=)], answer=C, analysis=设原计划需要 x天完成任务，则实际用了 x-5天。120x=150(x-5)，120x=150x-750，30x=750，\nx=25 天。零件总数=120×25=3000 个。, difficulty=4, category=数量关系, createdTime=2026-03-12T17:49:53, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 17:50:11');
