INSERT INTO `sys_log` VALUES (2213, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[301, Question(id=301, content=甲、乙、丙三人分一批苹果，甲得总数的 1/3，乙得总数的 1/4，丙得总数的 1/5。三人\n分完后还剩 20 个苹果。问这批苹果共有多少个？, contentImageUrl=, type=1, options=[Option(key=A, value=100 个, imageUrl=), Option(key=B, value=120 个, imageUrl=), Option(key=C, value=150 个, imageUrl=), Option(key=D, value=180 个, imageUrl=)], answer=B, analysis=设总数为 x 个，则 x/3+x/4+x/5+20=x。通分：20x/60+15x/60+12x/60+20=x，47x/60+20=x，\n20=13x/60，x=120 个。, difficulty=2, category=数量关系, createdTime=2026-03-12T17:49:53, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 8, '2026-03-12 17:50:16');
