INSERT INTO `sys_log` VALUES (2215, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[308, Question(id=308, content=一个长方体的长、宽、高分别为 6cm、4cm、3cm。如果长增加 50%，宽增加 25%，高减\n少 50%，则其体积如何变化？, contentImageUrl=, type=1, options=[Option(key=A, value=不变, imageUrl=), Option(key=B, value=增加 6.25%, imageUrl=), Option(key=C, value=减少 6.25%, imageUrl=), Option(key=D, value=减少 12.5%, imageUrl=)], answer=C, analysis=原体积=6×4×3=72cm³。新长=6×1.5=9cm，新宽=4×1.25=5cm，新高=3×0.5=1.5cm。\n新体积=9×5×1.5=67.5cm³。体积变化=(67.5-72)÷72×100%=-4.5÷72×100%=-6.25%。, difficulty=4, category=数量关系, createdTime=2026-03-12T17:49:53, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 7, '2026-03-12 17:50:19');
