INSERT INTO `sys_log` VALUES (2218, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[307, Question(id=307, content=某班有学生 45 人，其中喜欢数学的有 27 人，喜欢语文的有 18 人，喜欢英语的有 15 人。\n同时喜欢数学和语文的有 12 人，同时喜欢数学和英语的有 9 人，同时喜欢语文和英语的有\n6 人。三门都喜欢的有 3 人。问三门都不喜欢的有多少人？, contentImageUrl=, type=1, options=[Option(key=A, value=6 人, imageUrl=), Option(key=B, value=9 人, imageUrl=), Option(key=C, value=12 人, imageUrl=), Option(key=D, value=15 人, imageUrl=)], answer=B, analysis=只喜欢数学和语文的=12-3=9 人，只喜欢数学和英语的=9-3=6 人，只喜欢语文和英语\n的=6-3=3 人。只喜欢数学的=27-9-6-3=9 人，只喜欢语文的=18-9-3-3=3 人，只喜欢英语的\n=15-6-3-3=3 人。至少喜欢一门的人数=9+3+3+9+6+3+3=36 人。三门都不喜欢的人数=45-36=9\n人。, difficulty=5, category=数量关系, createdTime=2026-03-12T17:49:53, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 17:50:24');
