INSERT INTO `sys_log` VALUES (2344, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@3ffbfb2a, [Question(id=340, content=某公司有甲、乙、丙、丁、戊五位员工，他们分别来自北京、上海、广州、深圳、成都五\n个城市。已知：\n（1）甲不来自北京，也不来自广州；\n（2）乙不来自上海，也不来自深圳；\n（3）丙不来自北京，也不来自成都；\n（4）丁不来自广州，也不来自深圳；\n（5）戊不来自成都。\n如果来自北京的员工比来自上海的员工年龄大，来自上海的员工比来自广州的员工年龄大，\n来自广州的员工比来自深圳的员工年龄大，来自深圳的员工比来自成都的员工年龄大。\n请问，来自北京的员工是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=甲, imageUrl=null), Option(key=B, value=乙, imageUrl=null), Option(key=C, value=丙, imageUrl=null), Option(key=D, value=丁, imageUrl=null)], answer=B, analysis=根据条件（1）（3），甲和丙都不来自北京；根据条件（5），戊不来自成都，所以戊可\n能来自北京。但根据年龄顺序，来自北京的员工年龄最大。如果戊来自北京，那么其他员工\n分别来自其他城市。但这样无法满足所有条件。通过排除法，只有乙可能来自北京。验证：\n乙来自北京，甲来自深圳（不来自北京、广州），丙来自上海（不来自北京、成都），丁来自\n成都（不来自广州、深圳），戊来自广州（不来自成都）。所有条件都满足，且年龄顺序为乙>\n丙>戊>甲>丁，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=341, content=某中学有七位教师：A、B、C、D、E、F、G，他们分别教授语文、数学、英语、物理、化\n学、生物、历史七门课程。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教生物；\n（5）E 不教化学，也不教历史；\n（6）F 不教生物，也不教历史；\n（7）G 不教历史。\n如果教授语文的教师比教授数学的教师教龄长，教授数学的教师比教授英语的教师教龄长，\n教授英语的教师比教授物理的教师教龄长，教授物理的教师比教授化学的教师教龄长，教授\n化学的教师比教授生物的教师教龄长，教授生物的教师比教授历史的教师教龄长。\n请问，教授语文的教师是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=B, imageUrl=null), Option(key=B, value=C, imageUrl=null), Option(key=C, value=D, imageUrl=null), Option(key=D, value=E, imageUrl=null)], answer=C, analysis=根据条件（1），A 不教语文、数学；根据条件（3），C 不教数学、化学；根据条件（7），\nG 不教历史。根据教龄顺序，教授语文的教师教龄最长。通过排除法，只有 D 可能教授语文。\n验证：D 教语文，A 教英语（不教语文、数学），B 教化学（不教英语、物理），C 教历史（不\n教数学、化学），E教数学（不教化学、历史），F 教物理（不教生物、历史），G 教生物（不\n教历史）。所有条件都满足，且教龄顺序为 D>E>A>F>B>G>C，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=342, content=某小区有五栋楼：1 号楼、2 号楼、3 号楼、4 号楼、5 号楼，分别住着张、王、李、赵、\n陈五户人家。已知：\n（1）张不住 1 号楼，也不住 3 号楼；\n（2）王不住 2 号楼，也不住 4 号楼；\n（3）李不住 3 号楼，也不住 5 号楼；\n（4）赵不住 1 号楼，也不住 2 号楼；\n（5）陈不住 4 号楼，也不住 5 号楼。\n如果住在 1 号楼的人家比住在 2 号楼的人家入住时间早，住在 2 号楼的人家比住在 3 号楼的\n人家入住时间早，住在 3 号楼的人家比住在 4 号楼的人家入住时间早，住在 4 号楼的人家比\n住在 5 号楼的人家入住时间早。\n请问，住在 1 号楼的人家是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=张, imageUrl=null), Option(key=B, value=王, imageUrl=null), Option(key=C, value=李, imageUrl=null), Option(key=D, value=陈, imageUrl=null)], answer=D, analysis=根据条件（1），张不住 1 号楼、3 号楼；根据条件（4），赵不住 1 号楼、2 号楼；根\n据条件（5），陈不住 4号楼、5 号楼。根据入住时间顺序，住在 1 号楼的人家入住时间最早。\n通过排除法，只有陈可能住在 1 号楼。验证：陈住 1 号楼，张住 4 号楼（不住 1 号楼、3 号\n楼），王住 5 号楼（不住 2 号楼、4 号楼），李住 2 号楼（不住 3 号楼、5 号楼），赵住 3号楼\n（不住 1 号楼、2 号楼）。所有条件都满足，且入住时间顺序为陈>李>赵>张>王，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=343, content=某公司有六个部门：人事部、财务部、市场部、技术部、运营部、客服部，分别由甲、乙、\n丙、丁、戊、己六位经理负责。已知：\n（1）甲不负责人事部，也不负责财务部；\n（2）乙不负责市场部，也不负责技术部；\n（3）丙不负责财务部，也不负责运营部；\n（4）丁不负责技术部，也不负责客服部；\n（5）戊不负责运营部，也不负责客服部；\n（6）己不负责人事部。\n如果人事部比财务部员工多，财务部比市场部员工多，市场部比技术部员工多，技术部比运\n营部员工多，运营部比客服部员工多。\n请问，人事部的负责人是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=乙, imageUrl=null), Option(key=B, value=丙, imageUrl=null), Option(key=C, value=丁, imageUrl=null), Option(key=D, value=戊, imageUrl=null)], answer=C, analysis=根据条件（1），甲不负责人事部、财务部；根据条件（6），己不负责人事部。根据员\n工数量顺序，人事部员工最多。通过排除法，只有丁可能负责人事部。验证：丁负责人事部，\n甲负责技术部（不负责人事部、财务部），乙负责客服部（不负责市场部、技术部），丙负责\n市场部（不负责财务部、运营部），戊负责财务部（不负责运营部、客服部），己负责运营部\n（不负责人事部）。所有条件都满足，且员工数量顺序为丁>戊>丙>甲>己>乙，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=344, content=某大学有七位教授：A、B、C、D、E、F、G，他们分别毕业于北京大学、清华大学、复旦\n大学、上海交通大学、浙江大学、南京大学、武汉大学七所高校。已知：\n（1）A 不毕业于北京大学，也不毕业于清华大学；\n（2）B 不毕业于复旦大学，也不毕业于上海交通大学；\n（3）C 不毕业于清华大学，也不毕业于浙江大学；\n（4）D 不毕业于上海交通大学，也不毕业于南京大学；\n（5）E 不毕业于浙江大学，也不毕业于武汉大学；\n（6）F 不毕业于南京大学，也不毕业于武汉大学；\n（7）G 不毕业于武汉大学。\n如果毕业于北京大学的教授比毕业于清华大学的教授年龄大，毕业于清华大学的教授比毕业\n于复旦大学的教授年龄大，毕业于复旦大学的教授比毕业于上海交通大学的教授年龄大，毕\n业于上海交通大学的教授比毕业于浙江大学的教授年龄大，毕业于浙江大学的教授比毕业于\n南京大学的教授年龄大，毕业于南京大学的教授比毕业于武汉大学的教授年龄大。\n请问，毕业于北京大学的教授是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=B, imageUrl=null), Option(key=B, value=C, imageUrl=null), Option(key=C, value=D, imageUrl=null), Option(key=D, value=E, imageUrl=null)], answer=C, analysis=根据条件（1），A 不毕业于北京大学、清华大学；根据条件（3），C 不毕业于清华大\n学、浙江大学；根据条件（7），G 不毕业于武汉大学。根据年龄顺序，毕业于北京大学的教\n授年龄最大。通过排除法，只有 D 可能毕业于北京大学。验证：D毕业于北京大学，A 毕业\n于上海交通大学（不毕业于北京大学、清华大学），B 毕业于南京大学（不毕业于复旦大学、\n上海交通大学），C 毕业于武汉大学（不毕业于清华大学、浙江大学），E 毕业于清华大学（不\n毕业于浙江大学、武汉大学），F 毕业于复旦大学（不毕业于南京大学、武汉大学），G 毕业\n于浙江大学（不毕业于武汉大学）。所有条件都满足，且年龄顺序为 D>E>F>A>G>B>C，符合\n条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=345, content=某公司有五位员工：甲、乙、丙、丁、戊，他们分别负责项目 A、项目 B、项目 C、项目 D、\n项目 E。已知：\n（1）甲不负责项目 A，也不负责项目 C；\n（2）乙不负责项目 B，也不负责项目 D；\n（3）丙不负责项目 C，也不负责项目 E；\n（4）丁不负责项目 A，也不负责项目 B；\n（5）戊不负责项目 D，也不负责项目 E。\n如果项目 A 比项目 B 预算高，项目 B 比项目 C 预算高，项目 C 比项目 D 预算高，项目 D 比\n项目 E预算高。\n请问，负责项目 A 的员工是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=乙, imageUrl=null), Option(key=B, value=丙, imageUrl=null), Option(key=C, value=丁, imageUrl=null), Option(key=D, value=戊, imageUrl=null)], answer=A, analysis=根据条件（1），甲不负责项目 A、C；根据条件（4），丁不负责项目 A、B。根据预算\n顺序，项目 A 预算最高。通过排除法，只有乙可能负责项目 A。验证：乙负责项目 A，甲负\n责项目 D（不负责项目 A、C），丙负责项目 B（不负责项目 C、E），丁负责项目 E（不负责项\n目 A、B），戊负责项目 C（不负责项目 D、E）。所有条件都满足，且预算顺序为乙>丙>戊>\n甲>丁，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=346, content=某医院有六位医生：A、B、C、D、E、F，他们分别在内科、外科、儿科、妇科、眼科、耳\n鼻喉科工作。已知：\n（1）A 不在内科，也不在外科；\n（2）B 不在儿科，也不在妇科；\n（3）C 不在外科，也不在眼科；\n（4）D 不在妇科，也不在耳鼻喉科；\n（5）E 不在眼科，也不在耳鼻喉科；\n（6）F 不在内科。\n如果内科医生比外科医生经验丰富，外科医生比儿科医生经验丰富，儿科医生比妇科医生经\n验丰富，妇科医生比眼科医生经验丰富，眼科医生比耳鼻喉科医生经验丰富。\n请问，内科医生是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=B, imageUrl=null), Option(key=B, value=C, imageUrl=null), Option(key=C, value=D, imageUrl=null), Option(key=D, value=E, imageUrl=null)], answer=C, analysis=根据条件（1），A 不在内科、外科；根据条件（6），F 不在内科。根据经验丰富程度\n顺序，内科医生经验最丰富。通过排除法，只有 D 可能在内科。验证：D在内科，A 在眼科\n（不在内科、外科），B 在耳鼻喉科（不在儿科、妇科），C 在妇科（不在外科、眼科），E 在\n外科（不在眼科、耳鼻喉科），F 在儿科（不在内科）。所有条件都满足，且经验丰富程度顺\n序为 D>E>F>C>A>B，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=347, content=某学校有五门课程：语文、数学、英语、物理、化学，分别由 A、B、C、D、E 五位老师教\n授。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教化学；\n（5）E 不教语文，也不教英语。\n如果语文课比数学课课时多，数学课比英语课课时多，英语课比物理课课时多，物理课比化\n学课课时多。\n请问，语文课由哪位老师教授？, contentImageUrl=null, type=1, options=[Option(key=A, value=B, imageUrl=null), Option(key=B, value=C, imageUrl=null), Option(key=C, value=D, imageUrl=null), Option(key=D, value=E, imageUrl=null)], answer=B, analysis=根据条件（1），A 不教语文、数学；根据条件（5），E 不教语文、英语。根据课时顺\n序，语文课课时最多。通过排除法，只有 C 可能教授语文。验证：C 教语文，A 教物理（不\n教语文、数学），B 教化学（不教英语、物理），D 教英语（不教物理、化学），E 教数学（不\n教语文、英语）。所有条件都满足，且课时顺序为 C>E>D>A>B，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=348, content=某公司有七个部门：研发部、市场部、销售部、客服部、人事部、财务部、行政部，分别\n由甲、乙、丙、丁、戊、己、庚七位经理负责。已知：\n（1）甲不负责研发部，也不负责市场部；\n（2）乙不负责销售部，也不负责客服部；\n（3）丙不负责市场部，也不负责人事部；\n（4）丁不负责客服部，也不负责财务部；\n（5）戊不负责人事部，也不负责行政部；\n（6）己不负责财务部，也不负责行政部；\n（7）庚不负责行政部。\n如果研发部比市场部员工多，市场部比销售部员工多，销售部比客服部员工多，客服部比人\n事部员工多，人事部比财务部员工多，财务部比行政部员工多。\n请问，研发部的负责人是谁？, contentImageUrl=null, type=1, options=[Option(key=A, value=乙, imageUrl=null), Option(key=B, value=丙, imageUrl=null), Option(key=C, value=丁, imageUrl=null), Option(key=D, value=戊, imageUrl=null)], answer=C, analysis=根据条件（1），甲不负责研发部、市场部；根据条件（7），庚不负责行政部。根据员\n工数量顺序，研发部员工最多。通过排除法，只有丁可能负责研发部。验证：丁负责研发部，\n甲负责客服部（不负责研发部、市场部），乙负责行政部（不负责销售部、客服部），丙负责\n财务部（不负责市场部、人事部），戊负责市场部（不负责人事部、行政部），己负责销售部\n（不负责财务部、行政部），庚负责人事部（不负责行政部）。所有条件都满足，且员工数量\n顺序为丁>戊>己>甲>庚>丙>乙，符合条件。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=349, content=某小区有六栋楼：1 号楼、2 号楼、3 号楼、4 号楼、5 号楼、6 号楼，分别住着张、王、\n李、赵、陈、刘六户