INSERT INTO `sys_log` VALUES (2351, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[358, Question(id=358, content=某小区有五栋楼：1 号楼、2 号楼、3 号楼、4 号楼、5 号楼，分别住着张、王、李、赵、\n陈五户人家。已知：\n（1）张不住 1 号楼，也不住 3 号楼；\n（2）王不住 2 号楼，也不住 4 号楼；\n（3）李不住 3 号楼，也不住 5 号楼；\n（4）赵不住 1 号楼，也不住 2 号楼；\n（5）陈不住 4 号楼，也不住 5 号楼。\n如果住在 1 号楼的人家比住在 2 号楼的人家入住时间早，住在 2 号楼的人家比住在 3 号楼的\n人家入住时间早，住在 3 号楼的人家比住在 4 号楼的人家入住时间早，住在 4 号楼的人家比\n住在 5 号楼的人家入住时间早。\n请问，住在 1 号楼的人家是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=张, imageUrl=), Option(key=B, value=王, imageUrl=), Option(key=C, value=李, imageUrl=), Option(key=D, value=陈, imageUrl=)], answer=D, analysis=根据条件（1），张不住 1 号楼、3 号楼；根据条件（4），赵不住 1 号楼、2 号楼；根\n据条件（5），陈不住 4号楼、5 号楼。根据入住时间顺序，住在 1 号楼的人家入住时间最早。\n通过排除法，只有陈可能住在 1 号楼。验证：陈住 1 号楼，张住 4 号楼（不住 1 号楼、3 号\n楼），王住 5 号楼（不住 2 号楼、4 号楼），李住 2 号楼（不住 3 号楼、5 号楼），赵住 3号楼\n（不住 1 号楼、2 号楼）。所有条件都满足，且入住时间顺序为陈>李>赵>张>王，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:35, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 7, '2026-03-12 18:10:47');
