INSERT INTO `sys_log` VALUES (2353, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[356, Question(id=356, content=某大学有七位教授：A、B、C、D、E、F、G，他们分别毕业于北京大学、清华大学、复\n旦大学、上海交通大学、浙江大学、南京大学、武汉大学七所高校。已知：\n（1）A 不毕业于北京大学，也不毕业于清华大学；\n（2）B 不毕业于复旦大学，也不毕业于上海交通大学；\n（3）C 不毕业于清华大学，也不毕业于浙江大学；\n（4）D 不毕业于上海交通大学，也不毕业于南京大学；\n（5）E 不毕业于浙江大学，也不毕业于武汉大学；\n（6）F 不毕业于南京大学，也不毕业于武汉大学；\n（7）G 不毕业于武汉大学。\n如果毕业于北京大学的教授比毕业于清华大学的教授年龄大，毕业于清华大学的教授比毕业\n于复旦大学的教授年龄大，毕业于复旦大学的教授比毕业于上海交通大学的教授年龄大，毕\n业于上海交通大学的教授比毕业于浙江大学的教授年龄大，毕业于浙江大学的教授比毕业于\n南京大学的教授年龄大，毕业于南京大学的教授比毕业于武汉大学的教授年龄大。\n请问，毕业于北京大学的教授是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=B, imageUrl=), Option(key=B, value=C, imageUrl=), Option(key=C, value=D, imageUrl=), Option(key=D, value=E, imageUrl=)], answer=C, analysis=根据条件（1），A 不毕业于北京大学、清华大学；根据条件（3），C 不毕业于清华大\n学、浙江大学；根据条件（7），G 不毕业于武汉大学。根据年龄顺序，毕业于北京大学的教\n授年龄最大。通过排除法，只有 D 可能毕业于北京大学。验证：D毕业于北京大学，A 毕业\n于上海交通大学（不毕业于北京大学、清华大学），B 毕业于南京大学（不毕业于复旦大学、\n上海交通大学），C 毕业于武汉大学（不毕业于清华大学、浙江大学），E 毕业于清华大学（不\n毕业于浙江大学、武汉大学），F 毕业于复旦大学（不毕业于南京大学、武汉大学），G 毕业\n于浙江大学（不毕业于武汉大学）。所有条件都满足，且年龄顺序为 D>E>F>A>G>B>C，符合\n条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:35, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 12, '2026-03-12 18:10:50');
