INSERT INTO `sys_log` VALUES (2357, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[354, Question(id=354, content=某学校有六门课程：语文、数学、英语、物理、化学、生物，分别由 A、B、C、D、E、F\n六位老师教授。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教生物；\n（5）E 不教化学，也不教生物；\n（6）F 不教语文。\n如果语文课比数学课课时多，数学课比英语课课时多，英语课比物理课课时多，物理课比化\n学课课时多，化学课比生物课课时多。\n请问，语文课由哪位老师教授？, contentImageUrl=, type=1, options=[Option(key=A, value=B, imageUrl=), Option(key=B, value=C, imageUrl=), Option(key=C, value=D, imageUrl=), Option(key=D, value=E, imageUrl=)], answer=B, analysis=根据条件（1），A 不教语文、数学；根据条件（6），F 不教语文。根据课时顺序，语\n文课课时最多。通过排除法，只有 C 可能教授语文。验证：C 教语文，A 教物理（不教语文、\n数学），B 教生物（不教英语、物理），D 教英语（不教物理、生物），E教数学（不教化学、\n生物），F 教化学（不教语文）。所有条件都满足，且课时顺序为 C>E>D>A>F>B，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:35, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 18:10:56');
