INSERT INTO `sys_log` VALUES (2359, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[361, Question(id=361, content=某公司有七个项目：项目 A、项目 B、项目 C、项目 D、项目 E、项目 F、项目 G，分别由\n甲、乙、丙、丁、戊、己、庚七位项目经理负责。已知：\n（1）甲不负责项目 A，也不负责项目 B；\n（2）乙不负责项目 C，也不负责项目 D；\n（3）丙不负责项目 B，也不负责项目 E；\n（4）丁不负责项目 D，也不负责项目 F；\n（5）戊不负责项目 E，也不负责项目 G；\n（6）己不负责项目 F，也不负责项目 G；\n（7）庚不负责项目 A。\n如果项目 A 比项目 B 利润高，项目 B 比项目 C 利润高，项目 C 比项目 D 利润高，项目 D 比\n项目 E利润高，项目 E 比项目 F 利润高，项目 F 比项目 G 利润高。\n请问，负责项目 A 的项目经理是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=乙, imageUrl=), Option(key=B, value=丙, imageUrl=), Option(key=C, value=丁, imageUrl=), Option(key=D, value=戊, imageUrl=)], answer=C, analysis=根据条件（1），甲不负责项目 A、B；根据条件（7），庚不负责项目 A。根据利润顺\n序，项目 A 利润最高。通过排除法，只有丁可能负责项目 A。验证：丁负责项目 A，甲负责\n项目 E（不负责项目 A、B），乙负责项目 G（不负责项目 C、D），丙负责项目 C（不负责项\n目 B、E），戊负责项目 B（不负责项目 E、G），己负责项目 D（不负责项目 F、G），庚负责\n项目 F（不负责项目 A）。所有条件都满足，且利润顺序为丁>戊>丙>己>甲>庚>乙，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:35, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 18:10:59');
