INSERT INTO `sys_log` VALUES (2368, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[366, Question(id=366, content=某公司有六位员工：A、B、C、D、E、F，他们分别使用 Windows、Mac、Linux、Android、\niOS、ChromeOS 六种操作系统。已知：\n（1）A 不使用 Windows，也不使用 Mac；\n（2）B 不使用 Linux，也不使用 Android；\n（3）C 不使用 Mac，也不使用 iOS；\n（4）D 不使用 Android，也不使用 ChromeOS；\n（5）E 不使用 iOS，也不使用 ChromeOS；\n（6）F 不使用 Windows。\n如果使用 Windows 的员工比使用 Mac 的员工工龄长，使用 Mac 的员工比使用 Linux的员工\n工龄长，使用 Linux 的员工比使用 Android 的员工工龄长，使用 Android 的员工比使用 iOS\n的员工工龄长，使用 iOS 的员工比使用 ChromeOS 的员工工龄长。\n请问，使用 Windows 的员工是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=B, imageUrl=), Option(key=B, value=C, imageUrl=), Option(key=C, value=D, imageUrl=), Option(key=D, value=E, imageUrl=)], answer=C, analysis=根据条件（1），A 不使用 Windows、Mac；根据条件（6），F 不使用 Windows。根据\n工龄顺序，使用 Windows 的员工工龄最长。通过排除法，只有 D 可能使用 Windows。验证：\nD使用 Windows，A 使用 Android（不使用 Windows、Mac），B 使用 ChromeOS（不使用 Linux、\nAndroid），C 使用 Linux（不使用 Mac、iOS），E 使用 Mac（不使用 iOS、ChromeOS），F 使用\niOS（不使用 Windows）。所有条件都满足，且工龄顺序为 D>E>C>A>F>B，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:35, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 18:11:10');
