INSERT INTO `sys_log` VALUES (2377, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[350, Question(id=350, content=某公司有五位员工：甲、乙、丙、丁、戊，他们分别使用 Windows、Mac、Linux、Android、\niOS 五种操作系统。已知：\n（1）甲不使用 Windows，也不使用 Mac；\n（2）乙不使用 Linux，也不使用 Android；\n（3）丙不使用 Mac，也不使用 iOS；\n（4）丁不使用 Android，也不使用 iOS；\n（5）戊不使用 Linux，也不使用 Windows。\n如果使用 Windows 的员工比使用 Mac 的员工工龄长，使用 Mac 的员工比使用 Linux的员工\n工龄长，使用 Linux 的员工比使用 Android 的员工工龄长，使用 Android 的员工比使用 iOS\n的员工工龄长。\n请问，使用 Windows 的员工是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=乙, imageUrl=), Option(key=B, value=丙, imageUrl=), Option(key=C, value=丁, imageUrl=), Option(key=D, value=戊, imageUrl=)], answer=C, analysis=根据条件（1），甲不使用 Windows、Mac；根据条件（5），戊不使用 Linux、Windows。\n根据工龄顺序，使用 Windows 的员工工龄最长。通过排除法，只有丁可能使用 Windows。\n验证：丁使用 Windows，甲使用 Android（不使用 Windows、Mac），乙使用 iOS（不使用 Linux、\nAndroid），丙使用 Linux（不使用 Mac、iOS），戊使用 Mac（不使用 Linux、Windows）。所有\n条件都满足，且工龄顺序为丁>戊>丙>甲>乙，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:34, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 18:11:24');
