INSERT INTO `sys_log` VALUES (2380, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[353, Question(id=353, content=某医院有五位医生：A、B、C、D、E，他们分别在内科、外科、儿科、妇科、眼科工作。\n已知：\n（1）A 不在内科，也不在外科；\n（2）B 不在儿科，也不在妇科；\n（3）C 不在外科，也不在眼科；\n（4）D 不在妇科，也不在眼科；\n（5）E 不在内科，也不在儿科。\n如果内科医生比外科医生职称高，外科医生比儿科医生职称高，儿科医生比妇科医生职称高，\n妇科医生比眼科医生职称高。\n请问，内科医生是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=B, imageUrl=), Option(key=B, value=C, imageUrl=), Option(key=C, value=D, imageUrl=), Option(key=D, value=E, imageUrl=)], answer=C, analysis=根据条件（1），A 不在内科、外科；根据条件（5），E 不在内科、儿科。根据职称顺\n序，内科医生职称最高。通过排除法，只有 D可能在内科。验证：D 在内科，A 在眼科（不\n在内科、外科），B 在妇科（不在儿科、妇科），C 在外科（不在外科、眼科），E 在儿科（不\n在内科、儿科）。所有条件都满足，且职称顺序为 D>C>E>B>A，符合条件。, difficulty=2, category=判断推理, createdTime=2026-03-12T18:10:34, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 18:11:32');
