INSERT INTO `sys_log` VALUES (2382, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[341, Question(id=341, content=某中学有七位教师：A、B、C、D、E、F、G，他们分别教授语文、数学、英语、物理、化\n学、生物、历史七门课程。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教生物；\n（5）E 不教化学，也不教历史；\n（6）F 不教生物，也不教历史；\n（7）G 不教历史。\n如果教授语文的教师比教授数学的教师教龄长，教授数学的教师比教授英语的教师教龄长，\n教授英语的教师比教授物理的教师教龄长，教授物理的教师比教授化学的教师教龄长，教授\n化学的教师比教授生物的教师教龄长，教授生物的教师比教授历史的教师教龄长。\n请问，教授语文的教师是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=B, imageUrl=), Option(key=B, value=C, imageUrl=), Option(key=C, value=D, imageUrl=), Option(key=D, value=E, imageUrl=)], answer=C, analysis=根据条件（1），A 不教语文、数学；根据条件（3），C 不教数学、化学；根据条件（7），\nG 不教历史。根据教龄顺序，教授语文的教师教龄最长。通过排除法，只有 D 可能教授语文。\n验证：D 教语文，A 教英语（不教语文、数学），B 教化学（不教英语、物理），C 教历史（不\n教数学、化学），E教数学（不教化学、历史），F 教物理（不教生物、历史），G 教生物（不\n教历史）。所有条件都满足，且教龄顺序为 D>E>A>F>B>G>C，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:34, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 18:11:35');
