INSERT INTO `sys_log` VALUES (2389, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[345, Question(id=345, content=某公司有五位员工：甲、乙、丙、丁、戊，他们分别负责项目 A、项目 B、项目 C、项目 D、\n项目 E。已知：\n（1）甲不负责项目 A，也不负责项目 C；\n（2）乙不负责项目 B，也不负责项目 D；\n（3）丙不负责项目 C，也不负责项目 E；\n（4）丁不负责项目 A，也不负责项目 B；\n（5）戊不负责项目 D，也不负责项目 E。\n如果项目 A 比项目 B 预算高，项目 B 比项目 C 预算高，项目 C 比项目 D 预算高，项目 D 比\n项目 E预算高。\n请问，负责项目 A 的员工是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=乙, imageUrl=), Option(key=B, value=丙, imageUrl=), Option(key=C, value=丁, imageUrl=), Option(key=D, value=戊, imageUrl=)], answer=A, analysis=根据条件（1），甲不负责项目 A、C；根据条件（4），丁不负责项目 A、B。根据预算\n顺序，项目 A 预算最高。通过排除法，只有乙可能负责项目 A。验证：乙负责项目 A，甲负\n责项目 D（不负责项目 A、C），丙负责项目 B（不负责项目 C、E），丁负责项目 E（不负责项\n目 A、B），戊负责项目 C（不负责项目 D、E）。所有条件都满足，且预算顺序为乙>丙>戊>\n甲>丁，符合条件。, difficulty=3, category=判断推理, createdTime=2026-03-12T18:10:34, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 8, '2026-03-12 18:11:47');
