INSERT INTO `sys_log` VALUES (2391, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[347, Question(id=347, content=某学校有五门课程：语文、数学、英语、物理、化学，分别由 A、B、C、D、E 五位老师教\n授。已知：\n（1）A 不教语文，也不教数学；\n（2）B 不教英语，也不教物理；\n（3）C 不教数学，也不教化学；\n（4）D 不教物理，也不教化学；\n（5）E 不教语文，也不教英语。\n如果语文课比数学课课时多，数学课比英语课课时多，英语课比物理课课时多，物理课比化\n学课课时多。\n请问，语文课由哪位老师教授？, contentImageUrl=, type=1, options=[Option(key=A, value=B, imageUrl=), Option(key=B, value=C, imageUrl=), Option(key=C, value=D, imageUrl=), Option(key=D, value=E, imageUrl=)], answer=B, analysis=根据条件（1），A 不教语文、数学；根据条件（5），E 不教语文、英语。根据课时顺\n序，语文课课时最多。通过排除法，只有 C 可能教授语文。验证：C 教语文，A 教物理（不\n教语文、数学），B 教化学（不教英语、物理），D 教英语（不教物理、化学），E 教数学（不\n教语文、英语）。所有条件都满足，且课时顺序为 C>E>D>A>B，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:34, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 11, '2026-03-12 18:11:51');
