INSERT INTO `sys_log` VALUES (2393, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[348, Question(id=348, content=某公司有七个部门：研发部、市场部、销售部、客服部、人事部、财务部、行政部，分别\n由甲、乙、丙、丁、戊、己、庚七位经理负责。已知：\n（1）甲不负责研发部，也不负责市场部；\n（2）乙不负责销售部，也不负责客服部；\n（3）丙不负责市场部，也不负责人事部；\n（4）丁不负责客服部，也不负责财务部；\n（5）戊不负责人事部，也不负责行政部；\n（6）己不负责财务部，也不负责行政部；\n（7）庚不负责行政部。\n如果研发部比市场部员工多，市场部比销售部员工多，销售部比客服部员工多，客服部比人\n事部员工多，人事部比财务部员工多，财务部比行政部员工多。\n请问，研发部的负责人是谁？, contentImageUrl=, type=1, options=[Option(key=A, value=乙, imageUrl=), Option(key=B, value=丙, imageUrl=), Option(key=C, value=丁, imageUrl=), Option(key=D, value=戊, imageUrl=)], answer=C, analysis=根据条件（1），甲不负责研发部、市场部；根据条件（7），庚不负责行政部。根据员\n工数量顺序，研发部员工最多。通过排除法，只有丁可能负责研发部。验证：丁负责研发部，\n甲负责客服部（不负责研发部、市场部），乙负责行政部（不负责销售部、客服部），丙负责\n财务部（不负责市场部、人事部），戊负责市场部（不负责人事部、行政部），己负责销售部\n（不负责财务部、行政部），庚负责人事部（不负责行政部）。所有条件都满足，且员工数量\n顺序为丁>戊>己>甲>庚>丙>乙，符合条件。, difficulty=4, category=判断推理, createdTime=2026-03-12T18:10:34, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 18:11:54');
