INSERT INTO `sys_log` VALUES (2405, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@135b23d7, [Question(id=370, content=某公司有甲、乙、丙、丁四人，其中一人是经理。已知：甲不是经理；乙不是经理；丙\n不是经理。那么谁是经理？, contentImageUrl=null, type=1, options=[Option(key=A, value=甲, imageUrl=null), Option(key=B, value=乙, imageUrl=null), Option(key=C, value=丙, imageUrl=null), Option(key=D, value=丁, imageUrl=null)], answer=D, analysis=根据题意，甲、乙、丙都不是经理，那么只能是丁。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=371, content=如果天下雨，那么地面会湿。现在地面没有湿，可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=天下雨了, imageUrl=null), Option(key=B, value=天没有下雨, imageUrl=null), Option(key=C, value=无法确定, imageUrl=null), Option(key=D, value=地面会湿, imageUrl=null)], answer=B, analysis=原命题是\"下雨→湿\"，其逆否命题是\"不湿→不下雨\"，所以可以确定天没有下雨。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=372, content=所有学生都必须参加考试。小明没有参加考试。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=小明是学生, imageUrl=null), Option(key=B, value=小明不是学生, imageUrl=null), Option(key=C, value=小明生病了, imageUrl=null), Option(key=D, value=无法确定, imageUrl=null)], answer=B, analysis=根据\"所有学生都必须参加考试\"和\"小明没有参加考试\"，可以推出小明不是学生。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=373, content=某班有 30 人，其中 20 人喜欢篮球，15 人喜欢足球。问至少有多少人既喜欢篮球又喜欢\n足球？, contentImageUrl=null, type=1, options=[Option(key=A, value=0 人, imageUrl=null), Option(key=B, value=5 人, imageUrl=null), Option(key=C, value=10 人, imageUrl=null), Option(key=D, value=15 人, imageUrl=null)], answer=B, analysis=根据容斥原理，20+15-30=5，所以至少有 5 人两者都喜欢。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=374, content=如果甲去，那么乙也去。乙没去。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=甲去了, imageUrl=null), Option(key=B, value=甲没去, imageUrl=null), Option(key=C, value=无法确定, imageUrl=null), Option(key=D, value=乙去了, imageUrl=null)], answer=B, analysis=原命题是\"甲去→乙去\"，其逆否命题是\"乙不去→甲不去\"，所以甲没去。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=375, content=某商店规定：购买满 100 元打 9 折，满 200 元打 8 折。小王购买了 180 元的商品，实际\n支付多少元？, contentImageUrl=null, type=1, options=[Option(key=A, value=144 元, imageUrl=null), Option(key=B, value=162 元, imageUrl=null), Option(key=C, value=180 元, imageUrl=null), Option(key=D, value=160 元, imageUrl=null)], answer=B, analysis=180 元满 100 元但不满 200 元，打 9 折，180×0.9=162 元。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=376, content=所有老师都是成年人。张三是成年人。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=张三是老师, imageUrl=null), Option(key=B, value=张三不是老师, imageUrl=null), Option(key=C, value=无法确定, imageUrl=null), Option(key=D, value=张三是学生, imageUrl=null)], answer=C, analysis=原命题是\"老师→成年人\"，不能推出\"成年人→老师\"，所以无法确定。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=377, content=某次考试，小明比小红高 5 分，小红比小刚高 3 分。问小明比小刚高多少分？, contentImageUrl=null, type=1, options=[Option(key=A, value=2 分, imageUrl=null), Option(key=B, value=3 分, imageUrl=null), Option(key=C, value=5 分, imageUrl=null), Option(key=D, value=8 分, imageUrl=null)], answer=D, analysis=小明比小红高 5 分，小红比小刚高 3 分，所以小明比小刚高 5+3=8 分。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=378, content=如果不努力学习，就考不上好大学。小华考上了好大学。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=小华努力学习了, imageUrl=null), Option(key=B, value=小华没有努力学习, imageUrl=null), Option(key=C, value=无法确定, imageUrl=null), Option(key=D, value=小华很聪明, imageUrl=null)], answer=A, analysis=原命题是\"不努力→考不上\"，其逆否命题是\"考上→努力\"，所以小华努力学习了。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=379, content=某公司员工中，本科及以上学历占 60%，男性占 70%。问本科及以上学历的男性至少占\n多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=0%, imageUrl=null), Option(key=B, value=30%, imageUrl=null), Option(key=C, value=40%, imageUrl=null), Option(key=D, value=60%, imageUrl=null)], answer=B, analysis=60%+70%-100%=30%，所以至少有 30%是本科及以上学历的男性。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=380, content=所有鸟都会飞。企鹅是鸟。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=企鹅会飞, imageUrl=null), Option(key=B, value=企鹅不会飞, imageUrl=null), Option(key=C, value=企鹅不是鸟, imageUrl=null), Option(key=D, value=无法确定, imageUrl=null)], answer=A, analysis=根据三段论，所有鸟都会飞，企鹅是鸟，所以企鹅会飞（虽然实际不会飞，但按逻辑\n推理）。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=381, content=某班有 40 人，其中 25 人喜欢语文，20 人喜欢数学。问最多有多少人既不喜欢语文也\n不喜欢数学？, contentImageUrl=null, type=1, options=[Option(key=A, value=0 人, imageUrl=null), Option(key=B, value=5 人, imageUrl=null), Option(key=C, value=15 人, imageUrl=null), Option(key=D, value=20 人, imageUrl=null)], answer=C, analysis=最多有 40-(25+20-0)=15 人两者都不喜欢。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=382, content=如果今天不下雨，我们就去公园。我们去了公园。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=今天下雨了, imageUrl=null), Option(key=B, value=今天没下雨, imageUrl=null), Option(key=C, value=无法确定, imageUrl=null), Option(key=D, value=今天天气好, imageUrl=null)], answer=C, analysis=原命题是\"不下雨→去公园\"，不能推出\"去公园→不下雨\"，所以无法确定。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=383, content=某次抽奖，一等奖概率 1/100，二等奖概率 5/100。问至少中奖的概率是多少？, contentImageUrl=null, type=1, options=[Option(key=A, value=1/100, imageUrl=null), Option(key=B, value=5/100, imageUrl=null), Option(key=C, value=6/100, imageUrl=null), Option(key=D, value=95/100, imageUrl=null)], answer=C, analysis=至少中奖的概率=1/100+5/100=6/100。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=384, content=所有医生都需要执业证书。李医生没有执业证书。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=李医生不是医生, imageUrl=null), Option(key=B, value=李医生是医生, imageUrl=null), Option(key=C, value=李医生是假的, imageUrl=null), Option(key=D, value=无法确定, imageUrl=null)], answer=A, analysis=根据\"所有医生都需要执业证书\"和\"李医生没有执业证书\"，可以推出李医生不是医生。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=385, content=某公司有 50 人，其中 30 人会英语，25 人会日语。问最多有多少人既会英语又会日语？, contentImageUrl=null, type=1, options=[Option(key=A, value=0 人, imageUrl=null), Option(key=B, value=5 人, imageUrl=null), Option(key=C, value=25 人, imageUrl=null), Option(key=D, value=30 人, imageUrl=null)], answer=C, analysis=最多有 min(30,25)=25 人两者都会。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=386, content=如果甲说真话，那么乙说假话。乙说真话。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=甲说真话, imageUrl=null), Option(key=B, value=甲说假话, imageUrl=null), Option(key=C, value=无法确定, imageUrl=null), Option(key=D, value=乙说假话, imageUrl=null)], answer=B, analysis=原命题是\"甲真→乙假\"，其逆否命题是\"乙真→甲假\"，所以甲说假话。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=387, content=某次考试，及格率 80%，优秀率 40%。问至少有多少人既及格又优秀？, contentImageUrl=null, type=1, options=[Option(key=A, value=0%, imageUrl=null), Option(key=B, value=20%, imageUrl=null), Option(key=C, value=40%, imageUrl=null), Option(key=D, value=80%, imageUrl=null)], answer=B, analysis=80%+40%-100%=20%，所以至少有 20%既及格又优秀。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=388, content=所有学生都要遵守校规。小李遵守校规。可以得出什么结论？, contentImageUrl=null, type=1, options=[Option(key=A, value=小李是学生, imageUrl=null), Option(key=B, value=小李不是学生, imageUrl=null), Option(key=C, value=无法确定, imageUrl=null), Option(key=D, value=小李是好学生, imageUrl=null)], answer=C, analysis=原命题是\"学生→遵守校规\"，不能推出\"遵守校规→学生\"，所以无法确定。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=389, content=某商店促销：买二送一。小王买了 3 件商品，实际支付几件的钱？, contentImageUrl=null, type=1, options=[Option(key=A, value=1 件, imageUrl=null), Option(key=B, value=2 件, imageUrl=null), Option(key=C, value=3 件, imageUrl=null), Option(key=D, value=4 件, imageUrl=null)], answer=B, analysis=买二送一，买 3 件可以享受买二送一，实际支付 2 件的钱。, difficulty=3, category=判断推理, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null)]]', '0:0:0:0:0:0:0:1', 187, '2026-03-12 18:17:33');
