INSERT INTO `sys_log` VALUES (2476, 'teacher02', 'batchSave', 'com.examsystem.controller.teacher.QuestionImportController.batchSave', '[com.examsystem.security.UserPrincipal@6908a862, [Question(id=402, content=根据国家统计局数据，2023 年我国国内生产总值（GDP）为 1210207 亿元，同比增长 3.0%。\n其中，第一产业增加值 89755 亿元，增长 4.1%；第二产业增加值 483589 亿元，增长 4.7%；\n第三产业增加值 636863 亿元，增长 2.3%。2022 年我国第三产业增加值占 GDP 的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=50.8%, imageUrl=null), Option(key=B, value=52.6%, imageUrl=null), Option(key=C, value=53.2%, imageUrl=null), Option(key=D, value=54.5%, imageUrl=null)], answer=C, analysis=2023 年第三产业增加值为 636863 亿元，GDP 为 1210207 亿元，2023 年占比=636863\n÷1210207≈52.6%。2023 年第三产业增长 2.3%，GDP 增长 3.0%，由于第三产业增速低于\nGDP增速，因此 2022年占比应高于 2023年。计算 2022年第三产业增加值=636863÷(1+2.3%)\n≈622760 亿元，2022 年 GDP=1210207÷(1+3.0%)≈1174958 亿元，占比=622760÷1174958\n≈53.0%，最接近 C 选项 53.2%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=403, content=某省 2023 年规模以上工业企业实现营业收入 85000 亿元，同比增长 8.5%；利润总额 6800\n亿元，同比增长 12.3%。其中，国有控股企业营业收入 32000 亿元，利润总额 2800 亿元；\n私营企业营业收入 42000 亿元，利润总额 2100 亿元。该省 2023 年规模以上工业企业营业\n收入利润率为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=7.5%, imageUrl=null), Option(key=B, value=8.0%, imageUrl=null), Option(key=C, value=8.5%, imageUrl=null), Option(key=D, value=9.0%, imageUrl=null)], answer=B, analysis=营业收入利润率=利润总额÷营业收入×100%=6800÷85000×100%=8.0%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=404, content=2023 年，我国货物贸易进出口总值 42.07 万亿元，同比增长 0.2%。其中，出口 23.77 万亿\n元，增长 0.6%；进口 18.30 万亿元，下降 0.3%。贸易顺差 5.47 万亿元。2022 年我国货物贸\n易进出口总值为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=41.98 万亿元, imageUrl=null), Option(key=B, value=42.00 万亿元, imageUrl=null), Option(key=C, value=42.02 万亿元, imageUrl=null), Option(key=D, value=42.05 万亿元, imageUrl=null)], answer=A, analysis=2023 年进出口总值为 42.07 万亿元，同比增长 0.2%，则 2022 年进出口总值=42.07÷\n(1+0.2%)≈42.07÷1.002≈41.98 万亿元。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=405, content=某市 2023 年社会消费品零售总额 8500 亿元，同比增长 10.5%。其中，城镇消费品零售额\n7200 亿元，增长 10.8%；乡村消费品零售额 1300 亿元，增长 9.2%。2022 年该市城镇消费品\n零售额占社会消费品零售总额的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=83.5%, imageUrl=null), Option(key=B, value=84.2%, imageUrl=null), Option(key=C, value=84.7%, imageUrl=null), Option(key=D, value=85.0%, imageUrl=null)], answer=C, analysis=2022 年城镇消费品零售额=7200÷(1+10.8%)≈6497 亿元，2022 年社会消费品零售总\n额=8500÷(1+10.5%)≈7692 亿元，占比=6497÷7692≈84.5%，最接近 C 选项 84.7%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=406, content=2023 年，我国固定资产投资（不含农户）503036 亿元，同比增长 3.0%。其中，第一产业\n投资 13292 亿元，增长 0.2%；第二产业投资 162313 亿元，增长 9.0%；第三产业投资 327431\n亿元，增长 0.4%。2022 年第二产业投资占固定资产投资的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=30.5%, imageUrl=null), Option(key=B, value=31.2%, imageUrl=null), Option(key=C, value=31.8%, imageUrl=null), Option(key=D, value=32.5%, imageUrl=null)], answer=B, analysis=2022 年第二产业投资=162313÷(1+9.0%)≈148911 亿元，2022 年固定资产投资=503036\n÷(1+3.0%)≈488384 亿元，占比=148911÷488384≈30.5%，最接近 B 选项 31.2%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=407, content=某省 2023 年一般公共预算收入 8500 亿元，同比增长 5.5%。其中，税收收入 6800 亿元，\n增长 7.2%；非税收入 1700 亿元，下降 1.5%。2022 年该省税收收入占一般公共预算收入的\n比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=77.5%, imageUrl=null), Option(key=B, value=78.2%, imageUrl=null), Option(key=C, value=78.8%, imageUrl=null), Option(key=D, value=79.5%, imageUrl=null)], answer=C, analysis=2022 年税收收入=6800÷(1+7.2%)≈6342 亿元，2022 年一般公共预算收入=8500÷\n(1+5.5%)≈8057 亿元，占比=6342÷8057≈78.7%，最接近 C 选项 78.8%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=408, content=2023 年，我国居民人均可支配收入 39218 元，同比增长 6.3%。其中，城镇居民人均可支\n配收入 51821 元，增长 5.1%；农村居民人均可支配收入 21691 元，增长 7.7%。2022 年城乡\n居民人均可支配收入之比为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=2.28:1, imageUrl=null), Option(key=B, value=2.35:1, imageUrl=null), Option(key=C, value=2.42:1, imageUrl=null), Option(key=D, value=2.50:1, imageUrl=null)], answer=C, analysis=2022 年城镇居民人均可支配收入=51821÷(1+5.1%)≈49306 元，2022 年农村居民人均\n可支配收入=21691÷(1+7.7%)≈20140 元，比值=49306÷20140≈2.45，最接近 C 选项 2.42:1。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=409, content=某市 2023 年规模以上工业增加值同比增长 8.5%。分行业看，制造业增长 9.2%，电力、热\n力、燃气及水生产和供应业增长 6.5%，采矿业增长 3.8%。假设 2022 年制造业、电力热力燃\n气及水生产和供应业、采矿业的增加值之比为 5:3:2，则 2023年这三个行业的平均增速为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=7.2%, imageUrl=null), Option(key=B, value=7.5%, imageUrl=null), Option(key=C, value=7.8%, imageUrl=null), Option(key=D, value=8.1%, imageUrl=null)], answer=C, analysis=平均增速=（9.2%×5+6.5%×3+3.8%×2）÷（5+3+2）=（46%+19.5%+7.6%）÷10=73.1%\n÷10=7.31%，最接近 C 选项 7.8%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=410, content=2023 年，我国商品房销售面积 135837 万平方米，同比下降 8.5%；商品房销售额 130632\n亿元，下降 6.5%。2022 年我国商品房平均销售价格为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=9200 元/平方米, imageUrl=null), Option(key=B, value=9500 元/平方米, imageUrl=null), Option(key=C, value=9800 元/平方米, imageUrl=null), Option(key=D, value=10100 元/平方米, imageUrl=null)], answer=B, analysis=2023 年平均价格=130632 亿元÷135837 万平方米≈9617 元/平方米。2022 年销售额\n=130632÷(1-6.5%)≈139712 亿元，2022 年销售面积=135837÷(1-8.5%)≈148451 万平方米，\n2022 年平均价格=139712÷148451≈9412 元/平方米，最接近 B 选项 9500 元/平方米。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=411, content=某省 2023 年进出口总额 8500 亿元，同比增长 12.5%。其中，出口 5200 亿元，增长 15.0%；\n进口 3300 亿元，增长 8.5%。2022 年该省贸易顺差为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=1500 亿元, imageUrl=null), Option(key=B, value=1600 亿元, imageUrl=null), Option(key=C, value=1700 亿元, imageUrl=null), Option(key=D, value=1800 亿元, imageUrl=null)], answer=C, analysis=2022 年出口=5200÷(1+15.0%)≈4522 亿元，2022 年进口=3300÷(1+8.5%)≈3041 亿元，\n贸易顺差=4522-3041=1481 亿元，最接近 C 选项 1700 亿元。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=412, content=2023 年，我国粮食总产量 69541 万吨，同比增长 1.3%。其中，夏粮产量 14615 万吨，下\n降 0.8%；早稻产量 2834 万吨，增长 0.8%；秋粮产量 52092 万吨，增长 1.9%。2022 年我国\n秋粮产量占粮食总产量的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=73.5%, imageUrl=null), Option(key=B, value=74.2%, imageUrl=null), Option(key=C, value=74.8%, imageUrl=null), Option(key=D, value=75.2%, imageUrl=null)], answer=C, analysis=2022年秋粮产量=52092÷(1+1.9%)≈51112 万吨，2022年粮食总产量=69541÷(1+1.3%)\n≈68647 万吨，占比=51112÷68647≈74.5%，最接近 C 选项 74.8%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=413, content=某市 2023 年城镇新增就业 85 万人，同比增长 5.0%。其中，高校毕业生就业 32 万人，增\n长 8.0%；农民工就业 38 万人，增长 3.0%；其他人员就业 15 万人，增长 4.0%。2022 年该市\n高校毕业生就业占城镇新增就业的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=35.5%, imageUrl=null), Option(key=B, value=36.2%, imageUrl=null), Option(key=C, value=36.8%, imageUrl=null), Option(key=D, value=37.5%, imageUrl=null)], answer=B, analysis=2022年高校毕业生就业=32÷(1+8.0%)≈29.6万人，2022年城镇新增就业=85÷(1+5.0%)\n≈81.0 万人，占比=29.6÷81.0≈36.5%，最接近 B 选项 36.2%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=414, content=某省 2023 年研发经费支出 850 亿元，同比增长 15.0%。其中，企业研发支出 680 亿元，\n增长 16.5%；高校研发支出 102 亿元，增长 10.0%；科研院所研发支出 68 亿元，增长 8.0%。\n2022 年该省企业研发支出占研发经费支出的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=78.5%, imageUrl=null), Option(key=B, value=79.2%, imageUrl=null), Option(key=C, value=79.8%, imageUrl=null), Option(key=D, value=80.5%, imageUrl=null)], answer=C, analysis=2022 年企业研发支出=680÷(1+16.5%)≈584 亿元，2022 年研发经费支出=850÷\n(1+15.0%)≈739 亿元，占比=584÷739≈79.0%，最接近 C 选项 79.8%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=415, content=2023 年，我国快递业务量 1320 亿件，同比增长 19.4%；快递业务收入 12074 亿元，同比\n增长 14.3%。2022 年我国快递平均每件收入为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=8.5 元, imageUrl=null), Option(key=B, value=9.0 元, imageUrl=null), Option(key=C, value=9.5 元, imageUrl=null), Option(key=D, value=10.0 元, imageUrl=null)], answer=B, analysis=2022 年快递业务量=1320÷(1+19.4%)≈1106 亿件，2022 年快递业务收入=12074÷\n(1+14.3%)≈10563 亿元，平均每件收入=10563÷1106≈9.55 元，最接近 B 选项 9.0 元。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=416, content=某市 2023 年新能源汽车产量 85 万辆，同比增长 45.0%；销量 82 万辆，增长 42.0%。2022\n年该市新能源汽车产销率为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=94.5%, imageUrl=null), Option(key=B, value=95.2%, imageUrl=null), Option(key=C, value=95.8%, imageUrl=null), Option(key=D, value=96.5%, imageUrl=null)], answer=B, analysis=2022 年产量=85÷(1+45.0%)≈58.6 万辆，2022 年销量=82÷(1+42.0%)≈57.7 万辆，产\n销率=57.7÷58.6≈98.5%，最接近 B 选项 95.2%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=417, content=2023 年，我国移动互联网接入流量 2716 亿 GB，同比增长 18.2%。其中，手机上网流量\n2605 亿 GB，增长 18.5%。2022 年我国手机上网流量占移动互联网接入流量的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=94.5%, imageUrl=null), Option(key=B, value=95.2%, imageUrl=null), Option(key=C, value=95.8%, imageUrl=null), Option(key=D, value=96.2%, imageUrl=null)], answer=C, analysis=2022 年手机上网流量=2605÷(1+18.5%)≈2198 亿 GB，2022 年移动互联网接入流量\n=2716÷(1+18.2%)≈2298 亿 GB，占比=2198÷2298≈95.7%，最接近 C 选项 95.8%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=418, content=某省 2023 年文化及相关产业增加值 850 亿元，同比增长 12.5%。其中，文化制造业增加\n值 340 亿元，增长 10.5%；文化批发零售业增加值 170 亿元，增长 15.0%；文化服务业增加\n值 340 亿元，增长 13.5%。2022 年该省文化服务业增加值占文化及相关产业增加值的比重为\n（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=38.5%, imageUrl=null), Option(key=B, value=39.2%, imageUrl=null), Option(key=C, value=39.8%, imageUrl=null), Option(key=D, value=40.5%, imageUrl=null)], answer=B, analysis=2022 年文化服务业增加值=340÷(1+13.5%)≈299 亿元，2022 年文化及相关产业增加\n值=850÷(1+12.5%)≈756 亿元，占比=299÷756≈39.5%，最接近 B 选项 39.2%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=419, content=2023 年，我国铁路营业里程 15.9 万公里，同比增长 2.5%。其中，高速铁路营业里程 4.5\n万公里，增长 5.0%。2022 年我国高速铁路营业里程占铁路营业里程的比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=27.5%, imageUrl=null), Option(key=B, value=28.2%, imageUrl=null), Option(key=C, value=28.8%, imageUrl=null), Option(key=D, value=29.5%, imageUrl=null)], answer=B, analysis=2022 年高速铁路营业里程=4.5÷(1+5.0%)≈4.29 万公里，2022 年铁路营业里程=15.9\n÷(1+2.5%)≈15.51 万公里，占比=4.29÷15.51≈27.7%，最接近 B 选项 28.2%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null), Question(id=420, content=某市 2023 年软件和信息技术服务业收入 8500 亿元，同比增长 18.5%。其中，软件产品\n收入 2550 亿元，增长 15.0%；信息技术服务收入 5100 亿元，增长 20.0%；信息安全产品和\n服务收入 850 亿元，增长 12.0%。2022 年该市软件产品收入占软件和信息技术服务业收入的\n比重为（ ）。, contentImageUrl=null, type=1, options=[Option(key=A, value=29.5%, imageUrl=null), Option(key=B, value=30.2%, imageUrl=null), Option(key=C, value=30.8%, imageUrl=null), Option(key=D, value=31.5%, imageUrl=null)], answer=C, analysis=2022 年软件产品收入=2550÷(1+15.0%)≈2217 亿元，2022 年软件和信息技术服务业\n收入=8500÷(1+18.5%)≈7173 亿元，占比=2217÷7173≈30.9%，最接近 C 选项 30.8%。, difficulty=3, category=资料分析, createdTime=null, createBy=16, updatedTime=null, updateBy=null, stemId=null)]]', '0:0:0:0:0:0:0:1', 116, '2026-03-12 18:29:05');
