INSERT INTO `sys_log` VALUES (2501, 'teacher02', 'add', 'com.examsystem.controller.teacher.TeacherQuestionController.add', '[Question(id=421, content=1. 某省2023年GDP为8500亿元，同比增长6.5%。其中第一产业增加值1200亿元，同比增长4.2%；第二产业增加值3800亿元，同比增长7.8%；第三产业增加值3500亿元，同比增长5.8%。若2024年该省GDP增速保持2023年水平，且三次产业结构比例调整为12:45:43，则2024年该省第三产业增加值预计为多少亿元？, contentImageUrl=, type=1, options=[Option(key=A, value=3723.5, imageUrl=), Option(key=B, value=3825.0, imageUrl=), Option(key=C, value= 3926.5, imageUrl=), Option(key=D, value=4028.0, imageUrl=)], answer=C, analysis=2024年GDP=8500×(1+6.5%)=9052.5亿元。按新结构比例，第三产业占比43%，故第三产业增加值=9052.5×43%=3892.575亿元。但题目要求精确到小数点后一位，最接近C选项3926.5亿元。注意：此题需要考虑产业结构调整带来的基数变化。, difficulty=4, category=资料分析, createdTime=null, createBy=null, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 14, '2026-03-12 18:43:48');
