INSERT INTO `sys_log` VALUES (2509, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[401, Question(id=401, content=某市 2023 年城镇新增就业 85 万人，同比增长 5.0%。其中，高校毕业生就业 32 万人，增\n长 8.0%；农民工就业 38 万人，增长 3.0%；其他人员就业 15 万人，增长 4.0%。2022 年该市\n高校毕业生就业占城镇新增就业的比重为（ ）。, contentImageUrl=, type=1, options=[Option(key=A, value=35.5%, imageUrl=), Option(key=B, value=36.2%, imageUrl=), Option(key=C, value=36.8%, imageUrl=), Option(key=D, value=37.5%, imageUrl=)], answer=B, analysis=2022年高校毕业生就业=32÷(1+8.0%)≈29.6万人，2022年城镇新增就业=85÷(1+5.0%)\n≈81.0 万人，占比=29.6÷81.0≈36.5%，最接近 B 选项 36.2%。, difficulty=2, category=资料分析, createdTime=2026-03-12T18:26:51, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 18:44:28');
