INSERT INTO `sys_log` VALUES (2516, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[397, Question(id=397, content=某市 2023 年规模以上工业增加值同比增长 8.5%。分行业看，制造业增长 9.2%，电力、热\n力、燃气及水生产和供应业增长 6.5%，采矿业增长 3.8%。假设 2022 年制造业、电力热力燃\n气及水生产和供应业、采矿业的增加值之比为 5:3:2，则 2023年这三个行业的平均增速为（ ）。, contentImageUrl=, type=1, options=[Option(key=A, value=7.2%, imageUrl=), Option(key=B, value=7.5%, imageUrl=), Option(key=C, value=7.8%, imageUrl=), Option(key=D, value=8.1%, imageUrl=)], answer=C, analysis=平均增速=（9.2%×5+6.5%×3+3.8%×2）÷（5+3+2）=（46%+19.5%+7.6%）÷10=73.1%\n÷10=7.31%，最接近 C 选项 7.8%。, difficulty=3, category=资料分析, createdTime=2026-03-12T18:26:51, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 18:45:22');
