INSERT INTO `sys_log` VALUES (2522, 'teacher02', 'update', 'com.examsystem.controller.teacher.TeacherQuestionController.update', '[391, Question(id=391, content=某省 2023 年规模以上工业企业实现营业收入 85000 亿元，同比增长 8.5%；利润总额 6800\n亿元，同比增长 12.3%。其中，国有控股企业营业收入 32000 亿元，利润总额 2800 亿元；\n私营企业营业收入 42000 亿元，利润总额 2100 亿元。该省 2023 年规模以上工业企业营业\n收入利润率为（ ）。, contentImageUrl=, type=1, options=[Option(key=A, value=7.5%, imageUrl=), Option(key=B, value=8.0%, imageUrl=), Option(key=C, value=8.5%, imageUrl=), Option(key=D, value=9.0%, imageUrl=)], answer=B, analysis=营业收入利润率=利润总额÷营业收入×100%=6800÷85000×100%=8.0%。, difficulty=2, category=资料分析, createdTime=2026-03-12T18:26:51, createBy=16, updatedTime=null, updateBy=null, stemId=null)]', '0:0:0:0:0:0:0:1', 9, '2026-03-12 18:45:37');
