INSERT INTO `sys_log` VALUES (2547, 'teacher02', 'createStem', 'com.examsystem.controller.StemController.createStem', '[Stem(id=3, content=2023年，我国规模以上工业企业实现利润总额76858.3亿元，同比下降2.3%。其中，国有控股企业实现利润总额25813.6亿元，同比增长1.2%；股份制企业实现利润总额56610.5亿元，同比下降2.9%；外商及港澳台投资企业实现利润总额18337.8亿元，同比下降4.2%；私营企业实现利润总额23437.5亿元，同比下降4.1%。\n\n分行业看，采矿业实现利润总额12392.4亿元，同比下降19.7%；制造业实现利润总额57643.6亿元，同比下降2.0%；电力、热力、燃气及水生产和供应业实现利润总额6822.3亿元，同比增长54.7%。\n\n2023年，规模以上工业企业每百元营业收入中的成本为84.76元，同比增加0.04元；每百元营业收入中的费用为8.56元，同比增加0.20元。12月末，规模以上工业企业资产负债率为57.1%，同比下降0.1个百分点。, contentImageUrl=, category=资料分析, createdTime=2026-03-12T18:48:26.831632400, createBy=1, updatedTime=2026-03-12T18:48:26.831632400, updateBy=1)]', '0:0:0:0:0:0:0:1', 12, '2026-03-12 18:48:27');
