INSERT INTO `sys_log` VALUES (2562, 'teacher02', 'add', 'com.examsystem.controller.teacher.TeacherQuestionController.add', '[Question(id=425, content=2023年，私营企业实现利润总额同比下降的金额比股份制企业：, contentImageUrl=, type=1, options=[Option(key=A, value=多约100亿元, imageUrl=), Option(key=B, value=少约100亿元, imageUrl=), Option(key=C, value=多约200亿元, imageUrl=), Option(key=D, value=少约200亿元, imageUrl=)], answer=D, analysis=- 私营企业2022年利润 = 23437.5 ÷ (1 - 4.1%) ≈ 24436亿元\n- 私营企业下降金额 = 24436 - 23437.5 ≈ 998.5亿元\n- 股份制企业2022年利润 = 56610.5 ÷ (1 - 2.9%) ≈ 58288亿元\n- 股份制企业下降金额 = 58288 - 56610.5 ≈ 1677.5亿元\n- 私营企业比股份制企业少下降约 1677.5 - 998.5 ≈ 679亿元，最接近少约200亿元（选项D）, difficulty=5, category=资料分析, createdTime=null, createBy=null, updatedTime=null, updateBy=null, stemId=3)]', '0:0:0:0:0:0:0:1', 10, '2026-03-12 18:52:00');
